def gsnap_index(reference, kmer=15):
    ref_dir, ref_base = check_reference(reference)
    ref_base += "." + str(kmer)

    cmd = "gmap_build --no-sarray -k %(kmer)i -D %(ref_dir)s -d %(ref_base)s %(reference)s"
    cmd %= locals()
    if not gmap_built(ref_dir, ref_base):
        sh(cmd)
    else:
        print >>sys.stderr, "[skipping command] %s" % cmd

    cmd_cmet = "cmetindex -d %(ref_base)s -F %(ref_dir)s -k %(kmer)d\n"
    cmd_cmet %= locals()
    if not cmetindexed(ref_dir, ref_base, kmer):
        sh(cmd_cmet)
    else:
        print >>sys.stderr, "[skipping command] %s" % cmd

def parse_time(log_file):

    for line in open(log_file):
        if "CPU time" in line:
            _, time = [x.strip() for x in line.split(":")]
            time, unit = time.split()
            assert unit == "sec."
            return float(time)
    raise Exception(log_file)

def parse_mem(log_file):

    for line in open(log_file):
        if "Max Memory" in line:
            _, mem = [x.strip() for x in line.split(":")]
            mem, unit = mem.split()
            assert unit == "MB"
            return float(mem)

    raise Exception(log_file)

def parse_prog(log_file):
    import os.path as op
    p = op.basename(log_file)
    if p.startswith('trim-'):
        p = p[5:]
    return p.split("-")[0]

def parse_sim_real(log_file):
    import os.path as op
    p = op.basename(log_file)
    if p.startswith('trim-'):
        p = p[5:]
    return p.split("-")[1].split(".")[0]

def name(bam):
    return op.basename(bam).rsplit(".", 1)[0].split("-")[0]
    return op.basename(bam).rsplit(".", 1)[0].split("-")[0] + ("-trim" if "trim" in bam else "")
    return op.dirname(bam)

def count_both(bam, regions, flags):
    #if not "last" in bam: flags += " -f0x2"
    off, on = OFF.format(**locals()), ON.format(**locals())
    return bam, map(counter, [off, on])

def make_results_folder():
    """Creates a directory where all results and technical files will be saved to if it doesn't already exist.
    """
    # check if the main results folder already exists and if it is empty
    # if not, create it before proceeding
