def call_quiet(*args):
    """Safely run a command and get stdout; print stderr if there's an error.

    Like subprocess.check_output, but silent in the normal case where the
    command logs unimportant stuff to stderr. If there is an error, then the
    full error message(s) is shown in the exception message.
    """
    if not len(args):
        raise ValueError("Must supply at least one argument (the command name)")
    try:
        proc = subprocess.run(args, check=True, capture_output=True)
    except OSError as exc:
        raise RuntimeError(
            f"Could not find the executable {args[0]!r} -- is it installed correctly?"
            f"\n(Original error: {exc})"
        ) from exc
    except subprocess.CalledProcessError as exc:
        raise RuntimeError(
            f"Subprocess command failed:\n$ {' '.join(args)}\n\n{exc}"
        ) from exc
    return proc.stdout

def ensure_path(fname: str) -> bool:
    """Create dirs and move an existing file to avoid overwriting, if necessary.

    If a file already exists at the given path, it is renamed with an integer
    suffix to clear the way.
    """
    if "/" in os.path.normpath(fname):
        # Ensure the output directory exists
        dname = os.path.dirname(os.path.abspath(fname))
        if dname and not os.path.isdir(dname):
            try:
                os.makedirs(dname)
            except OSError as exc:
                raise OSError(
                    f"Output path {fname} contains a directory {dname} "
                    f"that cannot be created: {exc}"
                ) from exc
    if os.path.isfile(fname):
        # Add an integer suffix to the existing file name
        cnt = 1
        bak_fname = f"{fname}.{cnt}"
        while os.path.isfile(bak_fname):
            cnt += 1
            bak_fname = f"{fname}.{cnt}"
        os.rename(fname, bak_fname)
        logging.info("Moved existing file %s -> %s", fname, bak_fname)
    return True

def check_unique(items, title):
    """Ensure all items in an iterable are identical; return that one item."""
    its = set(items)
    assert len(its) == 1, "Inconsistent %s keys: %s" % (
        title,
        " ".join(map(str, sorted(its))),
    )
    return its.pop()

def interval_coverages_count(
    bed_fname: str, bam_fname: str, min_mapq: int, procs: int = 1, fasta: None = None
) -> Iterator[list[Union[int, tuple[str, int, int, str, float, float]]]]:
    """Calculate log2 coverages in the BAM file at each interval."""
    regions = tabio.read_auto(bed_fname)
    if procs == 1:
        bamfile = pysam.AlignmentFile(bam_fname, "rb", reference_filename=fasta)
        for chrom, subregions in regions.by_chromosome():
            logging.info(
                "Processing chromosome %s of %s", chrom, os.path.basename(bam_fname)
            )
            for count, row in _rdc_chunk(bamfile, subregions, min_mapq):
                yield [count, row]
    else:
        with futures.ProcessPoolExecutor(procs) as pool:
            args_iter = (
                (bam_fname, subr, min_mapq, fasta)
                for _c, subr in regions.by_chromosome()
            )
            for chunk in pool.map(_rdc, args_iter):
                for count, row in chunk:
                    yield [count, row]

def _rdc(args):
    """Wrapper for parallel."""
    return list(_rdc_chunk(*args))

def _rdc_chunk(
    bamfile: pysam.AlignmentFile,
    regions: GenomicArray,
    min_mapq: int,
    fasta: None = None,
) -> Iterator[tuple[int, tuple[str, int, int, str, float, float]]]:
    if isinstance(bamfile, str):
        bamfile = pysam.AlignmentFile(bamfile, "rb", reference_filename=fasta)
    for chrom, start, end, gene in regions.coords(["gene"]):
        yield region_depth_count(bamfile, chrom, start, end, gene, min_mapq)

def bedcov(
    bed_fname: str, bam_fname: str, min_mapq: int, fasta: Optional[str] = None
) -> pd.DataFrame:
    """Calculate depth of all regions in a BED file via samtools (pysam) bedcov.

    i.e. mean pileup depth across each region.
    """
    # Count bases in each region; exclude low-MAPQ reads
    cmd = [bed_fname, bam_fname]
    if min_mapq and min_mapq > 0:
        cmd.extend(["-Q", str(min_mapq)])
    if fasta:
        cmd.extend(["--reference", fasta])
    try:
        raw = pysam.bedcov(*cmd, split_lines=False)
    except pysam.SamtoolsError as exc:
        raise ValueError(
            f"Failed processing {bam_fname!r} coverages in {bed_fname!r} regions. "
            f"PySAM error: {exc}"
        ) from exc
    if not raw:
        raise ValueError(
            f"BED file {bed_fname!r} chromosome names don't match any in "
            f"BAM file {bam_fname!r}"
        )
    columns = detect_bedcov_columns(raw)
    table = pd.read_csv(StringIO(raw), sep="\t", names=columns, usecols=columns)
    return table

def on_array(default: Optional[int] = None) -> Callable:
    """Ensure `a` is a numpy array with no missing/NaN values."""

    def outer(f):
        @wraps(f)
        def wrapper(a, **kwargs):
            a = np.asarray(a, dtype=float)
            a = a[~np.isnan(a)]
            if not len(a):
                return np.nan
            if len(a) == 1:
                if default is None:
                    return a[0]
                return default
            return f(a, **kwargs)

        return wrapper

    return outer

def on_weighted_array(default: None = None) -> Callable:
    """Ensure `a` and `w` are equal-length numpy arrays with no NaN values.

    For weighted descriptives -- `a` is the array of values, `w` is weights.

    1. Drop any cells in `a` that are NaN from both `a` and `w`
    2. Replace any remaining NaN cells in `w` with 0.
    """

    def outer(f):
        @wraps(f)
        def wrapper(a, w, **kwargs):
            if len(a) != len(w):
                raise ValueError(f"Unequal array lengths: a={len(a)}, w={len(w)}")
            if not len(a):
                return np.nan
            a = np.asarray(a, dtype=float)
            w = np.asarray(w, dtype=float)
            # Drop a's NaN indices from both arrays
            a_nan = np.isnan(a)
            if a_nan.any():
                a = a[~a_nan]
                if not len(a):
                    return np.nan
                w = w[~a_nan]
            if len(a) == 1:
                if default is None:
                    return a[0]
                return default
            # Fill w's NaN indices
            w_nan = np.isnan(w)
            if w_nan.any():
                w[w_nan] = 0.0
            return f(a, w, **kwargs)

        return wrapper

    return outer

def interquartile_range(a: ndarray) -> float64:
    """Compute the difference between the array's first and third quartiles."""
    return np.percentile(a, 75) - np.percentile(a, 25)

def weighted_std(a: ndarray, weights: ndarray) -> float64:
    """Standard deviation with weights."""
    mean = np.average(a, weights=weights)
    var = np.average((a - mean) ** 2, weights=weights)
    return np.sqrt(var)

def mean_squared_error(a, initial=None):
    """Mean squared error (MSE).

    By default, assume the input array `a` is the residuals/deviations/error,
    so MSE is calculated from zero. Another reference point for calculating the
    error can be specified with `initial`.
    """
    if initial is None:
        initial = a.mean()
    if initial:
        a = a - initial
    return (a**2).mean()

def create_diagram(
    cnarr: CopyNumArray,
    segarr: CopyNumArray,
    threshold: float,
    min_probes: int,
    outfname: str,
    show_range: None = None,
    title: None = None,
    show_labels: bool = True,
) -> str:
    """Create the diagram."""
    if cnarr and segarr:
        do_both = True  # Draw segments on left, probes on right.
        cnarr_is_seg = False  # Are probes actually the segmented values?
    else:
        if cnarr:
            cnarr_is_seg = False
        elif segarr:
            cnarr = segarr
            cnarr_is_seg = True
        else:
            raise ValueError("Must provide argument cnarr or segarr, or both. ")
        do_both = False

    if show_range:
        chrom, start, end = unpack_range(show_range)
        if not (start is None and end is None):
            raise ValueError(
                "Must provide chromosome only "
                "(genomic-range not allowed for 'diagram')."
            )
        if cnarr:
            cnarr = cnarr.in_range(chrom=chrom, start=None, end=None)
        if segarr:
            segarr = segarr.in_range(chrom=chrom, start=None, end=None)
    gene_labels = _get_gene_labels(cnarr, segarr, cnarr_is_seg, threshold, min_probes)

    # NB: If multiple segments cover the same gene (gene contains breakpoints),
    # all those segments are marked as "hits".  We'll uniquify them.
    # TODO - use different logic to only label the gene's signficant segment(s)
    seen_genes = set()

    # Consolidate genes & coverage values as chromosome features
    features = collections.defaultdict(list)
    strand = 1 if do_both else None  # Draw on the chr. right half or full width
    chrom_sizes = plots.chromosome_sizes(cnarr)
    if not cnarr_is_seg:
        cnarr = cnarr.squash_genes()
    for row in cnarr:
        if (
            row.start - 1 >= 0 and row.end <= chrom_sizes[row.chromosome]
        ):  # Sanity check
            if show_labels and row.gene in gene_labels and row.gene not in seen_genes:
                seen_genes.add(row.gene)
                feat_name = row.gene
                if "," in feat_name:
                    # TODO - line-wrap multi-gene labels (reportlab won't do \n)
                    feat_name = feat_name.replace(",", ", ")
            else:
                feat_name = None
            features[row.chromosome].append(
                (
                    row.start - 1,
                    row.end,
                    strand,
                    feat_name,
                    colors.Color(*plots.cvg2rgb(row.log2, not cnarr_is_seg)),
                )
            )
    if do_both:
        # Draw segments in the left half of each chromosome (strand -1)
        for chrom, segrows in segarr.by_chromosome():
            for srow in segrows:
                if (
                    srow.start - 1 >= 0 and srow.end <= chrom_sizes[chrom]
                ):  # Sanity check
                    features[chrom].append(
                        (
                            srow.start - 1,
                            srow.end,
                            -1,
                            None,
                            colors.Color(*plots.cvg2rgb(srow.log2, False)),
                        )
                    )

    # Generate the diagram PDF
    if not outfname:
        outfname = cnarr.sample_id + "-diagram.pdf"
    drawing = build_chrom_diagram(features, chrom_sizes, cnarr.sample_id, title)
    cvs = canvas.Canvas(outfname, pagesize=PAGE_SIZE)
    renderPDF.draw(drawing, cvs, 0, 0)
    cvs.showPage()
    cvs.save()
    return outfname

def merge_samples(filenames: list[str]) -> pd.DataFrame:
    """Merge probe values from multiple samples into a 2D table (of sorts).

    Input:
        dict of {sample ID: (probes, values)}
    Output:
        list-of-tuples: (probe, log2 coverages...)
    """

    def row2label(row) -> str:
        return f"{row.chromosome}:{row.start}-{row.end}:{row.gene}"

    def label_with_gene(cnarr):
        return cnarr.data.apply(row2label, axis=1)

    if not filenames:
        return []
    first_cnarr = read_cna(filenames[0])
    out_table = first_cnarr.data.reindex(columns=["chromosome", "start", "end", "gene"])
    out_table["label"] = label_with_gene(first_cnarr)
    out_table[first_cnarr.sample_id] = first_cnarr["log2"]
    for fname in filenames[1:]:
        cnarr = read_cna(fname)
        if not (
            len(cnarr) == len(out_table)
            and (label_with_gene(cnarr) == out_table["label"]).all()
        ):
            raise ValueError(f"Mismatched row coordinates in {fname}")
        # Copy the next column by sample ID
        if cnarr.sample_id in out_table.columns:
            raise ValueError(f"Duplicate sample ID: {cnarr.sample_id}")
        out_table[cnarr.sample_id] = cnarr["log2"]
        del cnarr
    return out_table

def fmt_jtv(sample_ids: list[str], table: pd.DataFrame) -> tuple[list[str], map]:
    """Format for Java TreeView."""
    outheader = ["CloneID", "Name", *sample_ids]
    outtable = pd.concat(
        [
            pd.DataFrame(
                {
                    "CloneID": "IMAGE:",
                    "Name": table["label"],
                }
            ),
            table.drop(["chromosome", "start", "end", "gene", "label"], axis=1),
        ],
        axis=1,
    )
    outrows = outtable.itertuples(index=False)
    return outheader, outrows

def match_ref_to_sample(
    ref_cnarr: CopyNumArray, samp_cnarr: CopyNumArray
) -> CopyNumArray:
    """Filter the reference bins to match the sample (target or antitarget)."""
    # Assign each bin a unique string ID based on genomic coordinates
    samp_labeled = samp_cnarr.data.set_index(pd.Index(samp_cnarr.coords()))
    ref_labeled = ref_cnarr.data.set_index(pd.Index(ref_cnarr.coords()))
    for dset, name in ((samp_labeled, "sample"), (ref_labeled, "reference")):
        dupes = dset.index.duplicated()
        if dupes.any():
            raise ValueError(
                (
                    "Duplicated genomic coordinates in {} set. Total duplicated regions: {}, starting with:\n"
                    "{}."
                ).format(
                    name,
                    len(dset.index[dupes]),
                    "\n".join(map(str, dset.index[dupes][:10])),
                )
            )
    # Take the reference bins with IDs identical to those in the sample
    ref_matched = ref_labeled.reindex(index=samp_labeled.index)
    # Check for signs that the wrong reference was used
    num_missing = pd.isna(ref_matched.start).sum()
    if num_missing > 0:
        raise ValueError(
            f"Reference is missing {num_missing} bins found in {samp_cnarr.sample_id}"
        )
    x = ref_cnarr.as_dataframe(
        ref_matched.reset_index(drop=True).set_index(samp_cnarr.data.index)
    )
    return x

def cna2df(cna):
    """Extract a subset of DataFrame columns from a CNA."""
    return cna.data.loc[:, ["start", "end", "log2"]]

def do_metrics(
    cnarrs: CopyNumArray,
    segments: Optional[CopyNumArray] = None,
    skip_low: bool = False,
) -> pd.DataFrame:
    """Compute coverage deviations and other metrics for self-evaluation."""
    # Catch if passed args are single CopyNumArrays instead of lists
    from .cnary import CopyNumArray as CNA

    if isinstance(cnarrs, CNA):
        cnarrs = [cnarrs]
    if isinstance(segments, CNA):
        segments = [segments]
    elif segments is None:
        segments = [None]
    else:
        segments = list(segments)
    if skip_low:
        cnarrs = (cna.drop_low_coverage() for cna in cnarrs)
    rows = (
        (
            cna.meta.get("filename", cna.sample_id),
            len(seg) if seg is not None else "-",
            *ests_of_scale(cna.residuals(seg).to_numpy()),
        )
        for cna, seg in zip_repeater(cnarrs, segments)
    )
    colnames = ["sample", "segments", "stdev", "mad", "iqr", "bivar"]
    return pd.DataFrame.from_records(rows, columns=colnames)

def zip_repeater(
    iterable: Iterator[Any], repeatable: list[CopyNumArray]
) -> Iterator[tuple[CopyNumArray, CopyNumArray]]:
    """Repeat a single segmentation to match the number of copy ratio inputs"""
    rpt_len = len(repeatable)
    if rpt_len == 1:
        rpt = repeatable[0]
        for it in iterable:
            yield it, rpt
    else:
        i = -1
        for i, (it, rpt) in enumerate(zip(iterable, repeatable)):
            yield it, rpt
        # Require lengths to match
        if i + 1 != rpt_len:
            raise ValueError(
                "Number of unsegmented and segmented input files did not match "
                + f"({i} vs. {rpt_len})"
            )

def pick_pool(nprocs: int) -> Iterator[Union[SerialPool, ProcessPoolExecutor]]:
    if nprocs == 1:
        yield SerialPool()
    else:
        if nprocs < 1:
            nprocs = None
        with futures.ProcessPoolExecutor(max_workers=nprocs) as pool:
            yield pool

def chromosome_sizes(
    probes: CopyNumArray, to_mb: bool = False
) -> collections.OrderedDict:
    """Create an ordered mapping of chromosome names to sizes."""
    chrom_sizes = collections.OrderedDict()
    for chrom, rows in probes.by_chromosome():
        chrom_sizes[chrom] = rows["end"].max()
        if to_mb:
            chrom_sizes[chrom] *= MB
    return chrom_sizes

def translate_region_to_bins(region, bins):
    """Map genomic coordinates to bin indices.

    Return a tuple of (chrom, start, end), just like unpack_range.
    """
    if region is None:
        return Region(None, None, None)
    chrom, start, end = unpack_range(region)
    if start is None and end is None:
        return Region(chrom, start, end)
    if start is None:
        start = 0
    if end is None:
        end = float("inf")
    # NB: only bin start positions matter here
    c_bin_starts = bins.data.loc[bins.data.chromosome == chrom, "start"].values
    r_start, r_end = np.searchsorted(c_bin_starts, [start, end])
    return Region(chrom, r_start, r_end)

def translate_segments_to_bins(segments, bins):
    if "probes" in segments and segments["probes"].sum() == len(bins):
        # Segments and .cnr bins already match
        return update_binwise_positions_simple(segments)

    logging.warning(
        "Segments %s 'probes' sum does not match the number of bins in %s",
        segments.sample_id,
        bins.sample_id,
    )
    # Must re-align segments to .cnr bins
    _x, segments, _v = update_binwise_positions(bins, segments)
    return segments

def update_binwise_positions_simple(cnarr):
    start_chunks = []
    end_chunks = []
    is_segment = "probes" in cnarr
    if is_segment:
        cnarr = cnarr[cnarr["probes"] > 0]
    for _chrom, c_arr in cnarr.by_chromosome():
        if is_segment:
            # Segments -- each row can cover many bins
            ends = c_arr["probes"].values.cumsum()
            starts = np.r_[0, ends[:-1]]
        else:
            # Bins -- enumerate rows
            n_bins = len(c_arr)
            starts = np.arange(n_bins)
            ends = np.arange(1, n_bins + 1)
        start_chunks.append(starts)
        end_chunks.append(ends)
    return cnarr.as_dataframe(
        cnarr.data.assign(
            start=np.concatenate(start_chunks), end=np.concatenate(end_chunks)
        )
    )

def gene_coords_by_name(probes, names):
    """Find the chromosomal position of each named gene in probes.

    Returns
    -------
    dict
        Of: {chromosome: [(start, end, gene name), ...]}
    """
    names = list(filter(None, set(names)))
    if not names:
        return {}

    # Create an index of gene names
    gene_index = collections.defaultdict(set)
    for i, gene in enumerate(probes["gene"]):
        for gene_name in gene.split(","):
            if gene_name in names:
                gene_index[gene_name].add(i)
    # Retrieve coordinates by name
    all_coords = collections.defaultdict(lambda: collections.defaultdict(set))
    for name in names:
        gene_probes = probes.data.take(sorted(gene_index.get(name, [])))
        if not len(gene_probes):
            raise ValueError(f"No targeted gene named {name!r} found")
        # Find the genomic range of this gene's probes
        start = gene_probes["start"].min()
        end = gene_probes["end"].max()
        chrom = core.check_unique(gene_probes["chromosome"], name)
        # Deduce the unique set of gene names for this region
        uniq_names = set()
        for oname in set(gene_probes["gene"]):
            uniq_names.update(oname.split(","))
        all_coords[chrom][start, end].update(uniq_names)
    # Consolidate each region's gene names into a string
    uniq_coords = {}
    for chrom, hits in all_coords.items():
        uniq_coords[chrom] = [
            (start, end, ",".join(sorted(gene_names)))
            for (start, end), gene_names in hits.items()
        ]
    return uniq_coords

def gene_coords_by_range(probes, chrom, start, end, ignore=params.IGNORE_GENE_NAMES):
    """Find the chromosomal position of all genes in a range.

    Returns
    -------
    dict
        Of: {chromosome: [(start, end, gene), ...]}
    """
    ignore += params.ANTITARGET_ALIASES
    # Tabulate the genes in the selected region
    genes = collections.OrderedDict()
    for row in probes.in_range(chrom, start, end):
        name = str(row.gene)
        if name in genes:
            genes[name][1] = row.end
        elif name not in ignore:
            genes[name] = [row.start, row.end]
    # Reorganize the data structure
    return {
        chrom: [(gstart, gend, name) for name, (gstart, gend) in list(genes.items())]
    }

def infer_sexes(
    cnn_fnames: list[str], is_haploid_x: bool, diploid_parx_genome: Optional[str]
) -> dict[str, bool_]:
    """Map sample IDs to inferred chromosomal sex, where possible.

    For samples where the source file is empty or does not include either sex
    chromosome, that sample ID will not be in the returned dictionary.
    """
    sexes = {}
    for fname in cnn_fnames:
        cnarr = read_cna(fname)
        if cnarr:
            is_xx = cnarr.guess_xx(is_haploid_x, diploid_parx_genome)
            if is_xx is not None:
                sexes[cnarr.sample_id] = is_xx
    return sexes

def get_fasta_stats(cnarr: CNA, fa_fname: str) -> tuple[ndarray, ndarray]:
    """Calculate GC and RepeatMasker content of each bin in the FASTA genome."""
    logging.info("Calculating GC and RepeatMasker content in %s ...", fa_fname)
    gc_rm_vals = [
        calculate_gc_lo(subseq) for subseq in fasta_extract_regions(fa_fname, cnarr)
    ]
    gc_vals, rm_vals = zip(*gc_rm_vals)
    return np.asarray(gc_vals, dtype=float), np.asarray(rm_vals, dtype=float)

def fasta_extract_regions(fa_fname: str, intervals: CNA) -> Iterator[str]:
    """Extract an iterable of regions from an indexed FASTA file.

    Input: FASTA file name; iterable of (seq_id, start, end) (1-based)
    Output: iterable of string sequences.
    """
    with pyfaidx.Fasta(fa_fname, as_raw=True) as fa_file:
        for chrom, subarr in intervals.by_chromosome():
            logging.info("Extracting sequences from chromosome %s", chrom)
            for _chrom, start, end in subarr.coords():
                yield fa_file[_chrom][int(start) : int(end)]

def gene_metrics_by_gene(
    cnarr: CopyNumArray, threshold: float, skip_low: bool = False
) -> Iterator[pd.Series]:
    """Identify genes where average bin copy ratio value exceeds `threshold`.

    NB: Adjust the sample's sex-chromosome log2 values beforehand with shift_xx,
    otherwise all chrX/chrY genes may be reported gained/lost.
    """
    for row in group_by_genes(cnarr, skip_low):
        if abs(row.log2) >= threshold and row.gene:
            yield row

def gene_metrics_by_segment(
    cnarr: CopyNumArray,
    segments: CopyNumArray,
    threshold: float,
    skip_low: bool = False,
) -> Iterator[pd.Series]:
    """Identify genes where segmented copy ratio exceeds `threshold`.

    In the output table, show each segment's weight and probes as segment_weight
    and segment_probes, alongside the gene-level weight and probes.

    NB: Adjust the sample's sex-chromosome log2 values beforehand with shift_xx,
    otherwise all chrX/chrY genes may be reported gained/lost.
    """
    extra_cols = [
        col
        for col in segments.data.columns
        if col not in cnarr.data.columns and col not in ("depth", "probes", "weight")
    ]
    for colname in extra_cols:
        cnarr[colname] = np.nan
    for segment, subprobes in cnarr.by_ranges(segments):
        if abs(segment.log2) >= threshold:
            for row in group_by_genes(subprobes, skip_low):
                row["log2"] = segment.log2
                if hasattr(segment, "weight"):
                    row["segment_weight"] = segment.weight
                if hasattr(segment, "probes"):
                    row["segment_probes"] = segment.probes
                for colname in extra_cols:
                    row[colname] = getattr(segment, colname)
                yield row

def before(char):
    def selector(string):
        return string.split(char, 1)[0]

    return selector

def load_cnv_expression_corr(fname):
    shared_key = "Entrez_Gene_Id"
    table = pd.read_csv(
        fname, sep="\t", na_filter=False, dtype={shared_key: int}
    ).set_index(shared_key)
    logging.info("Loaded %s with shape: %s", fname, table.shape)
    return table

def tsl2int(tsl):
    """Convert an Ensembl Transcript Support Level (TSL) code to an integer.

    The code has the format "tsl([1-5]|NA)".

    See: https://www.ensembl.org/Help/Glossary?id=492
    """
    if tsl in (np.nan, "", "tslNA"):
        return 0
    # Remove "tsl" prefix
    assert tsl[:3] == "tsl"
    value = tsl[3:]
    # Remove possible suffix " (assigned to previous version _)"
    if len(value) > 2:
        value = value[:2].rstrip()
    if value == "NA":
        return 0
    return int(value)

def dedupe_ens_no_hugo(dframe):
    """Deduplicate Ensembl ID using Entrez ID but not HUGO gene name."""
    if len(dframe) == 1:
        return dframe.index[0]
    return dedupe_tx(dframe)

def correct_cnr(cnr, do_gc, do_txlen, max_log2, diploid_parx_genome):
    """Apply bias corrections & smoothing.

    - Biases: 'gc', 'length'
    - Smoothing: rolling triangle window using weights.
    """
    cnr.center_all(diploid_parx_genome=diploid_parx_genome)
    # Biases, similar to stock CNVkit
    if any((do_gc, do_txlen)):
        if do_gc and "gc" in cnr:
            cnr = center_by_window(cnr, 0.1, cnr["gc"])
        if do_txlen and "tx_length" in cnr:
            cnr = center_by_window(cnr, 0.1, cnr["tx_length"])
        cnr.center_all()
    if max_log2:
        cnr[cnr["log2"] > max_log2, "log2"] = max_log2
    return cnr

def bam_total_reads(bam_fname: str, fasta: Optional[str] = None) -> int64:
    """Count the total number of mapped reads in a BAM file.

    Uses the BAM index to do this quickly.
    """
    table = idxstats(bam_fname, drop_unmapped=True, fasta=fasta)
    return table.mapped.sum()

def ensure_bam_sorted(
    bam_fname: str, by_name: bool = False, span: int = 50, fasta: Optional[str] = None
) -> bool:
    """Test if the reads in a BAM file are sorted as expected.

    by_name=True: reads are expected to be sorted by query name. Consecutive
    read IDs are in alphabetical order, and read pairs appear together.

    by_name=False: reads are sorted by position. Consecutive reads have
    increasing position.
    """
    if by_name:
        # Compare read IDs
        def out_of_order(read, prev) -> bool:
            return not (prev is None or prev.qname <= read.qname)

    else:
        # Compare read locations
        def out_of_order(read, prev) -> bool:
            return not (prev is None or read.tid != prev.tid or prev.pos <= read.pos)

    # ENH - repeat at 50%, ~99% through the BAM
    bam = pysam.AlignmentFile(bam_fname, "rb", reference_filename=fasta)
    last_read = None
    for read in islice(bam, span):
        if out_of_order(read, last_read):
            return False
        last_read = read
    bam.close()
    return True

def is_newer_than(target_fname: str, orig_fname: str) -> bool:
    """Compare file modification times."""
    if not os.path.isfile(target_fname):
        return False
    return os.stat(target_fname).st_mtime >= os.stat(orig_fname).st_mtime

def genome_scatter(
    cnarr: CopyNumArray,
    segments: Optional[CopyNumArray] = None,
    variants: None = None,
    do_trend: bool = False,
    y_min: None = None,
    y_max: None = None,
    title: None = None,
    segment_color: str = SEG_COLOR,
) -> Figure:
    """Plot all chromosomes, concatenated on one plot."""
    if (cnarr or segments) and variants:
        # Lay out top 3/5 for the CN scatter, bottom 2/5 for SNP plot
        axgrid = pyplot.GridSpec(5, 1, hspace=0.85)
        axis = pyplot.subplot(axgrid[:3])
        axis2 = pyplot.subplot(axgrid[3:], sharex=axis)
        # Place chromosome labels between the CNR and SNP plots
        axis2.tick_params(labelbottom=False)
        chrom_sizes = plots.chromosome_sizes(cnarr or segments)
        axis2 = snv_on_genome(
            axis2, variants, chrom_sizes, segments, do_trend, segment_color
        )
    else:
        _fig, axis = pyplot.subplots()
    if title is None:
        title = (cnarr or segments or variants).sample_id
    if cnarr or segments:
        axis.set_title(title)
        axis = cnv_on_genome(
            axis, cnarr, segments, do_trend, y_min, y_max, segment_color
        )
    else:
        axis.set_title(f"Variant allele frequencies: {title}")
        chrom_sizes = collections.OrderedDict(
            (chrom, subarr["end"].max()) for chrom, subarr in variants.by_chromosome()
        )
        axis = snv_on_genome(
            axis, variants, chrom_sizes, segments, do_trend, segment_color
        )
    return axis.get_figure()

def snv_on_genome(axis, variants, chrom_sizes, segments, do_trend, segment_color):
    """Plot a scatter-plot of SNP chromosomal positions and shifts."""
    axis.set_ylim(0.0, 1.0)
    axis.set_ylabel("VAF")
    x_starts = plots.plot_chromosome_dividers(axis, chrom_sizes)

    # Calculate the coordinates of plot components
    chrom_snvs = dict(variants.by_chromosome())
    if segments:
        chrom_segs = dict(segments.by_chromosome())
    elif do_trend:
        # Pretend a single segment covers each chromosome
        chrom_segs = {chrom: None for chrom in chrom_snvs}
    else:
        chrom_segs = {}

    for chrom, x_offset in x_starts.items():
        if chrom not in chrom_snvs:
            continue

        snvs = chrom_snvs[chrom]
        # Plot the points
        axis.scatter(
            snvs["start"].values + x_offset,
            snvs["alt_freq"].values,
            color=POINT_COLOR,
            edgecolor="none",
            alpha=0.2,
            marker=".",
        )
        # Trend bars: always calculated, only shown on request
        if chrom in chrom_segs:
            # Draw average VAF within each segment
            segs = chrom_segs[chrom]
            for seg, v_freq in get_segment_vafs(snvs, segs):
                if seg:
                    posn = [seg.start + x_offset, seg.end + x_offset]
                    color = choose_segment_color(
                        seg, segment_color, default_bright=False
                    )
                else:
                    posn = [snvs.start.iat[0] + x_offset, snvs.start.iat[-1] + x_offset]
                    color = TREND_COLOR
                axis.plot(
                    posn,
                    [v_freq, v_freq],
                    color=color,
                    linewidth=2,
                    zorder=-1,
                    solid_capstyle="round",
                    snap=False,
                )
    return axis

def setup_chromosome(axis, y_min=None, y_max=None, y_label=None) -> None:
    """Configure axes for plotting a single chromosome's data."""
    if y_min and y_max:
        axis.set_ylim(y_min, y_max)
        if y_min < 0 < y_max:
            axis.axhline(color="k")
    if y_label:
        axis.set_ylabel(y_label)
    axis.tick_params(which="both", direction="out")
    axis.get_xaxis().tick_bottom()
    axis.get_yaxis().tick_left()

def highlight_genes(axis, genes, y_posn) -> None:
    """Show gene regions with background color and a text label."""
    # Rotate text in proportion to gene density
    ngenes = len(genes)
    text_size = "small" if ngenes <= 6 else "x-small"
    if ngenes <= 3:
        text_rot = "horizontal"
    elif ngenes <= 6:
        text_rot = 30
    elif ngenes <= 10:
        text_rot = 45
    elif ngenes <= 20:
        text_rot = 60
    else:
        text_rot = "vertical"
    for gene in genes:
        gene_start, gene_end, gene_name = gene
        # Highlight and label gene region
        # (rescale positions from bases to megabases)
        axis.axvspan(
            gene_start * MB, gene_end * MB, alpha=0.5, color=HIGHLIGHT_COLOR, zorder=-1
        )
        axis.text(
            0.5 * (gene_start + gene_end) * MB,
            y_posn,
            gene_name,
            horizontalalignment="center",
            rotation=text_rot,
            size=text_size,
        )

def require_column(*colnames) -> Callable:
    """Wrapper to coordinate the segment-filtering functions.

    Verify that the given columns are in the CopyNumArray the wrapped function
    takes. Also log the number of rows in the array before and after filtration.
    """
    if len(colnames) == 1:
        msg = "'{}' filter requires column '{}'"
    else:
        msg = "'{}' filter requires columns " + ", ".join(["'{}'"] * len(colnames))

    def wrap(func):
        @functools.wraps(func)
        def wrapped_f(segarr):
            filtname = func.__name__
            if any(c not in segarr for c in colnames):
                raise ValueError(msg.format(filtname, *colnames))
            result = func(segarr)
            logging.info(
                "Filtered by '%s' from %d to %d rows",
                filtname,
                len(segarr),
                len(result),
            )
            return result

        return wrapped_f

    return wrap

def enumerate_changes(levels: Series) -> Series:
    """Assign a unique integer to each run of identical values.

    Repeated but non-consecutive values will be assigned different integers.
    """
    return levels.diff().fillna(0).abs().cumsum().astype(int)

def squash_region(cnarr: DataFrame) -> DataFrame:
    """Reduce a CopyNumArray to 1 row, keeping fields sensible.

    Most fields added by the `segmetrics` command will be dropped.
    """
    assert "weight" in cnarr
    out = {
        "chromosome": [cnarr["chromosome"].iat[0]],
        "start": cnarr["start"].iat[0],
        "end": cnarr["end"].iat[-1],
    }
    region_weight = cnarr["weight"].sum()
    if region_weight > 0:
        out["log2"] = np.average(cnarr["log2"], weights=cnarr["weight"])
    else:
        out["log2"] = np.mean(cnarr["log2"])
    out["gene"] = ",".join(cnarr["gene"].drop_duplicates())
    out["probes"] = cnarr["probes"].sum() if "probes" in cnarr else len(cnarr)
    out["weight"] = region_weight
    if "depth" in cnarr:
        if region_weight > 0:
            out["depth"] = np.average(cnarr["depth"], weights=cnarr["weight"])
        else:
            out["depth"] = np.mean(cnarr["depth"])
    if "baf" in cnarr:
        if region_weight > 0:
            out["baf"] = np.average(cnarr["baf"], weights=cnarr["weight"])
        else:
            out["baf"] = np.mean(cnarr["baf"])
    if "cn" in cnarr:
        if region_weight > 0:
            out["cn"] = weighted_median(cnarr["cn"], cnarr["weight"])
        else:
            out["cn"] = np.median(cnarr["cn"])
        if "cn1" in cnarr:
            if region_weight > 0:
                out["cn1"] = weighted_median(cnarr["cn1"], cnarr["weight"])
            else:
                out["cn1"] = np.median(cnarr["cn1"])
            out["cn2"] = out["cn"] - out["cn1"]
    if "p_bintest" in cnarr:
        # Only relevant for single-bin segments, but this seems safe/conservative
        out["p_bintest"] = cnarr["p_bintest"].max()
    return pd.DataFrame(out)

def cn(segarr: CopyNumArray) -> CopyNumArray:
    """Merge segments by integer copy number."""
    return squash_by_groups(segarr, segarr["cn"])

def make_ci_func(alpha: float, bootstraps: int, smoothed: bool) -> Callable:
    def ci_func(ser, wt):
        return confidence_interval_bootstrap(ser, wt, alpha, bootstraps, smoothed)

    return ci_func

def make_pi_func(alpha: float) -> Callable:
    """Prediction interval, estimated by percentiles."""
    # ENH: weighted percentile
    pct_lo = 100 * alpha / 2
    pct_hi = 100 * (1 - alpha / 2)

    def pi_func(ser, _w):
        return np.percentile(ser, [pct_lo, pct_hi])

    return pi_func

def calc_intervals(
    bins_log2s: list[Series], weights: Series, func: Callable
) -> tuple[ndarray, ndarray]:
    """Compute a stat that yields intervals (low & high values)"""
    out_vals_lo = np.repeat(np.nan, len(bins_log2s))
    out_vals_hi = np.repeat(np.nan, len(bins_log2s))
    for i, ser in enumerate(bins_log2s):
        if len(ser):
            wt = weights[ser.index]
            assert (wt.index == ser.index).all()
            out_vals_lo[i], out_vals_hi[i] = func(ser.values, wt.values)
    return out_vals_lo, out_vals_hi

def segment_mean(cnarr: CopyNumArray, skip_low: bool = False) -> Union[float64, float]:
    """Weighted average of bin log2 values."""
    if skip_low:
        cnarr = cnarr.drop_low_coverage()
    if len(cnarr) == 0:
        return np.nan
    if "weight" in cnarr and cnarr["weight"].any():
        return np.average(cnarr["log2"], weights=cnarr["weight"])
    return cnarr["log2"].mean()

def _pad_array(x: ndarray, wing: int) -> ndarray:
    """Pad the edges of the input array with mirror copies."""
    return np.concatenate((x[wing - 1 :: -1], x, x[: -wing - 1 : -1]))

def rolling_quantile(x: pd.Series, width: int, quantile: float) -> ndarray:
    """Rolling quantile (0--1) with mirrored edges."""
    x, wing, signal = check_inputs(x, width)
    rolled = signal.rolling(2 * wing + 1, 2, center=True).quantile(quantile)
    return np.asarray(rolled[wing:-wing], dtype=float)

def rolling_std(x, width):
    """Rolling quantile (0--1) with mirrored edges."""
    x, wing, signal = check_inputs(x, width)
    rolled = signal.rolling(2 * wing + 1, 2, center=True).std()
    return np.asarray(rolled[wing:-wing], dtype=float)

def filter_names(names: set[str], exclude: tuple[str] = ("mRNA",)) -> set[str]:
    """Remove less-meaningful accessions from the given set."""
    if len(names) > 1:
        ok_names = set(n for n in names if not any(n.startswith(ex) for ex in exclude))
        if ok_names:
            return ok_names
    # Names are not filter-worthy; leave them as they are for now
    return names

def _mirrored_baf(vals: pd.Series, above_half: None = None) -> pd.Series:
    shift = (vals - 0.5).abs()
    if above_half is None:
        above_half = vals.median() > 0.5
    if above_half:
        return 0.5 + shift
    return 0.5 - shift

