def merge_gaps(regions, min_gap):
    """Merge regions across small gaps."""
    prev = next(regions)
    for reg in regions:
        if reg.start - prev.end < min_gap:
            # Merge
            prev = prev._replace(end=reg.end)
        else:
            # Done merging; move on
            yield prev
            prev = reg
    # Residual
    yield prev

def drop_small(regions, min_length):
    """Merge small gaps and filter by minimum length."""
    return (reg for reg in regions
            if reg.end - reg.start >= min_length)

def guess_baits(args) -> None:
    # ENH: can we reserve multiple cores for htslib?
    if args.processes < 1:
        args.processes = None

    if args.targets:
        baits = filter_targets(args.targets, args.sample_bams, args.processes, args.fasta)
    else:
        baits = scan_targets(args.access, args.sample_bams,
                             0.5 * args.min_depth,  # More sensitive 1st pass
                             args.min_gap, args.min_length, args.processes)
    baits = normalize_depth_log2_filter(baits, args.min_depth)
    tabio.write(baits, args.output or sys.stdout, 'bed')
    if args.coverage:
        baits['log2'] = np.log2(baits['depth'] / baits['depth'].median())
        tabio.write(baits, args.coverage, 'tab')

def argument_parsing():
    AP = argparse.ArgumentParser(description=__doc__)
    AP.add_argument("reference", help="Reference file.")
    AP.add_argument("-o", "--output",
                    help="Output base name (extensions added automatically).")
    return AP.parse_args()

def FindLocalPeaks(
    signal: ndarray,  # const double * signal,
    # peakLoc, #int * peakLoc
) -> ndarray:
    """Find local maxima on positive values, local minima on negative values.

    First and last index are never considered extramum.

    Parameters
    ----------
    signal : const array of floats

    Returns
    -------
    peakLoc : array of ints
        Locations of extrema in `signal`

    Source: HaarSeg.c
    """
    # use numpy.diff to simplify? argmax, argmin?
    maxSuspect = minSuspect = None
    peakLoc = []
    for k in range(1, len(signal) - 1):
        sig_prev, sig_curr, sig_next = signal[k - 1 : k + 2]
        if sig_curr > 0:
            # Look for local maxima
            if (sig_curr > sig_prev) and (sig_curr > sig_next):
                peakLoc.append(k)
            elif (sig_curr > sig_prev) and (sig_curr == sig_next):
                maxSuspect = k
            elif (sig_curr == sig_prev) and (sig_curr > sig_next):
                # Take the first in a series of equal values
                if maxSuspect is not None:
                    peakLoc.append(maxSuspect)
                    maxSuspect = None
            elif (sig_curr == sig_prev) and (sig_curr < sig_next):
                maxSuspect = None

        elif sig_curr < 0:
            # Look for local maxima
            if (sig_curr < sig_prev) and (sig_curr < sig_next):
                peakLoc.append(k)
            elif (sig_curr < sig_prev) and (sig_curr == sig_next):
                minSuspect = k
            elif (sig_curr == sig_prev) and (sig_curr < sig_next):
                if minSuspect is not None:
                    peakLoc.append(minSuspect)
                    minSuspect = None
            elif (sig_curr == sig_prev) and (sig_curr > sig_next):
                minSuspect = None

    return np.array(peakLoc, dtype=np.int_)

def _to_str(s, enc=locale.getpreferredencoding()):  # noqa: B008
    # Evaluate encoding once at function definition for performance
    if isinstance(s, bytes):
        return s.decode(enc)
    return s

def _ds(
    args: tuple[CNA, str, None, float, None, bool, int, int, bool, str, bool],
) -> CNA:
    """Wrapper for parallel map"""
    return _do_segmentation(*args)

def _do_segmentation(
    cnarr: CNA,
    method: str,
    diploid_parx_genome: Optional[str],
    threshold: Optional[float],
    variants: Optional[VariantArray] = None,
    skip_low: bool = False,
    skip_outliers: int = 10,
    min_weight: int = 0,
    save_dataframe: bool = False,
    rscript_path: str = "Rscript",
    smooth_cbs: bool = False,
) -> CNA:
    """Infer copy number segments from the given coverage table."""
    if not len(cnarr):
        return cnarr

    filtered_cn = cnarr.copy()
    # Filter out bins with no or near-zero sequencing coverage
    if skip_low:
        filtered_cn = filtered_cn.drop_low_coverage(verbose=False)
    # Filter by distance from rolling quantiles
    if skip_outliers:
        filtered_cn = drop_outliers(filtered_cn, 50, skip_outliers)
    # Filter by bin weights
    if min_weight:
        weight_too_low = (filtered_cn["weight"] < min_weight).fillna(True)
    else:
        weight_too_low = (filtered_cn["weight"] == 0).fillna(True)
    n_weight_too_low = weight_too_low.sum() if len(weight_too_low) else 0
    if n_weight_too_low:
        filtered_cn = filtered_cn[~weight_too_low]
        if min_weight:
            logging.debug(
                "Dropped %d bins with weight below %s", n_weight_too_low, min_weight
            )
        else:
            logging.debug("Dropped %d bins with zero weight", n_weight_too_low)

    if len(filtered_cn) != len(cnarr):
        msg = f"Dropped {len(cnarr) - len(filtered_cn)} / {len(cnarr)} bins"
        if cnarr["chromosome"].iat[0] == cnarr["chromosome"].iat[-1]:
            msg += " on chromosome " + str(cnarr["chromosome"].iat[0])
        logging.info(msg)
    if not len(filtered_cn):
        return filtered_cn

    seg_out = ""
    if method == "haar":
        segarr = haar.segment_haar(filtered_cn, threshold)

    elif method == "none":
        segarr = none.segment_none(filtered_cn)

    elif method.startswith("hmm"):
        segarr = hmm.segment_hmm(
            filtered_cn, method, diploid_parx_genome, threshold, variants
        )

    elif method in ("cbs", "flasso"):
        # Run R scripts to calculate copy number segments
        rscript = {
            "cbs": cbs.CBS_RSCRIPT,
            "flasso": flasso.FLASSO_RSCRIPT,
        }[method]

        filtered_cn["start"] += 1  # Convert to 1-indexed coordinates for R
        with tempfile.NamedTemporaryFile(suffix=".cnr", mode="w+t") as tmp:
            # TODO tabio.write(filtered_cn, tmp, 'seg')
            filtered_cn.data.to_csv(
                tmp, index=False, sep="\t", float_format="%.6g", mode="w+t"
            )
            tmp.flush()
            script_strings = {
                "probes_fname": tmp.name,
                "sample_id": cnarr.sample_id,
                "threshold": threshold,
                "smooth_cbs": smooth_cbs,
            }
            with core.temp_write_text(
                rscript % script_strings, mode="w+t"
            ) as script_fname:
                seg_out = core.call_quiet(
                    rscript_path, "--no-restore", "--no-environ", script_fname
                )
        # Convert R dataframe contents (SEG) to a proper CopyNumArray
        # NB: Automatically shifts 'start' back from 1- to 0-indexed
        segarr = tabio.read(StringIO(seg_out.decode()), "seg", into=CNA)
        if method == "flasso":
            # Merge adjacent bins with same log2 value into segments
            if "weight" in filtered_cn:
                segarr["weight"] = filtered_cn["weight"]
            else:
                segarr["weight"] = 1.0
            segarr = squash_by_groups(segarr, segarr["log2"], by_arm=True)

    else:
        raise ValueError(f"Unknown method {method!r}")

    segarr.meta = cnarr.meta.copy()
    if variants and not method.startswith("hmm"):
        # Re-segment the variant allele freqs within each segment
        # TODO train on all segments together
        logging.info("Re-segmenting on variant allele frequency")
        newsegs = [
            hmm.variants_in_segment(subvarr, segment)
            for segment, subvarr in variants.by_ranges(segarr)
        ]
        segarr = segarr.as_dataframe(pd.concat(newsegs))
        segarr["baf"] = variants.baf_by_ranges(segarr)

    segarr = transfer_fields(segarr, cnarr)
    if save_dataframe:
        return segarr, seg_out
    return segarr

def first_of(elems: Sequence) -> Any:
    """Return the first element of the input."""
    return elems[0]

def last_of(elems: Sequence) -> Any:
    """Return the last element of the input."""
    return elems[-1]

def join_strings(elems: Iterable, sep: str = ",") -> str:
    """Join a Series of strings by commas."""
    # ENH if elements are also comma-separated, split+uniq those too
    return sep.join(pd.unique(elems))

def merge_strands(elems: Sequence) -> str:
    """Summarize the given strands as '+', '-', or '.' (both/mixed)"""
    strands = set(elems)
    if len(strands) > 1:
        return "."
    return elems[0]

def make_const(val: Any) -> Callable:
    """Return a function that simply returns the value given as input here."""

    def const(_elems):
        return val

    return const

def by_ranges(
    table: pd.DataFrame, other: pd.DataFrame, mode: str, keep_empty: bool
) -> None:
    """Group rows by another GenomicArray's bin coordinate ranges."""
    for _chrom, bin_rows, src_rows in by_shared_chroms(other, table, keep_empty):
        if src_rows is not None:
            subranges = iter_ranges(
                src_rows, None, bin_rows["start"], bin_rows["end"], mode
            )
            for bin_row, subrange in zip(bin_rows.itertuples(index=False), subranges):
                yield bin_row, subrange
        elif keep_empty:
            for bin_row in bin_rows.itertuples(index=False):
                yield bin_row, []

def by_shared_chroms(
    table: pd.DataFrame, other: pd.DataFrame, keep_empty: bool = True
) -> Iterator[
    Union[tuple[str, pd.DataFrame, None], tuple[str, pd.DataFrame, pd.DataFrame]]
]:
    """Group rows for both `table` and `other` by matching chromosome names."""
    # When both `table` and `other` contain only one chromosome each, and it's
    # the same chromosome, we can just return the original tables.
    table_chr, other_chr = set(table["chromosome"]), set(other["chromosome"])
    if len(table_chr) == 1 and table_chr == other_chr:
        yield table["chromosome"].iat[0], table, other
        # yield None, table, other
    else:
        other_chroms = {c: o for c, o in other.groupby("chromosome", sort=False)}
        for chrom, ctable in table.groupby("chromosome", sort=False):
            if chrom in other_chroms:
                otable = other_chroms[chrom]
                yield chrom, ctable, otable
            elif keep_empty:
                yield chrom, ctable, None

def into_ranges(
    source: pd.DataFrame,
    dest: pd.DataFrame,
    src_col: str,
    default: Any,
    summary_func: Optional[Callable],
) -> Union[pd.DataFrame, pd.Series]:
    """Group a column in `source` by regions in `dest` and summarize."""
    if not len(source) or not len(dest):
        return dest

    if summary_func is None:
        # Choose a type-appropriate summary function
        elem = source[src_col].iat[0]
        if isinstance(elem, (str, np.bytes_)):
            summary_func = join_strings
        elif isinstance(elem, (float, np.float64)):
            summary_func = np.nanmedian
        else:
            summary_func = first_of
    elif not callable(summary_func):
        # Just fill in the given value, I suppose.
        summary_func = make_const(summary_func)

    def series2value(ser):
        if len(ser) == 0:
            return default
        if len(ser) == 1:
            return ser.iat[0]
        return summary_func(ser)

    column = source[src_col]
    result = [
        series2value(column[slc]) for slc in iter_slices(source, dest, "outer", True)
    ]
    return pd.Series(result)

def iter_ranges(
    table: pd.DataFrame,
    chrom: Optional[str],
    starts: Optional[Sequence[Numeric]],
    ends: Optional[Sequence[Numeric]],
    mode: str,
) -> Iterator[pd.DataFrame]:
    """Iterate through sub-ranges."""
    assert mode in ("inner", "outer", "trim")
    # Optional if we've already subsetted by chromosome (not checked!)
    if chrom:
        assert isinstance(chrom, str)  # ENH: accept array?
        try:
            table = table[table["chromosome"] == chrom]
        except KeyError as exc:
            raise KeyError(f"Chromosome {chrom} is not in this probe set") from exc
    for region_idx, start_val, end_val in idx_ranges(
        table, starts, ends, "inner" if mode == "inner" else "outer"
    ):
        subtable = table.iloc[region_idx]
        if mode == "trim":
            subtable = subtable.copy()
            # Update 5' endpoints to the boundary
            if start_val:
                subtable.start = subtable.start.clip(lower=start_val)
            # Update 3' endpoints to the boundary
            if end_val:
                subtable.end = subtable.end.clip(upper=end_val)
        yield subtable

def iter_slices(
    table: pd.DataFrame, other: pd.DataFrame, mode: str, keep_empty: bool
) -> Iterator[Union[ndarray, Index]]:
    """Yields indices to extract ranges from `table`.

    Returns an iterable of integer arrays that can apply to Series objects,
    i.e. columns of `table`. These indices are of the DataFrame/Series' Index,
    not array coordinates -- so be sure to use DataFrame.loc, Series.loc, or
    Series getitem, as opposed to .iloc or indexing directly into Numpy arrays.
    """
    for _c, bin_rows, src_rows in by_shared_chroms(other, table, keep_empty):
        if src_rows is None:
            # Emit empty indices since 'table' is missing this chromosome
            for _ in range(len(bin_rows)):
                yield pd.Index([], dtype="int64")
        else:
            for slc, _s, _e in idx_ranges(src_rows, bin_rows.start, bin_rows.end, mode):
                indices = src_rows.index[slc].to_numpy()
                if keep_empty or len(indices):
                    yield indices

def _irange_simple(
    table: pd.DataFrame, starts: pd.Series, ends: pd.Series, mode: str
) -> Iterator[tuple[slice, int, int]]:
    """Slice subsets of table when regions are not nested."""
    if starts is not None and len(starts):
        if mode == "inner":
            # Only rows entirely after the start point
            start_idxs = table.start.searchsorted(starts)
        else:
            # Include all rows overlapping the start point
            start_idxs = table.end.searchsorted(starts, "right")
    else:
        starts = np.zeros(len(ends) if ends is not None else 1, dtype=np.int_)
        start_idxs = starts.copy()

    if ends is not None and len(ends):
        if mode == "inner":
            end_idxs = table.end.searchsorted(ends, "right")
        else:
            end_idxs = table.start.searchsorted(ends)
    else:
        end_idxs = np.repeat(len(table), len(starts))
        ends = [None] * len(starts)

    for start_idx, start_val, end_idx, end_val in zip(
        start_idxs, starts, end_idxs, ends
    ):
        yield (slice(start_idx, end_idx), start_val, end_val)

def _irange_nested(
    table: pd.DataFrame, starts: Sequence, ends: Sequence, mode: str
) -> Iterator[tuple[ndarray, int, int]]:
    """Slice subsets of table when regions are nested."""
    # ENH: Binary Interval Search (BITS) or Layer&Quinlan(2015)
    assert len(starts) == len(ends) > 0
    for start_val, end_val in zip(starts, ends):
        # Mask of table rows to keep for this query region
        region_mask = np.ones(len(table), dtype=np.bool_)
        if start_val:
            if mode == "inner":
                # Only rows entirely after the start point
                start_idx = table.start.searchsorted(start_val)
                region_mask[: int(start_idx)] = 0
            else:
                # Include all rows overlapping the start point
                region_mask = table.end.to_numpy() > start_val
        if end_val is not None:
            if mode == "inner":
                # Only rows up to the end point
                region_mask &= table.end.to_numpy() <= end_val
            else:
                # Include all rows overlapping the end point
                end_idx = table.start.searchsorted(end_val)
                region_mask[int(end_idx) :] = 0

        yield region_mask, start_val, end_val

def flatten(
    table,
    combine: Optional[dict[str, Callable]] = None,
    split_columns: Optional[Iterable[str]] = None,
):
    """Combine overlapping regions into single rows, similar to bedtools merge."""
    if table.empty:
        return table
    if (table.start.to_numpy()[1:] >= table.end.cummax().to_numpy()[:-1]).all():
        return table
    # NB: Input rows and columns should already be sorted like this
    table = table.sort_values(["chromosome", "start", "end"])
    cmb = get_combiners(table, False, combine)
    out = (
        table.groupby(by="chromosome", as_index=False, group_keys=False, sort=False)[
            table.columns
        ]
        .apply(_flatten_overlapping, cmb, split_columns)
        .reset_index(drop=True)
    )
    return out.reindex(
        out.chromosome.apply(sorter_chrom).sort_values(kind="mergesort").index
    )

def _flatten_overlapping(
    table, combine: dict[str, Callable], split_columns: Optional[Iterable]
):
    """Merge overlapping regions within a chromosome/strand.

    Assume chromosome and (if relevant) strand are already identical, so only
    start and end coordinates are considered.
    """
    if split_columns:
        row_groups = (
            tuple(_flatten_tuples_split(row_group, combine, split_columns))
            for row_group in _nonoverlapping_groups(table, 0)
        )
    else:
        row_groups = (
            tuple(_flatten_tuples(row_group, combine))
            for row_group in _nonoverlapping_groups(table, 0)
        )
    all_row_groups = itertools.chain(*row_groups)
    return pd.DataFrame.from_records(list(all_row_groups), columns=table.columns)

def merge(
    table,
    bp: int = 0,
    stranded: bool = False,
    combine: Optional[dict[str, Callable]] = None,
):
    """Merge overlapping rows in a DataFrame."""
    if table.empty:
        return table
    gap_sizes = table.start.to_numpy()[1:] - table.end.cummax().to_numpy()[:-1]
    if (gap_sizes > -bp).all():
        return table
    if stranded:
        groupkey = ["chromosome", "strand"]
    else:
        # NB: same gene name can appear on alt. contigs
        groupkey = ["chromosome"]
    table = table.sort_values([*groupkey, "start", "end"])
    cmb = get_combiners(table, stranded, combine)
    out = (
        table.groupby(by=groupkey, as_index=False, group_keys=False, sort=False)[
            table.columns
        ]
        .apply(_merge_overlapping, bp, cmb)
        .reset_index(drop=True)
    )
    # Re-sort chromosomes cleverly instead of lexicographically
    return out.reindex(
        out.chromosome.apply(sorter_chrom).sort_values(kind="mergesort").index
    )

def _merge_overlapping(table, bp: int, combine: dict[str, Callable]):
    """Merge overlapping regions within a chromosome/strand.

    Assume chromosome and (if relevant) strand are already identical, so only
    start and end coordinates are considered.
    """
    merged_rows = [
        _squash_tuples(row_group, combine)
        for row_group in _nonoverlapping_groups(table, bp)
    ]
    return pd.DataFrame.from_records(merged_rows, columns=merged_rows[0]._fields)

def _squash_tuples(keyed_rows, combine: dict[str, Callable]):
    """Combine multiple rows into one NamedTuple.

    Parameters
    ----------
    keyed_rows : iterable
        pairs of (non-overlapping-group index, overlapping rows)
    combine : dict

    Returns
    -------
    namedtuple
    """
    rows = [kr[1] for kr in keyed_rows]  # list(rows)
    firsttup = rows[0]
    if len(rows) == 1:
        return firsttup
    newfields = {
        key: combiner(pd.Series([getattr(r, key) for r in rows]))
        for key, combiner in combine.items()
    }
    return firsttup._replace(**newfields)

def to_label(row: Region) -> str:
    """Convert a Region tuple to a region label."""
    return f"{row.chromosome}:{row.start + 1}-{row.end}"

def unpack_range(a_range: Union[str, Sequence]) -> Region:
    """Extract chromosome, start, end from a string or tuple.

    Examples::

        "chr1" -> ("chr1", None, None)
        "chr1:100-123" -> ("chr1", 99, 123)
        ("chr1", 100, 123) -> ("chr1", 100, 123)
    """
    if not a_range:
        return Region(None, None, None)
    if isinstance(a_range, str):
        if ":" in a_range and "-" in a_range:
            return from_label(a_range, keep_gene=False)  # type: ignore
        return Region(a_range, None, None)
    if isinstance(a_range, (list, tuple)):
        if len(a_range) == 3:
            return Region(*a_range)
        if len(a_range) == 4:
            return Region(*a_range[:3])
    raise ValueError(f"Not a range: {a_range!r}")

def subdivide(
    table, avg_size: int, min_size: int = 0, verbose: bool = False
) -> pd.DataFrame:
    """Split `table` rows into sub-regions of about `avg_size`."""
    return pd.DataFrame.from_records(
        _split_targets(table, avg_size, min_size, verbose), columns=table.columns
    )

def subtract(table, other) -> pd.DataFrame:
    """Subtract one set of regions from another, returning the one-way difference."""
    if not len(other):
        return table
    return pd.DataFrame.from_records(_subtraction(table, other), columns=table.columns)

def skg_convert(args) -> None:
    logging.info("Converting %s%s to %s",
                 "input" if args.infile is sys.stdin else args.infile,
                 " from "+ args.in_fmt if args.in_fmt != 'auto' else '',
                 args.out_fmt)

    if args.in_fmt == 'auto':
        args.in_fmt = tabio.sniff_region_format(args.infile)
    # Format-specific input options
    kwargs = {}
    if args.in_fmt == 'gff':
        if args.gff_tag:
            kwargs['tag'] = args.gff_tag
        if args.gff_type:
            kwargs['keep_type'] = args.gff_type
    elif args.in_fmt == 'refflat':
        if args.refflat_type == 'exon':
            kwargs['exons'] = True
        elif args.refflat_type == 'cds':
            kwargs['cds'] = True
    regions = tabio.read(args.infile, args.in_fmt, **kwargs)

    # Post-processing
    if args.flatten:
        regions = regions.flatten()
    elif args.merge:
        regions = regions.merge(bp=args.merge)

    tabio.write(regions, args.output, args.out_fmt)

def read_bed(infile: str) -> DataFrame:
    """UCSC Browser Extensible Data (BED) format.

    A BED file has these columns::

        chromosome, start position, end position, [gene, strand, other stuff...]

    Coordinate indexing is from 0.

    Sets of regions are separated by "track" lines. This function stops reading
    after encountering a track line other than the first one in the file.
    """

    # ENH: just pd.read_csv, skip 'track'
    @report_bad_line
    def _parse_line(line):
        fields = line.split("\t", 6)
        chrom, start, end = fields[:3]
        gene = fields[3].rstrip() if len(fields) >= 4 else "-"
        strand = fields[5].rstrip() if len(fields) >= 6 else "."
        return chrom, int(start), int(end), gene, strand

    def track2track(handle):
        try:
            firstline = next(handle)
            if firstline.startswith("browser "):
                # UCSC Genome Browser feature -- ignore it
                firstline = next(handle)
        except StopIteration:
            pass
        else:
            if not firstline.startswith("track"):
                yield firstline
            for line in handle:
                if line.startswith("track"):
                    break
                yield line

    with as_handle(infile, "r") as handle:
        rows = map(_parse_line, track2track(handle))
        return pd.DataFrame.from_records(
            rows, columns=["chromosome", "start", "end", "gene", "strand"]
        )

def read_bed6(infile):
    """6-column BED format: chromosome, start, end, name, score, strand."""
    return NotImplemented

def parse_bed_track(line):
    """Parse the "name" field of a BED track definition line.

    Example:
    track name=146793_BastianLabv2_P2_target_region description="146793_BastianLabv2_P2_target_region"
    """
    fields = shlex.split(line)  # raises ValueError if line is corrupted
    assert fields[0] == "track"
    for field in fields[1:]:
        if "=" in field:
            key, val = field.split("=", 1)
            if key == "name":
                return val
    raise ValueError("No name defined for this track")

def write_bed(dframe):
    """Serialize `dframe` in BED format."""
    if len(dframe.columns) == 3:
        return write_bed3(dframe)
    if len(dframe.columns) == 3:
        return write_bed4(dframe)
    # Default: BED-like, keep all trailing columns
    return dframe

def write_bed3(dframe: DataFrame) -> DataFrame:
    """Serialize `dframe` in 3-column BED format."""
    return dframe.loc[:, ["chromosome", "start", "end"]]

def write_bed4(dframe: DataFrame) -> DataFrame:
    """Serialize `dframe` in 4-column BED format."""
    dframe = dframe.copy()
    if "gene" not in dframe:
        dframe["gene"] = "-"
    return dframe.loc[:, ["chromosome", "start", "end", "gene"]]

def _split_exons(dframe):
    """Split exons into individual rows."""
    for row in dframe.itertuples(index=False):
        shared = row[:4]
        for start, end in zip(row.exon_starts, row.exon_ends):
            yield (*shared, start, end)

def write_interval(dframe):
    """Transform `dframe` contents to Interval format."""
    dframe = dframe.copy()
    dframe["start"] += 1
    if "gene" not in dframe:
        dframe["gene"] = "-"
    if "strand" not in dframe:
        dframe["strand"] = "+"
    return dframe.loc[:, ["chromosome", "start", "end", "strand", "gene"]]

def write_picard_hs(dframe):
    """Transform `dframe` contents to HsMetrics format."""
    if "depth" in dframe.columns:
        coverage = dframe["depth"]
        norm = coverage / coverage.mean()
    else:
        coverage = np.exp2(dframe["log2"])
        norm = coverage
    return pd.DataFrame.from_dict(
        OD(
            [
                ("chrom", dframe["chromosome"]),
                ("start", dframe["start"] + 1),
                ("end", dframe["end"]),
                ("length", dframe["end"] - dframe["start"]),
                ("name", dframe["gene"]),
                ("%gc", dframe["gc"]),
                ("mean_coverage", coverage),
                ("normalized_coverage", norm),
            ]
        )
    )

def read_seg(
    infile, sample_id=None, chrom_names=None, chrom_prefix=None, from_log10=False
):
    """Read one sample from a SEG file.

    Parameters
    ----------
    sample_id : string, int or None
        If a string identifier, return the sample matching that ID.  If a
        positive integer, return the sample at that index position, counting
        from 0. If None (default), return the first sample in the file.
    chrom_names : dict
        Map (string) chromosome IDs to names. (Applied before chrom_prefix.)
        e.g. {'23': 'X', '24': 'Y', '25': 'M'}
    chrom_prefix : str
        Prepend this string to chromosome names. (Usually 'chr' or None)
    from_log10 : bool
        Convert values from log10 to log2.

    Returns
    -------
    DataFrame of the selected sample's segments.
    """
    results = parse_seg(infile, chrom_names, chrom_prefix, from_log10)
    if isinstance(sample_id, int):
        # Select sample by index number
        for i, (_sid, dframe) in enumerate(results):
            if i == sample_id:
                return dframe
        else:
            raise IndexError(f"No sample index {sample_id} found in SEG file")

    elif isinstance(sample_id, str):
        # Select sample by name
        for sid, dframe in results:
            if sid == sample_id:
                return dframe
        else:
            raise IndexError(f"No sample ID '{sample_id}' found in SEG file")
    else:
        # Select the first sample
        sid, dframe = next(results)
        try:
            next(results)
        except StopIteration:
            pass
        else:
            logging.warning(
                "WARNING: SEG file contains multiple samples; "
                "returning the first sample '%s'",
                sid,
            )
        return dframe

def write_seg(
    dframe: Union[tuple[pd.DataFrame], tuple[pd.DataFrame, pd.DataFrame]],
    sample_id: Optional[Union[tuple[str], tuple[str, str]]] = None,
    chrom_ids: Optional[bool] = None,
) -> pd.DataFrame:
    """Format a dataframe or list of dataframes as SEG.

    To put multiple samples into one SEG table, pass `dframe` and `sample_id`
    as equal-length lists of data tables and sample IDs in matching order.
    """
    assert sample_id is not None
    if isinstance(dframe, pd.DataFrame):
        first = dframe
        first_sid = sample_id
        sids = dframes = None
    else:
        assert not isinstance(sample_id, str)
        dframes = iter(dframe)
        sids = iter(sample_id)
        first = next(dframes)
        first_sid = next(sids)

    if chrom_ids in (None, True):
        chrom_ids = create_chrom_ids(first)
    results = [format_seg(first, first_sid, chrom_ids)]
    if dframes is not None:
        # Unpack matching lists of data and sample IDs
        results.extend(
            format_seg(subframe, sid, chrom_ids)
            for subframe, sid in zip_longest(dframes, sids)
        )
    return pd.concat(results)

def format_seg(dframe: pd.DataFrame, sample_id: str, chrom_ids: bool) -> pd.DataFrame:
    """Transform `dframe` contents to match SEG format."""
    assert dframe is not None
    assert sample_id is not None
    chroms = dframe.chromosome.replace(chrom_ids) if chrom_ids else dframe.chromosome
    rename_cols = {"log2": "seg.mean", "start": "loc.start", "end": "loc.end"}
    # NB: in some programs the "sampleName" column is labeled "ID"
    reindex_cols = ["ID", "chrom", "loc.start", "loc.end", "seg.mean"]
    if "probes" in dframe:
        rename_cols["probes"] = "num.mark"  # or num_probes
        reindex_cols.insert(-1, "num.mark")
    return (
        dframe.assign(ID=sample_id, chrom=chroms, start=dframe.start + 1)
        .rename(columns=rename_cols)
        .reindex(columns=reindex_cols)
    )

def create_chrom_ids(segments):
    """Map chromosome names to integers in the order encountered."""
    mapping = collections.OrderedDict(
        (chrom, i + 1)
        for i, chrom in enumerate(segments.chromosome.drop_duplicates())
        if str(i + 1) != chrom
    )
    return mapping

def read_dict(infile):
    colnames = [
        "chromosome",
        "start",
        "end",
        # "file", "md5"
    ]
    with as_handle(infile, "r") as handle:
        rows = _parse_lines(handle)
        return pd.DataFrame.from_records(rows, columns=colnames)

def _parse_lines(lines):
    for line in lines:
        if line.startswith("@SQ"):
            _sq, sn, ln, _ur, _m5 = line.split("\t")
            if sn.startswith("SN:") and ln.startswith("LN:"):
                chrom = sn[3:]
                length = int(ln[3:])
                yield (chrom, 0, length)
            else:
                raise ValueError(f"Bad line: {line!r}")
        elif line.startswith("@HD"):
            pass
        else:
            # NB: not sure if there's any other valid row type
            # Assume it's some garbage at the end of the file & bail
            # (or an interval list with SAM header, but we've specified dict
            # and not interval, so still return what we've parsed up to this
            # point)
            break

def write_tab(dframe: DataFrame) -> DataFrame:
    """Write tab-separated data with column names in the first row."""
    return dframe

def write_text(dframe):
    """Text coordinate format: "chr:start-end", one per line."""
    dframe = dframe.copy()
    dframe["start"] += 1
    return dframe.apply(to_label, axis=1)

def report_bad_line(line_parser: Callable) -> Callable:
    @functools.wraps(line_parser)
    def wrapper(line):
        try:
            return line_parser(line)
        except ValueError as exc:
            raise ValueError("Bad line: %r" % line) from exc

    return wrapper

def _choose_samples(
    vcf_reader: VariantFile, sample_id: Optional[str], normal_id: Optional[str]
) -> tuple[str, str]:
    """Emit the sample IDs of all samples or tumor-normal pairs in the VCF.

    Determine tumor-normal pairs from the PEDIGREE tag(s). If no PEDIGREE tag
    is present, use the specified sample_id and normal_id as the pair, or if
    unspecified, emit all samples as unpaired tumors.
    """
    vcf_samples = list(vcf_reader.header.samples)
    if isinstance(sample_id, int):
        sample_id = vcf_samples[sample_id]
    if isinstance(normal_id, int):
        normal_id = vcf_samples[normal_id]
    for sid in (sample_id, normal_id):
        if sid and sid not in vcf_samples:
            raise IndexError(f"Specified sample {sid} not in VCF file")
    pairs = None
    peds = list(_parse_pedigrees(vcf_reader))
    if peds:
        # Trust the PEDIGREE tag
        pairs = peds
    elif normal_id:
        # All/any other samples are tumors paired with this normal
        other_ids = [s for s in vcf_samples if s != normal_id]
        if not other_ids:
            raise IndexError(
                f"No other sample in VCF besides the specified normal {normal_id}; "
                + "did you mean to use this as the sample_id instead?"
            )
        pairs = [(oid, normal_id) for oid in other_ids]
    else:
        # All samples are unpaired tumors
        pairs = [(sid, None) for sid in vcf_samples]
    if sample_id:
        # Keep only the specified tumor/test sample
        pairs = [(s, n) for s, n in pairs if s == sample_id]
    if not pairs:
        # sample_id refers to a normal/control sample -- salvage it
        pairs = [(sample_id, None)]
    for sid in set(chain(*pairs)) - {None}:
        _confirm_unique(sid, vcf_samples)

    sid, nid = pairs[0]
    if len(pairs) > 1:
        if nid:
            logging.warning(
                "WARNING: VCF file contains multiple tumor-normal "
                "pairs; returning the first pair '%s' / '%s'",
                sid,
                nid,
            )
        else:
            logging.warning(
                "WARNING: VCF file contains multiple samples; "
                "returning the first sample '%s'",
                sid,
            )

    return sid, nid

def _parse_pedigrees(vcf_reader: VariantFile) -> Iterator[tuple[str, str]]:
    """Extract tumor/normal pair sample IDs from the VCF header.

    Return an iterable of (tumor sample ID, normal sample ID).
    """
    meta = collections.defaultdict(list)
    for hr in vcf_reader.header.records:
        if hr.key and hr.key not in ("ALT", "FILTER", "FORMAT", "INFO", "contig"):
            meta[hr.key].append(dict(hr.items()))
    # Prefer the standard tag
    if "PEDIGREE" in meta:
        for tag in meta["PEDIGREE"]:
            if "Derived" in tag:
                sample_id = tag["Derived"]
                normal_id = tag["Original"]
                logging.debug(
                    "Found tumor sample %s and normal sample %s "
                    "in the VCF header PEDIGREE tag",
                    sample_id,
                    normal_id,
                )
                yield sample_id, normal_id
    # GATK Mutect and Mutect2 imply paired tumor & normal IDs
    elif "GATKCommandLine" in meta:
        # GATK 3.0(?) and earlier
        for tag in meta["GATKCommandLine"]:
            if tag.get("ID") == "MuTect":  # any others OK?
                options = dict(
                    kv.split("=", 1)
                    for kv in (tag["CommandLineOptions"].strip('"').split())
                    if "=" in kv
                )
                sample_id = options.get("tumor_sample_name")
                normal_id = options["normal_sample_name"]
                logging.debug(
                    "Found tumor sample %s and normal sample "
                    "%s in the MuTect VCF header",
                    sample_id,
                    normal_id,
                )
                yield sample_id, normal_id
    elif "GATKCommandLine.MuTect2" in meta:
        # GATK 3+ metadata is suboptimal.
        # Apparent T/N convention: The samples are just renamed TUMOR and
        # NORMAL, listed in arbitrary order. Metadata is data! We have always
        # been at war with metadata! (#195)
        # Mutect2 can also run in tumor-only mode (safe fallback)
        if len(vcf_reader.header.samples) == 2:
            sample_ids = tuple(vcf_reader.header.samples)
            if sample_ids == ("NORMAL", "TUMOR"):
                yield ("TUMOR", "NORMAL")
            else:
                yield sample_ids

def _confirm_unique(sample_id: str, samples: list[str]) -> None:
    occurrences = [s for s in samples if s == sample_id]
    if len(occurrences) != 1:
        raise IndexError(f"Did not find a single sample ID '{sample_id}' in: {samples}")

def _parse_records(
    records: VariantFile, sample_id: str, normal_id: str, skip_reject: bool
) -> Iterator[Any]:
    """Parse VCF records into DataFrame rows.

    Apply filters to skip records with low depth, homozygosity, the REJECT
    flag, or the SOMATIC info field.
    """
    cnt_reject = 0  # For logging
    for record in records:
        if (
            skip_reject
            and record.filter
            and len(record.filter) > 0
            and len(set(record.filter) - {".", "PASS", "KEEP"})
        ):
            cnt_reject += 1
            continue

        if record.samples:
            sample = record.samples[sample_id]
            try:
                depth, zygosity, alt_count = _extract_genotype(sample, record)
                if normal_id:
                    normal = record.samples[normal_id]
                    n_depth, n_zygosity, n_alt_count = _extract_genotype(normal, record)
            except Exception as exc:
                logging.error(
                    "Skipping %s:%d %s @ %s; %s",
                    record.chrom,
                    record.pos,
                    record.ref,
                    sample_id,
                    exc,
                )
                raise
        else:
            # Assume unpaired tumor; take DP, AF from INFO (e.g. LoFreq)
            depth = record.info.get("DP", 0.0) if "DP" in record.info else 0.0
            if "AF" in record.info:
                alt_freq = record.info["AF"]
                alt_count = round(alt_freq * depth)
                # NB: No genotype, so crudely guess from allele frequency
                if alt_freq < 0.25:
                    zygosity = 0.0
                elif alt_freq < 0.75:
                    zygosity = 0.5
                else:
                    zygosity = 1.0
            else:
                alt_count = 0
                zygosity = 0.0

        is_som = "SOMATIC" in record.info and bool(record.info.get("SOMATIC"))
        # Split multiallelics?
        # XXX Ensure sample genotypes are handled properly
        start = record.start
        if record.alts:
            for alt in record.alts:
                if alt == "<NON_REF>":
                    # gVCF placeholder -- not a real allele
                    continue
                end = _get_end(start, alt, record.info)
                row = (
                    record.chrom,
                    start,
                    end,
                    record.ref,
                    alt,
                    is_som,
                    zygosity,
                    depth,
                    alt_count,
                )
                if normal_id:
                    row += (n_zygosity, n_depth, n_alt_count)
                yield row

    if cnt_reject:
        logging.info("Filtered out %d records", cnt_reject)

def _extract_genotype(
    sample: VariantRecordSample, record: VariantRecord
) -> Union[
    tuple[None, float, int],
    tuple[int, float, int],
    tuple[None, float, float],
    tuple[int, float, float],
]:
    if "DP" in sample:
        depth = sample["DP"]
    elif "AD" in sample and isinstance(sample["AD"], tuple):
        depth = _safesum(sample["AD"])
    elif "DP" in record.info:
        depth = record.info["DP"]
    else:
        # SV or not called, probably
        depth = np.nan  # 0.0
    gts = set(sample["GT"])
    if len(gts) > 1:
        zygosity = 0.5
    elif gts.pop() == 0:
        zygosity = 0.0
    else:
        zygosity = 1.0
    alt_count = _get_alt_count(sample)
    return depth, zygosity, alt_count

def _get_alt_count(sample: VariantRecordSample) -> Union[int, float]:
    """Get the alternative allele count from a sample in a VCF record."""
    if sample.get("AD") not in (None, (None,)):
        # GATK and other callers: (ref depth, alt depth)
        if isinstance(sample["AD"], tuple):
            # Ensure we have alternative alleles and thus two AD values
            # ref only calls in GATK can be missing these
            # 1       49515   .       G       .       50.80   .       AN=2;DP=34;MQ=40.01  GT:AD:DP:MMQ  0/0:34:34:.
            alt_count = sample["AD"][1] if len(sample["AD"]) > 1 else 0.0
        # VarScan
        else:
            alt_count = sample["AD"]
    elif sample.get("CLCAD2") not in (None, (None,)):
        # Qiagen CLC Genomics Server -- similar to GATK's AD
        alt_count = sample["CLCAD2"][1]
    elif "AO" in sample:
        if isinstance(sample["AO"], tuple):
            alt_count = _safesum(sample["AO"])
        elif sample["AO"]:
            alt_count = sample["AO"]
        else:
            alt_count = 0.0
    else:
        alt_count = np.nan
    return alt_count

def _get_end(posn: int, alt: str, info: VariantRecordInfo) -> int:
    """Get record end position."""
    if "END" in info:
        # Structural variant
        return info["END"]
    return posn + len(alt)

