            else:
                cnv_anno[feature_id]['exon'][filter(lambda x: 'transcript_id' in x, feature[-1].split(";"))[0].split(" ")[2]] = 1

        elif feature[-7] == 'transcript':
            feature[-1] = feature[-1].replace('"','')
