                                for trans_id in transcript_dict[k][g].split(";"):
                                    #print trans_id
                                    if cnv_anno[k]['exon'].get(trans_id):
                                        cnv_anno[k]['exon_count'][trans_id] = cnv_anno[k]['exon'][trans_id]
