def rewrite_SR_coords(record, metrics, pval_cutoff, bg_cutoff):
    row = metrics.loc[record.id]
    if row.SR_sum_log_pval >= pval_cutoff and row.SR_sum_bg_frac >= bg_cutoff:
        posA = int(row.SR_posA_pos)
        posB = int(row.SR_posB_pos)
        if record.info['SVTYPE'] == 'INS':
            # posA is always (+) strand and posB (-) strand; need to set order so pos <= end
            if posB < posA:
                record.pos = int(posB)
                record.stop = int(posA)
                record.info['STRANDS'] = '-+'
            else:
                record.pos = int(posA)
                record.stop = int(posB)
                record.info['STRANDS'] = '+-'
        elif record.info['SVTYPE'] == 'INV':
            record.pos, record.stop = sorted([posA, posB])
        else:
            record.pos = posA
            record.stop = posB
        if record.info['SVTYPE'] not in 'INS BND'.split():
            record.info['SVLEN'] = record.stop - record.pos

def make_evidence_int(ev):
    ev = ev.split(',')

    evidence = 0
    if 'RD' in ev:
        evidence += 1
    if 'PE' in ev:
        evidence += 2
    if 'SR' in ev:
        evidence += 4

    return evidence

def add_genotypes(record, genotypes, varGQ):
    """
    Update formats and add genotypes
    """

    # tag varGQ
    record.info['varGQ'] = int(np.round(varGQ['GQ']))

    # clear out unused formats (e.g. algorithm keys)
    for fmt in record.format.keys():
        if fmt not in 'GT GQ PE_GT PE_GQ SR_GT SR_GQ RD_CN RD_GQ EV'.split():
            del record.format[fmt]

    max_GT = genotypes['GT'].max()

    if max_GT > 2:
        record.alts = ('<CNV>',)
        if record.info['SVTYPE'] != 'DUP':
            msg = 'Invalid SVTYPE {0} for multiallelic record {1}'
            msg = msg.format(record.info['SVTYPE'], record.id)
            raise Exception(msg)
        record.info['SVTYPE'] = 'CNV'

    cols = 'name sample GT GQ RD_CN RD_GQ PE_GT PE_GQ SR_GT SR_GQ EV'.split()
    gt_matrix = genotypes.reset_index()[cols].to_numpy()

    # update genotype and other data for each sample
    for j, sample in enumerate(record.samples):
        #  data = genotypes.iloc[j]
        data = gt_matrix[j]

        #  if record.id != data.name[0] or sample != data.name[1]:
        if record.id != data[0] or sample != data[1]:
            msg = 'iloc failed. expected ({0}, {1}) found ({2}, {3}).'
            msg = msg.format(record.id, sample, data[0], data[1])
            raise Exception(msg)

        if max_GT > 2:
            record.samples[sample]['GT'] = (None, None)
        elif data[2] == 0:
            record.samples[sample]['GT'] = (0, 0)
        elif data[2] == 1:
            record.samples[sample]['GT'] = (0, 1)
        elif data[2] == 2:
            record.samples[sample]['GT'] = (1, 1)
        else:
            raise Exception('Invalid GT')

        for i, fmt in enumerate('GQ RD_CN RD_GQ PE_GT PE_GQ SR_GT SR_GQ'.split()):
            if data[i + 3] == '.':
                record.samples[sample][fmt] = None
            else:
                record.samples[sample][fmt] = int(data[i + 3])

        record.samples[sample]['EV'] = make_evidence_int(data[10])

    # Bug in pysam - sometimes gets rid of the first EV field
    data = gt_matrix[0]
    record.samples[0]['EV'] = make_evidence_int(data[10])

def preprocess(df, dtype):
    if dtype == 'RD':
        return process_rdtest(df)
    elif dtype == 'SR':
        return process_srtest(df)
    elif dtype == 'PE':
        return process_petest(df)
    else:
        raise Exception('Invalid dtype {0}'.format(dtype))

def process_metadata(vcf):
    def _get_metadata(record):
        return (record.id,
                record.info['SVTYPE'],
                record.stop - record.pos,
                ','.join(record.info['ALGORITHMS']))

    metadata = [_get_metadata(record) for record in vcf]
    cols = 'name svtype svsize sources'.split()
    metadata = pd.DataFrame(metadata, columns=cols)

    return metadata

def count_vids(list_path):
    counts = defaultdict(lambda: 0)
    with open(list_path, 'r') as f_list:
        for path in f_list:
            with open(path.strip(), 'r') as f:
                for vid in f:
                    counts[vid.strip()] += 1
    return counts

def ensure_file(filename):
    filename = os.path.join(".", filename)
    filename = Path(filename)
    if filename.exists():
        os.remove(filename)
    return filename.name

def count_variants(infile):
    variant_counts = defaultdict(int)
    with open(infile, 'r') as IN:
        for line in IN:
            var_id = line.strip().split('\t')[0]
            variant_counts[var_id] += 1
    return dict(sorted(variant_counts.items(), key=lambda item: item[1], reverse=True))

def assign_shards(variant_counts, max_samples):
    shard_assignments = {}
    shard_number = 0
    sample_counter = 0
    first = True
    for variant in variant_counts.keys():
        if not first and (sample_counter + variant_counts[variant] > max_samples):
            shard_number += 1
            sample_counter = 0
        shard_assignments[variant] = shard_number
        sample_counter += variant_counts[variant]
        first = False
    return shard_number, shard_assignments

def create_shards(infile, shard_assignments, num_shards):
    if not path.isdir("./shards"):
        mkdir("./shards")
    with open(infile, 'r') as IN:
        for line in IN:
            var_id = line.strip().split('\t')[0]
            shard = shard_assignments[var_id]
            shard_file = f"shards/out.{shard}_{num_shards}.txt"
            with open(shard_file, 'a') as OUT:
                OUT.write(line)

def process_features_for_size1(features_for_size1, redundant_multiallelics):
    for intersection in sorted(features_for_size1, key=lambda x: int(x[9]) - int(x[8]), reverse=True):
        b_len = int(intersection.fields[9]) - int(intersection.fields[8])
        overlap = int(intersection.fields[14])
        small_coverage = overlap / b_len
        if small_coverage > 0.50:
            if intersection.fields[3] not in redundant_multiallelics:
                redundant_multiallelics.add(intersection.fields[10])

def main():
    parser = argparse.ArgumentParser(
        description=__doc__,
        formatter_class=argparse.RawDescriptionHelpFormatter)
    parser.add_argument('revise_vcf_lines', type=argparse.FileType('r'))
    parser.add_argument('normal_revise_vcf')
    parser.add_argument('famfile', type=argparse.FileType('r'))
    parser.add_argument('sexchr_revise')
    parser.add_argument('multi_geno_ids_txt')
    parser.add_argument('outlier_samples_list', type=argparse.FileType('r'))
    parser.add_argument('out_prefix')
    parser.add_argument('--threads_per_file', required=False, default=2, type=int)
    args = parser.parse_args()

    # load the revised lines and index by ID
    with pysam.VariantFile(args.revise_vcf_lines, threads=args.threads_per_file) as revise_vcf:
        header2 = revise_vcf.header
        revised_lines_by_id = {record.id: record for record in revise_vcf}
    print("loaded {} revised lines".format(len(revised_lines_by_id)), file=sys.stderr)

    outlier_samples = set([line.rstrip() for line in args.outlier_samples_list if not line.isspace()])
    print("loaded {} outlier samples".format(len(outlier_samples)), file=sys.stderr)

    male_samples = set()
    for line in args.famfile:
        if line.isspace():
            continue
        fields = line.rstrip().split("\t")
        if fields[4] == '1':
            male_samples.add(fields[1])
    print("identified {} male samples".format(len(male_samples)), file=sys.stderr)

    if args.sexchr_revise.endswith(".gz"):
        sexchr_revise = {line.rstrip() for line in gzip.open(args.sexchr_revise, 'rt')}
    else:
        sexchr_revise = {line.rstrip() for line in open(args.sexchr_revise, 'rt')}
    print("{} sites to revise on sex chromosomes".format(len(sexchr_revise)), file=sys.stderr)

    if args.multi_geno_ids_txt.endswith(".gz"):
        multi_geno_ids = {line.rstrip() for line in gzip.open(args.multi_geno_ids_txt, 'rt')}
    else:
        multi_geno_ids = {line.rstrip() for line in open(args.multi_geno_ids_txt, 'rt')}
    print("{} multiallelic sites".format(len(multi_geno_ids)), file=sys.stderr)

    NEW_HEADER_LINES = ['##ALT=<ID=CNV,Description="Copy Number Polymorphism">',
                        '##FORMAT=<ID=CNQ,Number=1,Type=Integer,Description="Read-depth genotype quality">',
                        '##FORMAT=<ID=CN,Number=1,Type=Integer,Description="Predicted copy state">',
                        '##INFO=<ID=PESR_GT_OVERDISPERSION,Number=0,Type=Flag,'
                        'Description="High PESR dispersion count">',
                        '##FILTER=<ID=MULTIALLELIC,Description="Multiallelic site">']

    with pysam.VariantFile(args.normal_revise_vcf) as normal_vcf:

        # # Add metadata lines for annotations
        header1 = normal_vcf.header

        for f in NEW_HEADER_LINES:
            header1.add_line(f)
            header2.add_line(f)

        non_outlier_samples = {s for s in header1.samples if s not in outlier_samples}
        vf_1 = max(len(non_outlier_samples) * 0.01, 2)

        biallelic_gts = {(1, 1), (0, 0), (0, 1), (None, None)}

        print("reformatting records", file=sys.stderr)
        cleangq_filename = args.out_prefix + ".cleanGQ.vcf.gz"
        multiallelic_filename = args.out_prefix + ".multiallelic.vcf.gz"
        no_variant_samples_list_file = args.out_prefix + ".no_called_samples.list"

        with pysam.VariantFile(cleangq_filename, 'w', header=normal_vcf.header, threads=args.threads_per_file) as cleanqg_out, \
                pysam.VariantFile(multiallelic_filename, 'w', header=normal_vcf.header) as multiallelic_out, \
                open(no_variant_samples_list_file, 'w') as no_variant_samples_out:
            for idx, record in enumerate(normal_vcf):
                multi_del = False
                multi_dup = False
                gt4_copystate = False
                gt5kb_dup = False
                gt5kb_del = False
                if (idx - 1) % 1000 == 0:
                    print("processed {} records".format(idx), file=sys.stderr)
                if record.id in revised_lines_by_id:
                    record = revised_lines_by_id[record.id]
                if record.info.get('SVTYPE', None) == 'DEL':
                    if abs(record.stop - record.pos) >= 1000:
                        sample_cn_map = {s: record.samples[s].get('RD_CN') for s in non_outlier_samples}
                        if len([s for s in sample_cn_map if (sample_cn_map[s] is not None and sample_cn_map[s] > 3)]) > vf_1:
                            multi_del = True
                    gts = [record.samples[s].get('GT') for s in non_outlier_samples]
                    if any(gt not in biallelic_gts for gt in gts):
                        gt5kb_del = True
                    if abs(record.stop - record.pos) >= 5000 or '<CN0>' in record.alts:
                        if not multi_del:
                            gt5kb_del = True

                if record.info.get('SVTYPE', None) == 'DUP':
                    if abs(record.stop - record.pos) >= 1000:
                        sample_cn_map = {s: record.samples[s].get('RD_CN') for s in non_outlier_samples}
                        if sum(1 for s in sample_cn_map if sample_cn_map[s] is not None and sample_cn_map[s] > 4) > vf_1:
                            multi_dup = True
                        if sum(1 for x in Counter(sample_cn_map.values()) if x is not None and (x < 1 or x > 4)) > 4:
                            gt4_copystate = True
                        if sum(1 for s in sample_cn_map if sample_cn_map[s] is not None and
                                (sample_cn_map[s] < 1 or sample_cn_map[s] > 4) and gt4_copystate) > vf_1:
                            multi_dup = True
                    gts = [record.samples[s].get('GT') for s in non_outlier_samples]
                    if any(gt not in biallelic_gts for gt in gts):
                        gt5kb_dup = True
                    if abs(record.stop - record.pos) >= 5000 or '<CN0>' in record.alts:
                        if not multi_dup:
                            gt5kb_dup = True

                if gt5kb_del:
                    for sample_obj in record.samples.itervalues():
                        # Leave no-calls
                        if sample_obj['GT'] == (None, None):
                            continue
                        if not sample_obj.get('GQ') is None and \
                                (sample_obj.get('RD_CN') is not None and sample_obj.get('RD_CN') >= 2):
                            sample_obj['GT'] = (0, 0)
                        elif not sample_obj.get('GQ') is None and \
                                (sample_obj.get('RD_CN') is not None and sample_obj.get('RD_CN') == 1):
                            sample_obj['GT'] = (0, 1)
                        elif not sample_obj.get('GQ') is None:
                            sample_obj['GT'] = (1, 1)  # RD_CN 0 DEL

                if gt5kb_dup:
                    # Convert to bi-allelic
                    if '<CN0>' in record.alts:
                        record.alts = ('<DUP>',)
                    for sample_obj in record.samples.itervalues():
                        # Leave no-calls - also causes bug that skips multiallelic genotypes for a biallelic variant
                        if sample_obj['GT'] == (None, None):
                            continue
                        if not sample_obj.get('GQ') is None and \
                                (sample_obj.get('RD_CN') is not None and sample_obj.get('RD_CN') <= 2):
                            sample_obj['GT'] = (0, 0)
                        elif not sample_obj.get('GQ') is None and \
                                (sample_obj.get('RD_CN') is not None and sample_obj.get('RD_CN') == 3):
                            sample_obj['GT'] = (0, 1)
                        elif not sample_obj.get('GQ') is None:
                            sample_obj['GT'] = (1, 1)  # RD_CN > 3 DUP

                if record.id in multi_geno_ids:
                    record.info['PESR_GT_OVERDISPERSION'] = True

                if multi_del or multi_dup:
                    record.filter.add('MULTIALLELIC')
                    for sample in record.samples:
                        record.samples[sample]['GT'] = None
                        record.samples[sample]['GQ'] = None
                        record.samples[sample]['CN'] = record.samples[sample].get('RD_CN')
                        record.samples[sample]['CNQ'] = record.samples[sample].get('RD_GQ')

                if len(record.filter) > 1 and 'PASS' in record.filter:
                    del record.filter['PASS']

                if 'MULTIALLELIC' in record.filter and ('<DUP>' in record.alts or '<DEL>' in record.alts or '<CN0>' in record.alts):
                    record.alts = ('<CNV>',)
                    record.info['SVTYPE'] = 'CNV'

                if record.id in sexchr_revise:
                    for sample in record.samples:
                        if sample in male_samples:
                            cn = record.samples[sample].get('RD_CN')
                            if cn is not None and int(cn) > 0:
                                cn = int(cn)
                                record.samples[sample]['RD_CN'] = cn - 1
                                if 'CN' in record.samples[sample]:
                                    record.samples[sample]['CN'] = cn - 1  # the old script didn't do this but I think it should

                cleanqg_out.write(record)

                if 'MULTIALLELIC' in record.filter:
                    multiallelic_out.write(record)

                if len(svu.get_called_samples(record)) == 0:
                    print(record.id, file=no_variant_samples_out)

    print("done", file=sys.stderr)

def convert_poisson_p(log_pval):
    """
    Convert poisson p-value to count, assuming 0 background

    Can't use ss.poisson.ppf because k/mu are flipped in pe/sr test calculation
    """
    count = 0
    while True:
        pval_cmp = -np.log10(ss.poisson.cdf(0, count))

        if pval_cmp > log_pval:
            return max(1, count - 1)

        count += 1

def vcf_readin(vcf_name):
    out = []
    fin = os.popen(r'''zcat %s''' % (vcf_name))
    for line in fin:
        pin = line.strip().split()
        if not pin[0][0] == '#':
            out.append(pin)
    fin.close()
    return out

def vcf_name_readin(vcf_name):
    out = []
    fin = os.popen(r'''zcat %s''' % (vcf_name))
    for line in fin:
        pin = line.strip().split()
        if pin[0][0] == '#' and not pin[0][:2] == '##':
            out = pin[8:]
            break
    fin.close()
    return out

def info_cha_extract(pin, character='END'):
    out = ''
    for i in pin[7].split(';'):
        if i.split('=')[0] == character:
            out = i.split('=')[1]
    return out

def unify_list(list):
    out = []
    for i in list:
        if i not in out:
            out.append(i)
    return out

def extract_non_ref_samples(pin, sample_name):
    GT_POS = pin[8].split(':').index('GT')
    sample_GT = [i.split(':')[GT_POS] for i in pin[9:]]
    sample_out = [i for i in sample_name[1:]
                  if not sample_GT[sample_name.index(i) - 1] == '0/0']
    return ','.join(sample_out)

def get_denovo_candidates(record, fam, max_parents=20):
    """
    Obtain list of samples which are putatively called de novo
    """
    called = svu.get_called_samples(record)

    parents = [s for s in called if fam.samples[s].is_parent]

    if len(parents) > max_parents:
        return []

    denovo = []

    for ID in called:
        sample = fam.samples[ID]
        if sample.has_parents:
            if sample.mother not in called and sample.father not in called:
                denovo.append(sample.ID)

    return denovo

def get_cutoff_class(sample):
    """
    Identify which set of cutoffs to use when classifying a given variant call

    Arguments
    ---------
    sample : namedtuple('Metrics')
        Row from variant metrics table

    Returns
    -------
    (source, svtype) : (str, str)
        Key to cutoffs table
    """

    if sample.sources == 'depth' and sample.svtype == 'DEL':
        return ('depth', 'DEL')
    elif sample.sources == 'depth' and sample.svtype == 'DUP':
        return ('depth', 'DUP')
    elif (sample.svtype in 'DEL DUP'.split() and sample.svsize >= 1000):
        return ('pesr', 'CNV')
    else:
        return ('pesr', 'SV')

def metric_parser(metricfile, fam):
    """Convert table of variant metrics to iterator over Metrics tuples"""
    header = next(metricfile).strip().split()
    Metrics = namedtuple('Metrics', ['family'] + header)

    def _cast(data):
        for i, var in enumerate(header):
            if var == 'svsize':
                data[i] = np.int(data[i])
            elif var.startswith('PE') or var.startswith('SR'):
                if data[i] == 'NA':
                    data[i] = np.nan
                else:
                    data[i] = np.float(data[i])
            elif var.startswith('RD') and var != 'RD_Model':
                if data[i] == 'NA':
                    data[i] = np.nan
                else:
                    data[i] = np.float(data[i])
        return data

    for line in metricfile:
        data = line.strip().split()
        family = fam.samples[data[1]].family
        yield Metrics(family, *_cast(data))

def set_null(record, sample):
    dat = record.samples[sample].items()

    # Set genotype to no-call
    record.samples[sample]['GT'] = (0, 0)

    for fmt, value in dat:
        if fmt == 'GT':
            continue

        # Get type and count of FORMAT
        n = record.format[fmt].number
        dtype = record.format[fmt].type

        # Set null value based on FORMAT type
        if dtype in 'Integer Float'.split():
            null_val = 0
        elif dtype in 'String Character'.split():
            null_val = ''
        else:
            raise ValueError('Invalid VCF FORMAT type: {0}'.format(dtype))

        # Set the appropriate count of values
        if n == 1:
            record.samples[sample][fmt] = null_val
        elif n == '.':
            record.samples[sample][fmt] = (null_val, )
        else:
            record.samples[sample][fmt] = tuple(null_val for i in range(n))

def parse_filtered(filterfile, fam):
    """Get dictionaries of added/removed samples from de novo filter"""

    add = defaultdict(list)
    remove = defaultdict(list)

    for line in filterfile:
        name, family, called, support = line.strip().split()
        called = called.split(',')

        samples = [s.ID for s in fam.families[family]]

        for sample in samples:
            if sample in called:
                add[name].append(sample)
            else:
                remove[name].append(sample)

    return add, remove

def final_filter(vcf, bed, chrom=None):
    bed = bed.set_index('name')
    new_variant = ((bed.operation == 'add-mosaic-variant') |
                   (bed.operation == 'add-variant'))

    filter_names = bed.loc[~new_variant].index.values

    for record in vcf:
        if record.id in filter_names:
            op = bed.loc[record.id, 'operation']
            samples = bed.loc[record.id, 'samples'].split(',')

            if op == 'add-samples':
                for sample in samples:
                    record.samples[sample]['GT'] = (0, 1)
            elif op == 'flag-mosaic':
                for sample in samples:
                    record.samples[sample]['GT'] = (0, 1)
                record.info['MOSAIC'] = samples
            elif op == 'remove-variant':
                continue

        yield record

    for new_name in bed.loc[new_variant].index.values:
        # Stick to variants on same chromosome
        data = bed.loc[new_name]
        if chrom is not None and data.chrom != chrom:
            continue

        new_record = record.copy()
        for sample in new_record.samples.keys():
            svu.set_null(new_record, sample)

        samples = data['samples'].split(',')
        for sample in samples:
            new_record.samples[sample]['GT'] = (0, 1)

        new_record.id = new_name
        new_record.chrom = data.chrom
        new_record.pos = data.start
        new_record.alts = ('<{0}>'.format(data.svtype), )
        new_record.info['CHR2'] = data.chrom
        new_record.stop = data.end

        new_record.info['SVTYPE'] = data.svtype
        if data.svtype == 'DEL':
            new_record.info['STRANDS'] = '+-'
        else:
            new_record.info['STRANDS'] = '-+'
        new_record.info['SVLEN'] = int(data.end - data.start)
        new_record.info['SOURCES'] = data.sources.split(',')

        new_record.info['MEMBERS'] = (new_name, )

        op = bed.loc[new_name, 'operation']
        if op == 'add-mosaic-variant':
            if len(samples) == 1:
                new_record.info['MOSAIC'] = samples
            else:
                parents = [s for s in samples if s.endswith(
                    'fa') or s.endswith('mo')]
                new_record.info['MOSAIC'] = parents

        yield new_record

def get_denovo_candidates(record, fam, max_parents=10):
    """
    Obtain list of samples which are putatively called de novo
    """
    called = svu.get_called_samples(record)
    parents = [s for s in called if fam.samples[s].is_parent]

    if len(parents) > max_parents:
        return []

    denovo = []
    for ID in called:
        sample = fam.samples[ID]
        if sample.has_parents:
            if sample.mother not in called and sample.father not in called:
                denovo.append(sample.ID)

    return denovo

def filter_denovo_records(vcf, fam, max_parents=10):
    for record in vcf:
        # Skip records without any Mendelian violations
        candidates = get_denovo_candidates(record, fam, max_parents)
        if len(candidates) == 0:
            continue

        # Restrict to rare (parental VF<0.1%) variants
        called = svu.get_called_samples(record)
        parents = [s for s in called if fam.samples[s].is_parent]
        if len(parents) > max_parents:
            continue

        # Skip non-stranded (wham)
        if 'STRANDS' in record.info.keys():
            if record.info['STRANDS'] not in '+- -+ ++ --'.split():
                continue

        yield record

def main():
    parser = argparse.ArgumentParser(
        description=__doc__,
        formatter_class=argparse.RawDescriptionHelpFormatter)
    parser.add_argument('vcf')
    parser.add_argument('famfile', type=argparse.FileType('r'))
    parser.add_argument('fout')
    parser.add_argument('--max-parents', type=int, default=10)
    args = parser.parse_args()

    if args.vcf in '- stdin'.split():
        vcf = pysam.VariantFile(sys.stdin)
    else:
        vcf = pysam.VariantFile(args.vcf)

    if args.fout in '- stdout'.split():
        fout = pysam.VariantFile(sys.stdout, 'w', header=vcf.header)
    else:
        fout = pysam.VariantFile(args.fout, 'w', header=vcf.header)

    fam = parse_famfile(args.famfile)

    for record in filter_denovo_records(vcf, fam, args.max_parents):
        fout.write(record)

def update_header(header: pysam.VariantHeader) -> None:
    header.add_line('##INFO=<ID=UNRESOLVED,Number=0,Type=Flag,Description="Variant is unresolved.">')
    header.add_line('##INFO=<ID=UNRESOLVED_TYPE,Number=1,Type=String,Description=\"Class of unresolved variant.\">')

def get_members(record: pysam.VariantRecord):
    return list(record.info[MEMBERS_KEY]) if isinstance(record.info[MEMBERS_KEY], tuple) \
        else [record.info[MEMBERS_KEY]] if record.info[MEMBERS_KEY] is not None \
        else list()

def get_vids_and_members_sets(vcf: pysam.VariantFile,
                              predicate: Callable) -> Dict:
    unresolved_vids_set = set()
    unresolved_members_set = set()
    for r in vcf:
        if predicate(r):
            unresolved_vids_set.add(r.id)
            unresolved_members_set.update(get_members(r))
    vcf.reset()
    return unresolved_vids_set, unresolved_members_set

def write_vcf(header: pysam.VariantHeader,
              all_vcf: pysam.VariantFile,
              inv_vcf: pysam.VariantFile,
              inv_resolved_vids_set: Set,
              inv_resolved_members_set: Set,
              all_unresolved_vids_set: Set,
              all_unresolved_members_set: Set) -> None:
    sys.stdout.write(str(header))
    for r in all_vcf:
        if r.id not in all_unresolved_vids_set or r.id not in inv_resolved_members_set:
            # Resolved in ALL vcf, or unresolved in both VCFs
            sys.stdout.write(str(r))
    for r in inv_vcf:
        if r.id in inv_resolved_vids_set:
            # Resolved variant in the INV vcf
            members = get_members(r)
            if all((m in all_unresolved_members_set) for m in members):
                # Resolved in the INV vcf and every member unresolved in the ALL vcf
                sys.stdout.write(str(r))

def label_mosaics(vcf, mosaics):
    for record in vcf:
        if record.id in mosaics.keys():
            record.info['MOSAIC'] = mosaics[record.id]
        yield record

