def get_inh(called, fam):
    """
    Get list of children per inheritance status

    Returns
    -------
    inh_status : dict of {str: list of str}
        Maps inheritance status to list of corresponding samples
    """

    inh_status = dict(denovo=[], maternal=[], paternal=[], biparental=[])

    for family, samples in itertools.groupby(called, key=lambda s: fam.samples[s].family):
        samples = list(samples)

        for sample in samples:
            if fam.samples[sample].has_parents:
                if fam.samples[sample].mother in samples and fam.samples[sample].father in samples:
                    status = 'biparental'
                elif fam.samples[sample].mother in samples:
                    status = 'maternal'
                elif fam.samples[sample].father in samples:
                    status = 'paternal'
                else:
                    status = 'denovo'

                inh_status[status].append(sample)

    return inh_status

def sfari_filters(vcf):
    for record in vcf:
        called = set(svu.get_called_samples(record))

        # Remove allosomal calls in aneuploidy samples
        if record.chrom in 'X Y'.split():
            if called.issubset(ANEUPLOIDIES):
                continue
            else:
                for sample in called.intersection(ANEUPLOIDIES):
                    svu.set_null(record, sample)

        # Remove depth-only events in Robertsonian translocation cases
        if record.info['SOURCES'] == ('depth',):
            if called.issubset(DEPTH_EXCLUDED):
                continue

        # Check variant wasn't only in aneuploidies and Robertsonians
        #  called = set(svu.get_called_samples(record))
        #  if len(called) == 0:
            #  continue

        # Remove variants specific to dosage outliers
        #  if called.issubset(OUTLIERS):
            #  continue

        yield record

def get_file_name(prefix, suffix, digits):
    if len(str(suffix)) > digits:
        raise ValueError('No more files can be generated with the current naming scheme. '
                         'Increase the digits parameter or the n parameter to proceed.')
    return f"{prefix}.{str(suffix).zfill(digits)}.bed"

def create_pop_dict(popfile):
    """
    Makes dictionary of sample-population pairs
    """

    pop_dict = {}

    for sample in popfile:
        pop_dict[sample.split('\t')[0]] = sample.split('\t')[1]

    return pop_dict

def gather_allele_freqs(record, samples, males_set, females_set, parbt, pop_dict, pops,
                        sex_chroms, no_combos=False):
    """
    Wrapper to compute allele frequencies for all sex & population pairings
    """

    # Add PAR annotation to record (if optioned)
    if record.chrom in sex_chroms and len(parbt) > 0:
        if in_par(record, parbt):
            rec_in_par = True
            record.info['PAR'] = True
        else:
            rec_in_par = False
    else:
        rec_in_par = False

    # Get allele frequencies for all populations
    calc_allele_freq(record, samples)
    if len(males_set) > 0:
        if record.chrom in sex_chroms and not rec_in_par:
            calc_allele_freq(record, males_set, prefix='MALE', hemi=True)
        else:
            calc_allele_freq(record, males_set, prefix='MALE')
    if len(females_set) > 0:
        calc_allele_freq(record, females_set, prefix='FEMALE')

    # Adjust global allele frequencies on sex chromosomes, if famfile provided
    if record.chrom in sex_chroms and not rec_in_par \
            and svu.is_biallelic(record) and len(males_set) + len(females_set) > 0:
        update_sex_freqs(record)

    # Get allele frequencies per population
    if len(pops) > 0:
        for pop in pops:
            pop_samps = [
                s for s in samples if pop_dict.get(s, None) == pop]
            calc_allele_freq(record, pop_samps, prefix=pop)
            if len(males_set) > 0 and not no_combos:
                if record.chrom in sex_chroms and not rec_in_par:
                    calc_allele_freq(record, list([s for s in pop_samps if s in males_set]),
                                     prefix=pop + '_MALE', hemi=True)
                else:
                    calc_allele_freq(record, list([s for s in pop_samps if s in males_set]),
                                     prefix=pop + '_MALE')
            if len(females_set) > 0 and not no_combos:
                calc_allele_freq(record, list([s for s in pop_samps if s in females_set]),
                                 prefix=pop + '_FEMALE')

            # Adjust per-pop allele frequencies on sex chromosomes, if famfile provided
            if record.chrom in sex_chroms and not rec_in_par \
                    and svu.is_biallelic(record) and len(males_set) + len(females_set) > 0:
                update_sex_freqs(record, pop=pop)

        # Get POPMAX AF biallelic sites only
        if svu.is_biallelic(record):
            AFs = [record.info['AF_{0}'.format(pop)][0] for pop in pops]
            popmax = max(AFs)
            record.info['POPMAX_AF'] = popmax

    return record

def GTFParser(gtf):
    """
    Simple GTF parser - for each line, convert to GTFEntry
    """
    for line in gtf:
        yield GTFEntry(*line.strip().split('\t'), line)

def filter_UTRs(gtf, fout):
    """
    For every gene in a GTF, subtract UTR sequence from exonic features. Leave
    other features untouched.
    """
    curr_gene = None
    exons = []
    UTRs = []

    for entry in gtf:
        if curr_gene is None:
            curr_gene = entry.attribute['gene_id']

        if curr_gene != entry.attribute['gene_id']:
            for UTR in UTRs:
                fout.write(UTR.line)
            for exon in update_exons(exons, UTRs):
                fout.write(exon.line)

            curr_gene = entry.attribute['gene_id']
            exons = []
            UTRs = []

        if entry.feature == 'exon':
            exons.append(entry)
        elif entry.feature == 'UTR':
            UTRs.append(entry)
        else:
            fout.write(entry.line)

    for UTR in UTRs:
        fout.write(UTR.line)
    for exon in update_exons(exons, UTRs):
        fout.write(exon.line)

