def merge_annotations(vcf, protein_coding_vcf, lincRNA_vcf, promoter_vcf, noncoding_vcf):

    record_iter = zip(vcf, protein_coding_vcf, lincRNA_vcf,
                      promoter_vcf, noncoding_vcf)

    gene_classes = ['PROTEIN_CODING', 'LINCRNA']

    coding_classes = 'LOF DUP_LOF COPY_GAIN MSV_EXON_OVR DUP_PARTIAL INTRONIC INV_SPAN UTR'.split()

    for records in record_iter:
        # First check that all records have same ID
        ids = [r.id for r in records]
        if len(set(ids)) != 1:
            msg = 'Mismatched records: {0}'.format(','.join(set(ids)))
            raise Exception(msg)

        # Use record from unannotated VCF with updated header as base
        base = records[0]

        # Copy coding annotations over from each gene class
        for gene_class, record in zip(gene_classes, records[1:6]):
            for coding_class in coding_classes:
                if coding_class in record.info.keys():
                    info = '{0}__{1}'.format(gene_class, coding_class)
                    base.info[info] = record.info[coding_class]

            # Additionally tag nearest TSS and intergenic for protein coding
            if gene_class == 'PROTEIN_CODING':
                if 'INTERGENIC' in record.info.keys():
                    base.info['PROTEIN_CODING__NEAREST_TSS'] = record.info['NEAREST_TSS']
                    base.info['PROTEIN_CODING__INTERGENIC'] = True

        # Annotate promoters of any genes if there wasn't a coding hit
        promoter_record = records[3]
        promoters = promoter_record.info.get(
            'NONCODING_SPAN', ()) + promoter_record.info.get('NONCODING_BREAKPOINT', ())
        kept_promoters = []
        for gene in promoters:
            coding_hit = False
            for coding_class in coding_classes:
                info = 'PROTEIN_CODING__{0}'.format(coding_class)
                if info in base.info.keys() and gene in base.info[info]:
                    coding_hit = True
            if not coding_hit:
                kept_promoters.append(gene)

        if len(kept_promoters) > 0:
            base.info['PROTEIN_CODING__PROMOTER'] = kept_promoters

        noncoding_record = records[4]
        if 'NONCODING_SPAN' in noncoding_record.info.keys():
            base.info['NONCODING_SPAN'] = noncoding_record.info['NONCODING_SPAN']
        if 'NONCODING_BREAKPOINT' in noncoding_record.info.keys():
            base.info['NONCODING_BREAKPOINT'] = noncoding_record.info['NONCODING_BREAKPOINT']

        yield base

def take_highest_effect(s):
    if 'LOF' in s.values:
        return 'LOF'
    if 'COPY_GAIN' in s.values:
        return 'COPY_GAIN'
    if 'DUP_PARTIAL' in s.values:
        return 'DUP_PARTIAL'
    if 'INV_SPAN' in s.values:
        return 'INV_SPAN'
    if 'INTRONIC' in s.values:
        return 'INTRONIC'
    if 'PROMOTER' in s.values:
        return 'PROMOTER'
    return 'OTHER'

def prune_allrefs(vcf, fout):
    for record in vcf.fetch():
        if is_biallelic(record):
            if record.info['AC'][0] > 0:
                fout.write(record)
        else:
            if record.info['CN_NONREF_FREQ'] > 0:
                fout.write(record)

def chr_extract(pin, chr):
    out = ''
    for i in pin[7].split(';'):
        if i.split('=')[0] == chr:
            out = i.split('=')[1]
    return out

def vcf_stat_readin(filename):
    fin = gzip.open(filename, 'rb')
    out = {}
    sv_types = []
    for line in fin:
        pin = line.strip().decode().split()
        if not pin[0][0] == '#':
            if not pin[0] in out.keys():
                out[pin[0]] = {}
            svtype = chr_extract(pin, 'SVTYPE')
            if svtype not in out[pin[0]].keys():
                out[pin[0]][svtype] = 0
                if svtype not in sv_types:
                    sv_types.append(svtype)
            out[pin[0]][svtype] += 1
    fin.close()
    return [out, sv_types]

def write_output(output_name, stat_hash, sv_types, sample_name):
    if not os.path.isfile(output_name):
        fo = open(output_name, 'w')
        print('\t'.join(['#CHROM', 'SVTYPE', 'NUM', 'SAMPLE']), file=fo)
        fo.close()
    fo = open(output_name, 'a')
    for i in sv_types:
        for j in stat_hash.keys():
            if i in stat_hash[j].keys():
                print(
                    '\t'.join([str(k) for k in [j, i, stat_hash[j][i], sample_name]]), file=fo)
            else:
                print('\t'.join([str(k)
                                 for k in [j, i, 0, sample_name]]), file=fo)
    fo.close()

def _is_no_call(gt):
    s = _gt_no_call_map.get(gt, None)
    if s is None:
        s = all([a is None for a in gt])
        _gt_no_call_map[gt] = s
    return s

def _is_hom_ref(gt):
    s = _gt_ref_map.get(gt, None)
    if s is None:
        s = all([a is not None and a == 0 for a in gt])
        _gt_ref_map[gt] = s
    return s

def _is_hom_var(gt):
    s = _gt_hom_var_map.get(gt, None)
    if s is None:
        s = all([a is not None and a > 0 for a in gt])
        _gt_hom_var_map[gt] = s
    return s

def _gt_to_filter_status(gt, fails_filter):
    if not fails_filter:
        return 'pass'
    s = _gt_to_filter_status_map.get(gt, None)
    if s is None:
        if _is_hom_ref(gt):
            s = 'homRefFail'
        elif _is_hom_var(gt):
            s = 'homVarFail'
        elif _is_no_call(gt):
            s = 'noCallFail'
        else:
            s = 'hetFail'
        _gt_to_filter_status_map[gt] = s
    return s

def _filter_gt(gt, allele):
    s = _gt_to_filter_gt_map.get(gt, None)
    if s is None:
        s = tuple(allele for _ in gt)
        _gt_to_filter_gt_map[gt] = s
    return s

def recalculate_gq(sl, scale_factor, is_hom_ref, upper, lower, shift):
    sign = -1 if is_hom_ref else 1
    sl = (sign * min(max(sl, lower), upper)) + shift
    return int(math.floor(-10 * math.log10(1 / (math.pow(scale_factor, sl) + 1))))

def _fails_filter(sl, gt_is_ref, cutoff):
    if cutoff is None:
        return False
    if gt_is_ref:
        sl = -sl
    return sl < cutoff

def recal_qual_score(record):
    """
    Recalibrate quality score for a single variant
    """
    quals = []
    for s in [s for s in record.samples]:
        gt = record.samples[s]['GT']
        if _is_hom_ref(gt) or _is_no_call(gt):
            continue
        elif _is_hom_var(gt):
            quals.append(99)
        else:
            quals.append(record.samples[s]['GQ'])

    if len(quals) > 0:
        return int(median(quals))

def get_threshold(record, sl_thresholds, med_size, large_size):
    svtype = record.info['SVTYPE']
    if svtype in _cnv_types:
        svlen = record.info['SVLEN']
        if svlen < med_size:
            size_index = 0
        elif svlen < large_size:
            size_index = 1
        else:
            size_index = 2
        return sl_thresholds[svtype][size_index]
    else:
        return sl_thresholds[svtype][0]

def multisort(xs, specs):
    for key, reverse in reversed(specs):
        xs.sort(key=attrgetter(key), reverse=reverse)
    return xs

