def drop_nonref_gts(vcf, fout):
    NULL_GT = [(0, 0), (None, None), (0, ), (None, ), (None, 2)]
    samples = [s for s in vcf.header.samples]

    for record in vcf.fetch():
        for s in samples:
            if is_biallelic(record):
                if record.samples[s]['GT'] not in NULL_GT:
                    fout.write(record)
                    break
            else:
                if record.samples[s]['CN'] != 2:
                    fout.write(record)
                    break

def _cache_gt(gt):
    if gt is None:
        return 0, 0
    s = _gt_map.get(gt, None)
    if s is None:
        x = sum([1 for a in gt if a is not None and a > 0])
        if x == 0:
            s = (0, 0)
        elif x == 1:
            s = (0, 1)
        else:
            s = (1, 1)
        _gt_map[gt] = s
    return s

