def handle_header(line, columns, fields, default_num_columns, sample_to_extract):
    if line.startswith("#"):
        # get column names beyond first default ones from header if available
        for i, name in enumerate(fields[default_num_columns:]):
            columns[name] = default_num_columns + i
        if "SVLEN" not in columns:
            raise ValueError("SVLEN column not found in header")
    else:
        raise ValueError("Header not found. Header must exist and start with #")
        if len(fields) >= default_num_columns:
            columns['samples'] = default_num_columns  # if no header but extra fields, assume samples is next column
    if sample_to_extract is not None and "samples" not in columns:
        raise ValueError("Sample to extract provided but no samples column found")

def process(vcf: pysam.VariantFile) -> None:
    add_header_lines(vcf.header)
    sys.stdout.write(str(vcf.header))
    allowed_svtypes = set(['DEL', 'DUP', 'INS', 'INV'])
    for record in vcf:
        svtype = record.info['SVTYPE']
        if svtype not in allowed_svtypes:
            continue
        svlen = record.info.get('SVLEN', record.stop - record.pos)
        if svlen > 5000:
            continue
        record.info['ORIGINAL_SVTYPE'] = svtype
        record.info['ORIGINAL_ALT'] = record.alts[0]
        if svtype != 'DUP':
            sys.stdout.write(str(record))
        else:
            record.info['SVLEN'] = record.stop - record.pos
            record.info['SVTYPE'] = 'INS'
            record.stop = record.pos + 1
            sys.stdout.write(str(record).replace("\t<DUP>", "\t<INS>"))

def parse_truth_support(labels: Dict[Text, List[Text]],
                        vcf: pysam.VariantFile,
                        main_vids: Set[Text],
                        truth_alg: Text) -> Dict:
    for record in vcf:
        if record.id in main_vids and record.info.get("STATUS", "") == "TP":
            labels[record.id].append(truth_alg)

def refine_labels(vids: Set[Text],
                  sample_id: Text,
                  large_cnv_vids: Set[Text],
                  bypass_vids: Set[Text],
                  vapor_true: Set[Text],
                  vapor_false: Set[Text],
                  strict_labels: Dict[Text, List[Text]],
                  loose_labels: Dict[Text, List[Text]],
                  strict_support_threshold: int,
                  loose_support_threshold: int) -> Dict:
    labels = {GOOD_VARIANTS_KEY: list(), BAD_VARIANTS_KEY: list()}
    for vid in vids:
        in_vapor_true = vid in vapor_true
        in_vapor_false = vid in vapor_false
        if vid in large_cnv_vids:
            # Calls where we are going to use array-based label from the vapor file
            if in_vapor_true:
                labels[GOOD_VARIANTS_KEY].append(vid)
            elif in_vapor_false:
                labels[BAD_VARIANTS_KEY].append(vid)
        elif (vid in bypass_vids) or not (in_vapor_true or in_vapor_false):
            # Vapor no-calls and unlabelable variants (large INV/INS)
            continue
        else:
            vapor_score = 1 if in_vapor_true else 0
            support_strict = len(strict_labels[vid]) + vapor_score
            support_loose = len(loose_labels[vid]) + vapor_score
            if support_strict >= strict_support_threshold:
                labels[GOOD_VARIANTS_KEY].append(vid)
            elif support_loose <= loose_support_threshold:
                labels[BAD_VARIANTS_KEY].append(vid)
    return {sample_id: labels}

