def validate_id(identifier, id_set, id_type, source_file):
    # check for empty IDs
    if identifier is None or identifier == "":
        raise ValueError(f"Empty {id_type} ID in {source_file}")

    # check all characters are alphanumeric or underscore
    if not re.match(r'^\w+$', identifier):
        raise ValueError(f"Invalid {id_type} ID in {source_file}: '{identifier}'. " +
                         "IDs should only contain alphanumeric and underscore characters.")

    # check for all-numeric IDs
    # except: allow maternal and paternal ID to be 0
    # except: allow all-numeric family IDs (as in current ref panel PED file)
    if id_type != ID_TYPE_FAMILY and not (id_type == ID_TYPE_PARENT and identifier == "0") and identifier.isdigit():
        raise ValueError(f"Invalid {id_type} ID in {source_file}: {identifier}. " +
                         "IDs should not contain only numeric characters.")

    # check for illegal substrings
    for sub in ILLEGAL_ID_SUBSTRINGS:
        if sub in identifier:
            raise ValueError(f"Invalid {id_type} ID in {source_file}: {identifier}. " +
                             f"IDs cannot contain the following substrings: {', '.join(ILLEGAL_ID_SUBSTRINGS)}.")

    # check for duplicate IDs
    if id_set is not None:
        if identifier in id_set:
            raise ValueError(f"Duplicate {id_type} ID in {source_file}: {identifier}")

def revise_filter_Large_SR_only(vcf, fout, size_cutoff=500, sample_proportion_cutoff=0.1):
    records = []
    for record in vcf:
        if 'PASS' in record.filter.keys():
            if record.info['SVLEN'] > size_cutoff:
                SR_only_list = []
                gt_list = []
                for sample in record.samples.values():
                    if sample['RD_CN'] == 2 and sample['PE_GT'] == 0 and sample['PE_GQ'] == 99 and sample['SR_GT'] != 0:
                        SR_only_list.append(1)
                        gt_list.append(sample['GT'])
                    else:
                        SR_only_list.append(0)
                        gt_list.append(sample['GT'])
                if sum(SR_only_list) / len(SR_only_list) > sample_proportion_cutoff:
                    record.filter.clear()
                    record.filter.add('LARGE_SR_ONLY')
                    # print([str(j) for j in [record.chrom, record.pos,record.id, sum(SR_only_list)/len(SR_only_list)]])
        records.append(record)
    for record in records:
        fout.write(record)

def _lookup_SVLEN_key(SVLEN, SVLEN_table):
    out = None
    for key in SVLEN_table:
        if SVLEN in key:
            out = SVLEN_table[key]
            break
    return out

def _lookup_AF_key(AF, AF_table, scalar=10000):
    val = int(np.round(scalar * float(AF)))
    if val >= scalar:
        val = scalar - 1
    out = None
    for key in AF_table:
        if val in key:
            out = AF_table[key]
            break
    return out

def _lookup_SVTYPE_key(SVTYPE, SVTYPE_table):
    out = SVTYPE_table.get(SVTYPE, None)
    return out

def _lookup_FILTER_key(FILTERs, FILTER_table):
    maxkey = str(np.max(list(map(int, set(FILTER_table.values())))))
    out = [FILTER_table.get(f, maxkey) for f in FILTERs.split(',')]
    if len(out) > 0:
        out = str(np.min(list(map(int, out))))
    return out

def _lookup_EV_key(EV, EV_table):
    # Reorder EV string to match expected
    e = []
    for c in ['RD', 'PE', 'SR']:
        if c in EV:
            e.append(c)
    EV = ','.join(e)
    maxkey = str(np.max(list(map(int, set(EV_table.values())))))
    out = EV_table.get(EV, maxkey)
    return out

def _get_minGQ(record, minGQ_dict, SVLEN_table, AF_table, SVTYPE_table,
               FILTER_table, EV_table, globalMin=0):
    # Get minGQ_dict indexes
    if 'SVLEN' in record.info.keys():
        SVLEN_idx = _lookup_SVLEN_key(record.info['SVLEN'], SVLEN_table)
    if 'AF' in record.info.keys():
        AF_idx = _lookup_AF_key(record.info['AF'][0], AF_table)
    if 'SVTYPE' in record.info.keys():
        SVTYPE_idx = _lookup_SVTYPE_key(record.info['SVTYPE'], SVTYPE_table)
    FILTER_query = ','.join(f for f in record.filter)
    FILTER_idx = _lookup_FILTER_key(FILTER_query, FILTER_table)

    # Get minGQ dict down to EV
    if SVLEN_idx is not None \
            and AF_idx is not None \
            and SVTYPE_idx is not None \
            and FILTER_idx is not None:
        minGQ = minGQ_dict[SVLEN_idx][AF_idx][SVTYPE_idx][FILTER_idx]
    # Otherwise, set all EV categories to globalMin
    else:
        minGQ = defaultdict(dict)
        for key in list(set(EV_table.values())):
            minGQ[key] = int(globalMin)

    return (minGQ)

def get_pcrdict(vcf, PCRPLUS_samples_file):
    # Get list of all samples in VCF
    samples = [s for s in vcf.header.samples]

    # Read list of all PCRPLUS samples
    PCRPLUS_samples = [line.rstrip('\n') for line in PCRPLUS_samples_file]

    # Make dictionary of samples with PCR statuses
    pcrdict = {}
    for s in samples:
        if s not in pcrdict.keys():
            if s in PCRPLUS_samples:
                pcrdict[s] = 'PCRPLUS'
            else:
                pcrdict[s] = 'PCRMINUS'

    return pcrdict

def get_AC(record, ID):
    GTs_to_skip = './. None/None 0/None None/0'.split()
    GT = '/'.join([str(i) for i in record.samples[ID]['GT']])
    if GT not in GTs_to_skip:
        AC = sum([int(a) for a in GT.split('/')])
        return AC

def classify_trio_AC(ACs):
    n_missing = len([c for c in ACs if c is None])
    n_homref = len([c for c in ACs if c == 0])
    pro_homref = ACs[0] == 0
    n_homref_parents = len([c for c in ACs[1:3] if c == 0])
    # n_het = len([c for c in ACs if c == 1])
    # pro_het = ACs[0] == 1
    # n_het_parents = len([c for c in ACs[1:3] if c == 1])
    # n_homalt = len([c for c in ACs if c == 2])
    pro_homalt = ACs[0] == 2
    n_homalt_parents = len([c for c in ACs[1:3] if c == 2])

    if n_missing > 0:
        return 'INCOMPLETE'
    elif n_homref == 3:
        return 'NO_VARIANT'
    elif pro_homalt and n_homref_parents == 2:
        return 'APPARENT_DE_NOVO'
    elif pro_homref and n_homalt_parents > 0:
        return 'UNTRANSMITTED_HOMOZYGOTE'
    elif pro_homalt and n_homref_parents > 0:
        return 'SPONTANEOUS_HOMOZYGOTE'
    else:
        return 'MENDELIAN'

def count_MVs(record, trios, pcrdict):
    mendel = {}
    cats = 'INCOMPLETE NO_VARIANT APPARENT_DE_NOVO UNTRANSMITTED_HOMOZYGOTE ' + \
           'SPONTANEOUS_HOMOZYGOTE MENDELIAN TRIOS_CONSIDERED'
    for PCR in 'PCRPLUS PCRMINUS'.split(' '):
        for k in cats.split(' '):
            newkey = '{0}_{1}'.format(PCR, k)
            if newkey not in mendel.keys():
                mendel[newkey] = 0

    for fam in trios:
        propcr = pcrdict.get(fam['proband'], 'PCRMINUS')
        ACs = [get_AC(record, s) for s in fam.values()]
        classification = classify_trio_AC(ACs)
        mendel['{0}_{1}'.format(propcr, classification)] += 1
        skips = '{0}_INCOMPLETE {0}_NO_VARIANT {1}_INCOMPLETE {1}_NO_VARIANT'.format(
            'PCRPLUS', 'PCRMINUS')
        if classification not in skips.split(' '):
            mendel['{0}_TRIOS_CONSIDERED'.format(propcr)] += 1

    return mendel

