def create_trees_from_records(records, variant_types, contigs):
    trees = {}
    variant_types_set = set(variant_types)
    for type in variant_types:
        trees[type] = {}
        for contig in contigs:
            trees[type][contig] = IntervalTree()
    for record in records:
        type = vu.get_sv_type(record, variant_types_set)
        contig = record.chrom
        if type == 'INS' or type == 'BND':
            length = 0
        else:
            length = max(0, vu.get_record_length(record))
        trees[type][contig].addi(
            record.start, record.start + length + 1)
    return trees

def create_trees_from_bed_records(records, variant_types, contigs):
    trees = {}
    variant_types_set = set(variant_types)
    for type in variant_types:
        trees[type] = {}
        for contig in contigs:
            trees[type][contig] = IntervalTree()
    for record in records:
        type = record[3]
        if type not in variant_types_set:
            raise ValueError("Unexpected SVTYPE in bed file: %s" % type)
        contig = record[0]
        start = record[1]
        if type == 'INS' or type == 'BND':
            length = 0
        else:
            length = record[2] - record[1]
        trees[type][contig].addi(start, start + length)
    return trees

def create_trees_from_bed(f, contigs, padding):
    trees = {}
    for contig in contigs:
        trees[contig] = IntervalTree()
    contigs_set = set(contigs)
    for record in f:
        line = record.decode()
        if line.startswith('#'):
            continue
        record_tokens = line.strip().split('\t')
        contig = record_tokens[0]
        if contig not in contigs_set:
            continue
        start = int(record_tokens[1])
        end = int(record_tokens[2])
        trees[contig].addi(start - padding, end + padding, record_tokens)
    return trees

def evaluate_tree(test_tree, truth_tree, min_ro, padding):
    tp = {}
    fp = {}
    fpi = {}
    for contig in test_tree:
        if contig in truth_tree:
            tp_contig, fp_contig, fpi_contig = evaluate_contig_tree(
                test_tree[contig], truth_tree[contig], min_ro, padding)
            tp[contig] = tp_contig
            fp[contig] = fp_contig
            fpi[contig] = fpi_contig
        else:
            tp[contig] = 0
            fp[contig] = len(test_tree[contig])
            fpi[contig] = list(test_tree[contig])
    return tp, fp, fpi

