    if len(iterable_a) != len(iterable_b):
        raise ValueError("%s (%d) was not the same size as %s (%d)" % (
            name_a, len(iterable_a), name_b, len(iterable_b)))

def test_iterable_size(iterable, size):
    if len(iterable) != size:
        raise ValueError("Expected %d values but found %d in: %s" %
                         (size, len(iterable), str(iterable)))

def test_column_equals(columns, idx, val):
    if columns[idx] != val:
        raise ValueError("Expected column %d to equal %s but found %s" % (
            idx + 1, val, columns[idx]))

def test_column_in_iterable(columns, idx, iter, msg=None):
    if columns[idx] not in iter:
        if msg is None:
            raise ValueError("Expected column %d to be one of %s but found %s" % (
                idx + 1, str(iter), columns[idx]))
        else:
            raise ValueError(msg)

def test_is_not_empty(list, name):
    if len(list) == 0:
        raise ValueError("List %s was empty" % name)

def test_is_float(columns, idx):
    if not is_float(columns[idx]):
        raise ValueError("Column %d was not a float: %s" %
                         (idx + 1, str(columns)))

def test_is_int(columns, idx):
    if not is_int(columns[idx]):
        raise ValueError("Column %d was not an int: %s" %
                         (idx + 1, str(columns)))

def is_float(str):
    try:
        float(str)
        return True
    except ValueError:
        return False

def is_int(str):
    try:
        int(str)
        return True
    except ValueError:
        return False

def get_info_field(record, name, singularize=False):
    if name not in record.info:
        if name == 'SVLEN':
            if record.info['SVTYPE'] in ['DEL', 'DUP', 'INV']:
                record.info['SVLEN'] = record.stop - record.pos
            else:
                record.info['SVLEN'] = -1
        else:
            raise ValueError("%s info field not found: %s" %
                             (name, record.info.keys()))

    # Checks if the value is a tuple (such as for SVLEN)
    val = record.info[name]
    if singularize and isinstance(val, tuple):
        if len(val) == 1:
            return val[0]
        else:
            raise ValueError(f"Encountered value tuple containing multiple entries: {val}")
    return val

def get_sv_type(record, expected_types):
    if "SVTYPE" not in record.info:
        raise ValueError("SVTYPE info field not found: %s" %
                         record.info.keys())
    type = record.info["SVTYPE"]
    if type not in expected_types:
        raise ValueError("Unexpected SVTYPE: %s" % type)
    return type

def get_evidence_types(record, expected_types):
    if "EVIDENCE" not in record.info:
        raise ValueError("EVIDENCE info field not found: %s" %
                         record.info.keys())
    types = record.info["EVIDENCE"]
    for type in types:
        if type not in expected_types:
            raise ValueError("Unexpected EVIDENCE: %s" % type)
    return types

def parse_famfile(famfile):
    """
    Parse a fam file.

    Returns
    -------
    fam : dict of {str: FamSample}
        Mapping of sample IDs to FamSample entries
    """

    samples = {}
    families = defaultdict(list)

    for line in famfile:
        data = line.strip().split()

        sample = FamSample(*data)
        samples[data[1]] = sample
        families[data[0]].append(sample)

    # Label parents
    for ID, sample in samples.items():
        if sample.father is not None:
            samples[sample.father].is_parent = True
            samples[sample.father].children.append(ID)
        if sample.mother is not None:
            samples[sample.mother].is_parent = True
            samples[sample.mother].children.append(ID)

    return Fam(samples, families)

def learn_cutoff_fdr(metric, probs, fdr_cff=.05):
    preds = metric.values

    # Pass/fail if greater/less than 0.5
    classify = np.vectorize(lambda x: 1 if x >= 0.5 else 0)
    truth = classify(probs)

    # If all variants which passed prior cutoffs also passed random forest,
    # return minimum value instead of trying to compute cutoff
    if 0 not in truth:
        return preds.min()

    fpr, tpr, thresh = roc_curve(truth, preds)

    for i in range(len(fpr)):
        if fpr[i] > fdr_cff:
            break
    best_idx = i
    # If cutoff set at no instances, scikit-learn sets thresh[0] to max(y_score) + 1
    if best_idx == 0:
        return thresh[best_idx] - 1

    return thresh[best_idx]

def annotate_vcf(vcf, gencode, noncoding, annotated_vcf):
    """
    Parameters
    ----------
    vcf : pysam.VariantFile
    gencode : pbt.BedTool
        Gencode gene annotations
    noncoding : pbt.BedTool
        Noncoding elements
    annotated_vcf : str
        Path to output VCF
    """

    # Add metadata lines for annotations
    header = vcf.header

    if gencode is not None:
        for line in GENCODE_INFO:
            header.add_line(line)
    if noncoding is not None:
        for line in NONCODING_INFO:
            header.add_line(line)

    # Open output file
    fout = pysam.VariantFile(annotated_vcf, 'w', header=header)

    # Annotate genic hits
    if isinstance(vcf.filename, bytes):
        fname = vcf.filename.decode()
    else:
        fname = vcf.filename
    sv = svu.vcf2bedtool(fname, split_bnd=True, split_cpx=True,
                         simple_sinks=True, include_unresolved=False)

    effects = annotate(sv, gencode, noncoding)
    effects = effects.to_dict(orient='index')
    # Add results to variant records and save
    for record in vcf:
        anno = effects.get(record.id)
        if anno is None:
            fout.write(record)
            continue

        # Handle general catch-all intersection for MULTIALLELIC variants
        if 'MULTIALLELIC' in record.filter:
            multi_ovr = []
            for info, genelist in anno.items():
                if info in 'LOF DUP_LOF COPY_GAIN DUP_PARTIAL'.split():
                    if genelist != 'NA':
                        for gene in genelist.split(','):
                            if gene not in multi_ovr:
                                multi_ovr.append(gene)
                else:
                    if genelist != 'NA':
                        record.info[info] = genelist
            if len(multi_ovr) > 0:
                record.info['MSV_EXON_OVR'] = ','.join(multi_ovr)
        else:
            for info, genelist in anno.items():
                if genelist != 'NA':
                    record.info[info] = genelist

        if 'NEAREST_TSS' in record.info:
            record.info['INTERGENIC'] = True

        fout.write(record)

    fout.close()

def intersection_type(variant, element, filetype='bed'):
    """
    list of str
        chrom, start, end, ID
    """

    variant_start, variant_end = [int(x) for x in variant[1:3]]

    if filetype == 'bed':
        element_start, element_end = [int(x) for x in element[1:3]]
    elif filetype == 'gtf':
        element_start, element_end = [int(x) for x in element[3:5]]

    if variant_start > element_start and variant_end < element_end:
        return 'BOTH-INSIDE'
    elif variant_start > element_start and variant_start < element_end:
        return 'ONE-INSIDE'
    elif variant_end > element_start and variant_end < element_end:
        return 'ONE-INSIDE'
    else:
        return 'SPAN'

def disruption_type(hit_type, svtype):
    disruptions = {
        'DEL': {
            'BOTH-INSIDE': 'DISRUPTING',
            'ONE-INSIDE': 'DISRUPTING',
            'SPAN': 'DISRUPTING'},
        'DUP': {
            'BOTH-INSIDE': 'DISRUPTING',
            'ONE-INSIDE': 'DISRUPTING',
            'SPAN': 'COPY_GAIN'},
        'CNV': {
            'BOTH-INSIDE': 'DISRUPTING',
            'ONE-INSIDE': 'DISRUPTING',
            'SPAN': 'COPY_GAIN'},
        'INV': {
            'BOTH-INSIDE': 'DISRUPTING',
            'ONE-INSIDE': 'DISRUPTING',
            'SPAN': 'SPAN'},
        'BND': {
            'BOTH-INSIDE': 'DISRUPTING',
            'ONE-INSIDE': 'DISRUPTING',
            'SPAN': 'DISRUPTING'},
        'CTX': {
            'BOTH-INSIDE': 'DISRUPTING',
            'ONE-INSIDE': 'DISRUPTING',
            'SPAN': 'DISRUPTING'},
        'ANEUPLOIDY': {
            'BOTH-INSIDE': 'DISRUPTING',
            'ONE-INSIDE': 'DISRUPTING',
            'SPAN': 'DISRUPTING'},
        'CPX': {
            'BOTH-INSIDE': 'DISRUPTING',
            'ONE-INSIDE': 'DISRUPTING',
            'SPAN': 'DISRUPTING'},
    }

    return disruptions[svtype][hit_type]

def classify_del(disrupt_dict):
    """
    All deletion hits are DISRUPTING
    """
    regions = list(disrupt_dict.keys())
    if 'CDS' in regions:
        return 'LOF'
    if 'UTR' in regions:
        return 'UTR'
    if 'transcript' in regions:
        return 'INTRONIC'
    if 'gene' in regions:
        return 'GENE_OTHER'
    if 'promoter' in regions:
        return 'promoter'

    return 'no_effect'

def classify_dup(disrupt_dict):
    """
    Classify genic effect of a duplication.
    """
    elements = disrupt_dict.keys()
    if 'CDS' in elements:
        # duplication internal to exon - LOF
        if 'BOTH-INSIDE' in disrupt_dict['CDS']:
            return 'LOF'

        # duplication internal to gene, wholly contained within exon, is LOF
        # duplication internal to gene, spanning at least one exon, is DUP_LOF
        # duplication spanning gene is copy gain
        # duplication overlapping gene is no effect (one good copy left)
    if 'gene' in elements:
        if 'SPAN' in disrupt_dict['gene']:
            return 'COPY_GAIN'
        elif 'BOTH-INSIDE' in disrupt_dict['gene'] \
                and 'CDS' in elements \
                and 'SPAN' in disrupt_dict['CDS']:
            return 'DUP_LOF'
        else:
            return 'DUP_PARTIAL'

    if 'UTR' in elements:
        if 'BOTH-INSIDE' in disrupt_dict['UTR']:
            return 'UTR'

    if 'transcript' in elements:
        if 'BOTH-INSIDE' in disrupt_dict['transcript']:
            return 'INTRONIC'

    if 'gene' in elements:
        # Hit gene boundary but not transcript/exon, likely due to
        # filtering to canonical transcript
        return 'GENE_OTHER'

    if 'promoter' in elements:
        if 'BOTH-INSIDE' in disrupt_dict['promoter']:
            return 'promoter'

    return 'no_effect'

def classify_bnd(disrupt_dict):
    """
    Classify genic effect of a breakend.

    An interchromosomal breakpoint falling within a gene is LOF.
    """

    elements = disrupt_dict.keys()

    if 'CDS' in elements:
        return 'LOF'
    if 'transcript' in elements:
        return 'LOF'
    if 'gene' in elements:
        return 'GENE_OTHER'
    if 'UTR' in elements:
        return 'UTR'
    if 'promoter' in elements:
        return 'promoter'

    return 'no_effect'

def classify_disrupt(disrupt_dict, svtype):
    """

    Exonic disruptions count as LOF.

    If exonic span or copy gain, check gene:
        gene disruptions count as LOF
        CDS copy_gain/span count as themselves

    If no exonic hit, check UTR:
        UTR disruption counts as UTR

    If no UTR, check promoter:
        disruption counts
    """

    if svtype == 'DEL':
        return classify_del(disrupt_dict)
    if svtype in 'DUP CNV'.split():
        return classify_dup(disrupt_dict)
    if svtype == 'INV':
        return classify_inv(disrupt_dict)
    if svtype == 'BND' or svtype == 'CTX':
        return classify_bnd(disrupt_dict)

def classify_effect(hits):
    hits['element_hit'] = hits['element_type'] + '__' + hits['hit_type']
    effects = hits.groupby('name svtype gene_name'.split())['element_hit']\
                  .agg(lambda s: ','.join(sorted(set(s))))\
                  .reset_index()

    def _apply_classify(row):
        svtype = row.svtype
        element_hit = row.element_hit.split(',')
        element_hit = [h.split('__') for h in element_hit]
        element_hit = {h[0]: h[1] for h in element_hit}

        return classify_disrupt(element_hit, svtype)
    if effects.shape[0] > 0:
        effects['effect'] = effects.apply(_apply_classify, axis=1)
    else:
        effects['effect'] = 'GENE_OTHER'
    # only necessary when testing
    effects = effects.drop('element_hit', axis=1)
    return effects

def ROH(F, M, E, length, thres=0.0001):
    if min(F, M, E) < length * thres:
        return True
    else:
        return False

def rmsstd(intervals):
    starts = np.array([interval.start for interval in intervals])
    ends = np.array([interval.end for interval in intervals])

    def _meanSS(X):
        mu = np.mean(X)
        return np.sum((X - mu) ** 2) / len(X)

    SS = _meanSS(starts) + _meanSS(ends)
    return np.sqrt(SS)

def RdtestParser(bed):
    CNV = namedtuple('CNV', 'chrom start end name samples svtype'.split())

    for line in bed:
        if line.startswith('#'):
            continue
        data = line.strip().split()

        chrom = data[0]
        start = int(data[1])
        end = int(data[2])
        name = data[3]
        samples = data[4].split(',')
        svtype = data[5].upper()

        yield CNV(chrom, start, end, name, samples, svtype)

def _merge_records(vcf, cpx_records, cpx_record_ids):
    """
    r1, r2 : iter of pysam.VariantRecord
    """
    def _next_record():
        # Skip VCF records that were included in complex event
        # get next record that's not already present in cpx_record_idss
        _rec = next(vcf, None)
        while _rec is not None and _rec.id in cpx_record_ids:
            _rec = next(vcf, None)
        return _rec

    def _next_cpx():
        try:
            return cpx_records.popleft()
        except IndexError:
            return None
    # Initialize merge
    curr_record = _next_record()
    curr_cpx = _next_cpx()
    while curr_record is not None and curr_cpx is not None:
        # Merge sort records not in complex event
        if curr_record.chrom == curr_cpx.chrom:
            if curr_record.pos <= curr_cpx.pos:
                yield curr_record
                curr_record = _next_record()
            else:
                yield curr_cpx
                curr_cpx = _next_cpx()
        elif svu.is_smaller_chrom(curr_record.chrom, curr_cpx.chrom):
            yield curr_record
            curr_record = _next_record()
        else:
            yield curr_cpx
            curr_cpx = _next_cpx()

    # At least one iterator is exhausted, return rest of other iterator, if any
    while curr_record is not None:
        yield curr_record
        curr_record = _next_record()
    while curr_cpx is not None:
        yield curr_cpx
        curr_cpx = _next_cpx()

def multisort(xs, specs):
    for key, reverse in reversed(specs):
        xs.sort(key=attrgetter(key), reverse=reverse)
    return xs

def _cluster_INV_list(independent_INV):
    out = []
    rec = float('-inf')  # be sure to add first element
    for i in independent_INV:
        if i.pos > rec:
            out.append([i])
            rec = i.stop
        else:
            out[-1].append(i)
            if i.stop > rec:
                rec = i.stop
    return out

def cluster_single_cleanup(cluster):
    # for clusters including both FF and RR inversions, only keep inversions for CPX resolution
    cluster_svtype = [[i.info['SVTYPE'], i.info['STRANDS']] for i in cluster]
    if ['INV', '--'] in cluster_svtype and ['INV', '++'] in cluster_svtype:
        return deque(
            [
                cluster[cluster_svtype.index(['INV', '--'])],
                cluster[cluster_svtype.index(['INV', '++'])]
            ]
        )
    else:
        return cluster

def ok_ins_strands(bnd1, bnd2):
    strand1, strand2 = sorted([t.info['STRANDS'] for t in (bnd1, bnd2)])

    return (strand1 == '+-') and (strand2 == '-+')

def get_arms(record, cytobands):
    regionA = '{0}:{1}-{1}'.format(record.chrom, record.pos)
    regionB = '{0}:{1}-{1}'.format(record.info['CHR2'], record.stop)

    def _get_arm(region):
        arm = next(cytobands.fetch(region))
        return arm.split()[3][0]

    return _get_arm(regionA), _get_arm(regionB)

def samples_overlap_records(recA, recB, called_samples_dict, upper_thresh=0.5, lower_thresh=0.5):
    if recA.id not in called_samples_dict:
        called_samples_dict[recA.id] = set(svu.get_called_samples(recA))
    if recB.id not in called_samples_dict:
        called_samples_dict[recB.id] = set(svu.get_called_samples(recB))
    return samples_overlap(called_samples_dict[recA.id], called_samples_dict[recB.id],
                           upper_thresh=upper_thresh, lower_thresh=lower_thresh)

def unify_list(list):
    out = []
    for i in list:
        if i not in out:
            out.append(i)
    return out

def link_cpx_V2(linked_INV, cpx_dist=2000):
    overlapping_inv = []
    called_samples_dict = {}
    for group in linked_INV:
        if len(group) > 1:
            for i, j in itertools.combinations(group, 2):
                if records_overlap(i, j) and samples_overlap_records(i, j, called_samples_dict):
                    overlapping_inv.append([i, j])
        else:
            overlapping_inv.append(group)
    cluster = []
    for inv in overlapping_inv:
        if len(inv) > 1:
            if abs(inv[1].pos - inv[0].pos) > cpx_dist and abs(inv[1].stop - inv[0].stop) > cpx_dist:
                if 'STRANDS' in inv[0].info.keys() and 'STRANDS' in inv[1].info.keys():
                    if inv[0].info['STRANDS'] != inv[1].info['STRANDS']:
                        if inv[0].pos < inv[1].pos < inv[0].stop < inv[1].stop \
                                or inv[1].pos < inv[0].pos < inv[1].stop < inv[0].stop:
                            cluster.append(inv)
        else:
            cluster.append(inv)
    return cluster

def classify_insertion(plus, minus, mh_buffer=50):
    plus_A = plus.pos
    minus_A = minus.pos
    plus_B = plus.stop
    minus_B = minus.stop

    # Buffer comparisons
    def _greater(p1, p2):
        return p1 > p2 - mh_buffer

    if _greater(minus_A, plus_A) and _greater(minus_B, plus_B):
        return 'INS_B2A'
    elif _greater(plus_A, minus_A) and _greater(plus_B, minus_B):
        return 'INS_A2B'
    else:
        return 'INS_UNCLASSIFIED'

def rescan_single_enders(vcf, pe, min_support=4, window=500, pe_blacklist=None):
    for record in vcf:
        rescan_single_ender(record, pe, min_support, window,
                            pe_blacklist=pe_blacklist)

def any_called(record):
    null_GTs = [(0, 0), (None, None), (0, ), (None, )]

    def _is_called(sample):
        return record.samples[sample]['GT'] not in null_GTs

    return any([_is_called(sample) for sample in record.samples])

def make_multiallelic_alts(records):
    """
    Sets simple symbolic alt for multi-allelic records
    """
    for record in records:
        record.alts = ('<CNV>',)

def update_best_genotypes(new_record, records, preserve_multiallelic=False):
    """
    For each sample in record, update GT and other formats with best genotype

    Parameters
    ----------
    new_record : pysam.VariantRecord
    records : list of SVRecord
    preserve_multiallelic : bool
        If any record is multiallelic, make all genotypes multiallelic
    """

    def _binary_or(x, y):
        return x | y

    def _str_to_tuple(x):
        return (x,) if type(x) is str else x

    if preserve_multiallelic:
        is_multiallelic = check_multiallelic(records)
    else:
        is_multiallelic = False

    if is_multiallelic:
        make_multiallelic_alts(records)

    new_record_formats = new_record.header.formats.keys()
    for sample in new_record.samples:
        best_record = choose_best_genotype(sample, records)
        for key in best_record.format.keys():
            if key in new_record_formats:
                # If any record is multiallelic, replace non-multiallelic
                # genotypes with multiallelic equivalents
                if key == 'GT':
                    gt = best_record.samples[sample][key]
                    if is_multiallelic:
                        # No genotypes for multi-allelic records since they can't always be determined
                        new_record.samples[sample][key] = (None, None)
                    else:
                        new_record.samples[sample][key] = tuple([x if x is None else min(x, 1) for x in gt])
                elif key == 'EV':
                    ev_values = [r.samples[sample][key] for r in records]
                    ev_values = [_str_to_tuple(v) for v in ev_values]
                    ev_types = list(set(type(v) for v in ev_values if v is not None))
                    if len(ev_types) == 0:
                        new_record.samples[sample][key] = None
                    elif len(ev_types) > 1:
                        raise ValueError(f"Found multiple EV types: {str(ev_types)}")
                    else:
                        ev_type = ev_types[0]
                        if ev_type is tuple:
                            new_record.samples[sample][key] = ",".join(
                                sorted(tuple(set(t for ev in ev_values for t in ev))))
                        elif ev_type is int:
                            new_record.samples[sample][key] = reduce(_binary_or, ev_values)
                        else:
                            raise ValueError(f"Unsupported EV type: {str(ev_type)}")
                else:
                    new_record.samples[sample][key] = best_record.samples[sample][key]

def _record_to_bed(record):
    entry = '{chrom}\t{start}\t{end}\t{name}\t{samples}\t{svtype}\n'

    if record.info['SVTYPE'] in 'DEL DUP'.split():
        return entry.format(chrom=record.chrom,
                            start=record.pos,
                            end=record.stop,
                            name=record.id,
                            samples=','.join(get_called_samples(record)),
                            svtype=record.info['SVTYPE'])
    else:
        return ''

def is_smaller_chrom(chrA, chrB):
    """
    Test if chrA is naturally less than chrB

    Returns True if chrA == chrB so comparison will default to position
    """

    if chrA.startswith('chr'):
        chrA = chrA[3:]
    if chrB.startswith('chr'):
        chrB = chrB[3:]

    # Numeric comparison, if possible
    if chrA.isdigit() and chrB.isdigit():
        return int(chrA) <= int(chrB)

    # String comparison for X/Y
    elif not chrA.isdigit() and not chrB.isdigit():
        return chrA <= chrB

    # Numeric is always less than X/Y
    else:
        return chrA.isdigit()

def recip(startA, endA, startB, endB, frac):
    """
    Test if two intervals share a specified reciprocal overlap.
    """

    if frac == 0:
        return True

    start = max(startA, startB)
    end = min(endA, endB)
    olen = end - start
    lenA = endA - startA
    lenB = endB - startB

    try:
        lapA = olen / float(lenA)
        lapB = olen / float(lenB)
    except ZeroDivisionError:
        return False

    return (olen > 0) and (lapA >= frac) and (lapB >= frac)

def make_bnd_alt(chrom, pos, strands, ref_base='N'):
    """
    Make ALT for BND record in accordance with VCF specification.
    """

    p = '{0}:{1}'.format(chrom, pos)
    t = ref_base

    if strands == '++':
        fmt = '{1}]{0}]'
    elif strands == '+-':
        fmt = '{1}[{0}['
    elif strands == '-+':
        fmt = ']{0}]{1}'
    elif strands == '--':
        fmt = '[{0}[{1}'

    return fmt.format(p, t)

def set_null(record, sample):
    """Remove sample call from a VariantRecord"""
    dat = record.samples[sample].items()

    # Set genotype to no-call
    record.samples[sample]['GT'] = (0, 0)

    for fmt, value in dat:
        if fmt == 'GT':
            continue

        # Get type and count of FORMAT
        n = record.format[fmt].number
        dtype = record.format[fmt].type

        # Set null value based on FORMAT type
        if dtype in 'Integer Float'.split():
            null_val = 0
        elif dtype in 'String Character'.split():
            null_val = ''
        else:
            raise ValueError('Invalid VCF FORMAT type: {0}'.format(dtype))

        # Set the appropriate count of values
        if n == 1:
            record.samples[sample][fmt] = null_val
        elif n == '.':
            record.samples[sample][fmt] = (null_val, )
        else:
            record.samples[sample][fmt] = tuple(null_val for i in range(n))

def _ordered_intersection(
        keep_order_members: Iterable[str],
        check_members: Iterable[str]
):
    check_members = set(check_members)
    return [member for member in keep_order_members if member in check_members]

def load_variants_from_pickle(
        pickle_file: str,
        wanted_variant_ids: Optional[Iterable[str]] = None,
        wanted_sample_ids: Optional[Iterable[str]] = None,
        wanted_properties: Optional[Iterable[str]] = None
) -> pandas.DataFrame:
    variants = pandas.read_pickle(pickle_file)
    if wanted_variant_ids is None and wanted_sample_ids is None and wanted_properties is None:
        return variants
    variants_select = slice(None) if wanted_variant_ids is None \
        else _ordered_intersection(wanted_variant_ids, variants.index)
    # noinspection PyTypeChecker
    samples_select = slice(None) if wanted_sample_ids is None or Keys.sample_id not in variants.columns.names \
        else [None] + _ordered_intersection(wanted_sample_ids, variants.columns.get_level_values(level=Keys.sample_id))
    properties_select = slice(None) if wanted_properties is None or Keys.property not in variants.columns.names \
        else _ordered_intersection(wanted_properties, variants.columns.get_level_values(level=Keys.property))
    columns_select = samples_select if Keys.property not in variants.columns.names \
        else properties_select if Keys.sample_id not in variants.columns.names \
        else (samples_select, properties_select)
    return variants.loc[variants_select, columns_select]

def get_dtype_info(dt: type) -> Union[numpy.iinfo, numpy.finfo]:
    numpy_dt = dt.numpy_dtype if hasattr(dt, "numpy_dtype") else dt
    return numpy.iinfo(numpy_dt) if numpy.issubdtype(numpy_dt, numpy.integer) else numpy.finfo(numpy_dt)

def get_precision_recall_curves_figure(
        truth_data: TruthData,
        scores_data_sets: Collection[ScoresDataSet],
        sv_selectors: Mapping[str, SvTypeCutoffSelector],
        num_precision_recall_curve_rows: int = Default.num_precision_recall_curve_rows,
        title_font_size: int = Default.title_font_size,
        label_font_size: int = Default.label_font_size,
        legend_font_size: int = Default.legend_font_size,
        tick_font_size: int = Default.tick_font_size,
        plot_max_f1: bool = Default.plot_max_f1,
        pdf_writer: Optional[PdfPages] = None
) -> (pyplot.Figure, Dict[str, float]):
    # get the PrecisionRecallCurves broken down by category, keeping only the categories that have at least one
    # non-empty curve
    precision_recall_curves = {
        category: category_pr_curves
        for category, category_pr_curves in get_precision_recall_curves(
            truth_data=truth_data, scores_data_sets=scores_data_sets, sv_selectors=sv_selectors
        ).items()
        if not all(precision_recall_curve.is_empty for precision_recall_curve in category_pr_curves.values())
    }
    # get the overall best thresholds
    best_thresholds = {
        data_set_label: precision_recall_curve.get_point_at_max_f_score().name
        for data_set_label, precision_recall_curve in precision_recall_curves[Keys.non_bnd_types].items()
    }
    # get the default thresholds
    default_thresholds = {
        data_set.label: data_set.passing_score
        for data_set in scores_data_sets
    }

    # construct figure add axis for legend
    fig, gridspec, num_columns = make_fig_and_gridspec(num_axes=len(precision_recall_curves) + 1,
                                                       num_rows=num_precision_recall_curve_rows)
    row, column = 0, 0
    for sv_category, category_pr_curves in precision_recall_curves.items():
        ax = fig.add_subplot(gridspec[row, column])
        plot_precision_recall_curves(ax, category_pr_curves, best_thresholds, default_thresholds, title_str=sv_category,
                                     title_font_size=title_font_size, label_font_size=label_font_size,
                                     tick_font_size=tick_font_size, plot_max_f1=plot_max_f1)
        column += 1
        if column == num_columns:
            row, column = row + 1, 0

    # make extra axis with legend
    _draw_extra_legend_axis(
        fig, gridspec, row, column,
        line_labels=precision_recall_curves[Keys.all_variant_types].keys(),
        markers=[("ks", "default"), ("ko", "f1-max")] if plot_max_f1 else [("ks", "default")],
        legend_font_size=legend_font_size, advance_color_cycle=1
    )

    if pdf_writer is not None:
        pdf_writer.savefig(fig, bbox_inches="tight")
        return None, best_thresholds
    else:
        return fig, best_thresholds

def iter_categories(sv_selectors: Mapping[str, SvTypeCutoffSelector]) -> Iterator[Tuple[str, SvTypeCutoffSelector]]:
    yield Keys.all_variant_types, lambda metrics: pandas.Series(common.true(metrics.shape[0]),
                                                                index=metrics.index)
    if Keys.bnd_types in sv_selectors:
        bnd_selector = sv_selectors[Keys.bnd_types]
        yield Keys.non_bnd_types, lambda info: ~bnd_selector(info)

    for category in sorted(sv_selectors.keys()):
        yield category, sv_selectors[category]

def _filter_null_curves_categories(
        precision_recall_curves: Dict[str, Dict[str, PrecisionRecallCurve]]
) -> Dict[str, Dict[str, PrecisionRecallCurve]]:
    return {
        category: category_pr_curves
        for category, category_pr_curves in precision_recall_curves.items()
        if not all(precision_recall_curve.is_empty for precision_recall_curve in category_pr_curves.values())
    }

def get_precision_recall_curves(
        truth_data: TruthData,
        scores_data_sets: Collection[ScoresDataSet],
        sv_selectors: Mapping[str, SvTypeCutoffSelector]
) -> Dict[str, Dict[str, PrecisionRecallCurve]]:
    """
    return dict from SV category to another mapping, that being a dict from data set label to precision-recall curve
    """
    log("get_precision_recall_curves() ...")
    precision_recall_curves = _filter_null_curves_categories(
        {
            category: {
                data_set.label: data_set.select_category(
                    category=category, sv_type_cutoff_selector=selector
                ).get_precision_recall_curve(truth_data)
                for data_set in scores_data_sets
            }
            for category, selector in iter_categories(sv_selectors)
        }
    )
    log("COMPLETE: get_precision_recall_curves()")
    return precision_recall_curves

def _filter_null_stats_categories(
        stats_by_category: Optional[Mapping[str, pandas.DataFrame]]
) -> Optional[Dict[str, pandas.DataFrame]]:
    if stats_by_category is None:
        return None
    # noinspection PyUnresolvedReferences
    return {
        category: stats for category, stats in stats_by_category.items()
        if not (stats == 0).all().all()
    }

def get_mendelian_inheritance_stats(
        truth_data: TruthData,
        scores_data_sets: Collection[ScoresDataSet],
        sv_selectors: Mapping[str, SvTypeCutoffSelector],
        max_f1_thresholds: Mapping[str, float],
        plot_max_f1: bool,
        replot_unfiltered: bool,
) -> Optional[Dict[str, pandas.DataFrame]]:
    log("get_mendelian_inheritance_stats() ...")
    if truth_data.pedigree_file_info is None:
        log("SKIPPED: get_mendelian_inheritance_stats(), no truth data")
        return None

    inheritance_stats_dict = {}
    calculate_unfiltered = True
    for data_set in scores_data_sets:
        for filter_label, filter_score in {
            Keys.unfiltered: None,
            Keys.filtered: data_set.passing_score,
            Keys.max_f1: max_f1_thresholds.get(data_set.label, None)
        }.items():
            if filter_label == Keys.unfiltered and not calculate_unfiltered:
                continue
            elif filter_label == Keys.max_f1 and not plot_max_f1:
                continue  # don't need/want max-f1 so skip calculation
            log(f"get_inheritance_stats({data_set.label}:{filter_label}) ...")
            filtered_data_set = data_set.get_inheritance_stats(truth_data=truth_data) if filter_score is None \
                else data_set.apply_hard_filter(filter_score).get_inheritance_stats(truth_data=truth_data)

            for category, selector in iter_categories(sv_selectors):
                log(f"\tselect_variants: {category} ...")
                selected_filtered_data_set = filtered_data_set.select_category(category=category,
                                                                               sv_type_cutoff_selector=selector)
                log("\tsum inheritance stats ...")
                inheritance_stats_dict[(data_set.label, filter_label, category)] = \
                    selected_filtered_data_set.inheritance_stats.astype(pandas.UInt64Dtype()).sum(axis=0)
            log(f"get_inheritance_stats({data_set.label}:{filter_label}) COMPLETE")
            if filter_label == Keys.unfiltered and not replot_unfiltered:
                # don't re-compute unfiltered stats
                if calculate_unfiltered:
                    calculate_unfiltered = False

    filter_keys = (Keys.unfiltered, Keys.filtered, Keys.max_f1) if plot_max_f1 \
        else (Keys.unfiltered, Keys.filtered)
    mendelian_inheritance_stats = _filter_null_stats_categories(
        {
            category: pandas.DataFrame.from_dict(
                {
                    (data_set.label, filter_label): inheritance_stats_dict[(data_set.label, filter_label, category)]
                    for data_set in scores_data_sets
                    for filter_label in filter_keys
                    if (data_set.label, filter_label, category) in inheritance_stats_dict
                },
                orient="index"
            )
            for category, __ in iter_categories(sv_selectors)
        }
    )
    log("COMPLETE: get_mendelian_inheritance_stats()")
    return mendelian_inheritance_stats

def get_variants_per_sample(
        scores_data_sets: Collection[ScoresDataSet],
        sv_selectors: Mapping[str, SvTypeCutoffSelector],
        max_f1_thresholds: Mapping[str, float],
        plot_max_f1: bool,
        replot_unfiltered: bool,
) -> Dict[str, pandas.DataFrame]:
    log("get_variants_per_sample() ...")

    variants_per_sample_dict = {}
    calculate_unfiltered = True
    for data_set in scores_data_sets:
        for filter_label, filter_score in {
            Keys.unfiltered: None,
            Keys.filtered: data_set.passing_score,
            Keys.max_f1: max_f1_thresholds.get(data_set.label, None)
        }.items():
            if filter_label == Keys.unfiltered and not calculate_unfiltered:
                continue
            if filter_label == Keys.max_f1 and not plot_max_f1:
                continue  # don't need/want max-f1 so skip calculation
            log(f"get variants per sample({data_set.label}:{filter_label}) ...")
            filtered_data_set = data_set if filter_score is None else data_set.apply_hard_filter(filter_score)

            for category, selector in iter_categories(sv_selectors):
                log(f"\tselect_variants: {category} ...")
                selected_filtered_data_set = filtered_data_set.select_category(category=category,
                                                                               sv_type_cutoff_selector=selector)
                log("\tget variants per sample ...")
                variants_per_sample_dict[(data_set.label, filter_label, category)] = \
                    selected_filtered_data_set.variants_per_sample
            if filter_label == Keys.unfiltered and not replot_unfiltered:
                # don't re-compute unfiltered stats
                if calculate_unfiltered:
                    calculate_unfiltered = False

    filter_keys = (Keys.unfiltered, Keys.filtered, Keys.max_f1) if plot_max_f1 \
        else (Keys.unfiltered, Keys.filtered)

    variants_per_sample = _filter_null_stats_categories(
        {
            category: pandas.DataFrame.from_dict(
                {
                    (data_set.label, filter_label): variants_per_sample_dict[(data_set.label, filter_label, category)]
                    for data_set in scores_data_sets
                    for filter_label in filter_keys
                    if (data_set.label, filter_label, category) in variants_per_sample_dict
                },
                orient="index"
            )
            for category, __ in iter_categories(sv_selectors)
        }
    )
    log("COMPLETE: get_variants_per_sample()")
    return variants_per_sample

def get_mendelian_violation_curves(
        truth_data: TruthData,
        scores_data_sets: Collection[ScoresDataSet],
        sv_selectors: Mapping[str, SvTypeCutoffSelector],
        plotted_mendelian_violation_keys: Optional[Iterable[str]] = Default.plotted_mendelian_violation_trio_types
) -> Optional[Dict[str, Dict[str, MendelianViolationCurve]]]:
    if truth_data.pedigree_file_info is None:
        return None
    log("get_mendelian_violation_curves() ...")

    mendelian_violation_curves_dict = {category: {} for category, __ in iter_categories(sv_selectors)}
    for data_set in scores_data_sets:
        log(f"get_inheritance_stats({data_set.label}) ...")
        filtered_data_set = data_set.get_inheritance_stats(truth_data=truth_data)
        for category, selector in iter_categories(sv_selectors):
            log(f"\tselect_variants: {category} ...")
            selected_filtered_data_set = filtered_data_set.select_category(category=category,
                                                                           sv_type_cutoff_selector=selector)
            log("\tget violation curve ...")
            violation_curve = selected_filtered_data_set.get_mendelian_violation_curve(
                truth_data=truth_data, plotted_mendelian_violation_keys=plotted_mendelian_violation_keys
            )
            if violation_curve is not None:
                mendelian_violation_curves_dict[category][data_set.label] = violation_curve

    log("COMPLETE: get_mendelian_violation_curves()")
    return {
        sv_category: category_violation_curves
        for sv_category, category_violation_curves in mendelian_violation_curves_dict.items()
        if len(category_violation_curves) > 0
    }

def scale_inheritance_stats(
        mendelian_inheritance_stats: pandas.DataFrame
) -> (pandas.DataFrame, pandas.DataFrame, pandas.Series):
    num_trios = mendelian_inheritance_stats[Keys.num_trios].copy()
    # scale all stats by num_trios_stat
    scaled_stats = mendelian_inheritance_stats.div(num_trios, axis=0)
    # replace num_trios stat by num_trios scaled to unfiltered num_trios for each data set
    unfiltered_num_trios = num_trios.xs(Keys.unfiltered, level=1, drop_level=True)
    scaled_stats[Keys.num_trios] = num_trios / unfiltered_num_trios.max()
    return scaled_stats, num_trios.astype("int"), unfiltered_num_trios.astype("int")

def _set_component_color(_plot_component, _color, _alpha=0.7):
    if hasattr(_plot_component, "set_color"):
        _plot_component.set_color(_color)
    else:
        if hasattr(_plot_component, "set_facecolor"):
            _plot_component.set_facecolor(_color)
        if hasattr(_plot_component, "set_edgecolor"):
            _plot_component.set_edgecolor(_color)
    if hasattr(_plot_component, "set_alpha"):
        _plot_component.set_alpha(_alpha)

def _set_violin_obj_color(violin_obj, color):
    for pc in violin_obj["bodies"]:
        _set_component_color(pc, color)
    for component_name, component in violin_obj.items():
        if isinstance(component, Iterable):
            for pc in component:
                _set_component_color(pc, color)
        else:
            _set_component_color(component, color)

def load_quality_data(
        overlap_results_file: str,
        pedigree_files: Optional[Collection[str]],
        optimal_overlap_cutoffs_file: str,
        scores_data_json: Optional[str] = None,
        size_ranges: Mapping[str, Tuple[float, float]] = Default.sv_selector_size_ranges
) -> (TruthData, Dict[str, SvTypeCutoffSelector], List[ScoresDataSet]):
    truth_data = TruthData(overlap_results_file=overlap_results_file, pedigree_files=pedigree_files)
    scores_data_sets = ScoresDataSet.from_json(
        scores_data_json, truth_data=truth_data
    )
    all_sv_types = set.union(*(data_set.all_sv_types for data_set in scores_data_sets))
    sv_selectors = get_truth_overlap.get_sv_selectors(all_sv_types=all_sv_types, size_ranges=size_ranges) \
        if optimal_overlap_cutoffs_file is None \
        else {
            sv_category: cutoff.selector
            for sv_category, cutoff in get_truth_overlap.load_optimal_overlap_cutoffs(
                optimal_overlap_cutoffs_file
            ).items()
        }  # noqa: E123

    return truth_data, sv_selectors, scores_data_sets

def _parse_size_ranges(size_ranges_arg: str) -> dict[str, tuple[float, float]]:
    def _parse_arg(_arg: str) -> Iterator[tuple[str, tuple[float, float]]]:
        for _word in _arg.split(','):
            _split_word = _word.split(':', 1)
            yield _split_word[0], tuple(float(_x) for _x in _split_word[1].split(':', 1))

    return {description: size_range for description, size_range in _parse_arg(size_ranges_arg)}

def _kebab_to_snake(kebab_str: str) -> str:
    """
    Allow passing commands in kebab case by converting to snake case (to match file names)
    """
    return kebab_str.replace('-', '_')

def _snake_to_kebab(snake_str: str) -> str:
    """
    Convert snake-case files to kebab-case for display
    """
    return snake_str.replace('_', '-')

def _find_sub_modules(package: str) -> Iterator[Text]:
    module = common.dynamic_import(package)
    module_path = module.__path__
    # noinspection PyProtectedMember
    module_folder = module_path[0] if isinstance(module_path, List) else module_path._path[0]
    command_module = os.path.basename(__file__)  # but exclude this module if it happens to be there
    for sub_module_name in os.listdir(module_folder):
        if sub_module_name != command_module:
            yield sub_module_name.rsplit(".py", 1)[0]

def _command_help_func(
        package: str,
        sub_modules: FrozenSet[str],
        file_descriptor: TextIO = sys.stdout,
        num_indent: int = 2,
        max_width: int = 78
):
    print(f"{package} [command] [args...]", file=file_descriptor)
    print("Valid commands are:", file=file_descriptor)
    indent1 = " " * num_indent
    indent2 = " " * (num_indent * 2)
    for command_name in sub_modules:
        help_str = _get_help_summary(package, command_name)
        if help_str is None:
            continue
        print(f"{indent1}{_snake_to_kebab(command_name)}:", file=file_descriptor)
        help_str = help_str.strip()
        if len(indent2 + help_str) <= max_width:
            print(f"{indent2}{help_str}", file=file_descriptor)
        else:
            help_words = help_str.split()
            help_line = indent2 + help_words[0]
            for next_word in help_words[1:]:
                if len(help_line + " " + next_word) <= max_width:
                    help_line += " " + next_word
                else:
                    print(str(help_line), file=file_descriptor)
                    help_line = indent2 + next_word
            print(str(help_line), file=file_descriptor)
    print("", file=file_descriptor)

def _bad_command_func(
        package: str,
        sub_modules: FrozenSet[str],
        argv: List[Text],
        file_descriptor: TextIO = sys.stderr
):
    if len(argv) >= 1:
        print("Bad command: %s" % argv[0], file=file_descriptor)
    else:
        print("No command specified.", file=file_descriptor)

    _command_help_func(package=package, sub_modules=sub_modules, file_descriptor=file_descriptor)
    sys.exit(1)

def main(argv: Optional[List[Text]] = None):
    """
    Dispatch arguments to appropriate module function, with call to
    command_line.py removed, so that the dispatched command will behave the same
    as if it had been called directly.
    Args:
        argv: input arguments to command. If called from command-line (usual use
              case), this will simply be sys.argv
    """
    if argv is None:
        argv = sys.argv
    package = os.path.basename(_kebab_to_snake(argv[0]))
    sub_modules = frozenset(_find_sub_modules(package))
    if len(argv) < 2:
        _bad_command_func(package=package, sub_modules=sub_modules, argv=argv[1:])
    else:
        sub_module_command = argv[1]
        if sub_module_command in {"help", "-help", "--help"}:
            _command_help_func(package=package, sub_modules=sub_modules)
            return
        sub_module_command = _kebab_to_snake(sub_module_command)
        if sub_module_command in sub_modules:
            try:
                call_func = common.dynamic_import(f"{package}.{sub_module_command}.main")
            except ModuleNotFoundError:
                raise ValueError(
                    f"{sub_module_command} does not have a 'main' function, and thus cannot be invoked as a "
                    "command-line program."
                )
            call_func(argv[1:])
        else:
            # bad command
            _bad_command_func(package=package, sub_modules=sub_modules, argv=argv[1:])

def argparse_bool(arg: Union[str, bool]) -> bool:
    if isinstance(arg, bool):
        return arg
    if arg.lower() in ('yes', 'true', 't', 'y', '1'):
        return True
    elif arg.lower() in ('no', 'false', 'f', 'n', '0'):
        return False
    else:
        raise ValueError('Boolean value expected.')

def fix_record(
        record: pysam.VariantRecord,
        error_on_mismatched_chr2: bool = Default.error_on_mismatched_chr2,
        flipped_interval_strategy: FlippedIntervalStrategy = Default.flipped_interval_strategy,
        gq_scale: Optional[float] = None
) -> pysam.VariantRecord:
    f"""
    For supplied VCF record, detect and fix errors with pos/end, and allele designation
    Args:
        record: pysam.VariantRecord
            Variant line in VCF
        error_on_mismatched_chr2: bool (Default={Default.error_on_mismatched_chr2})
            If {VcfKeys.bnd_contig_2} does not match info in SOURCE, then throw an error if true, otherwise warn
        flipped_interval_strategy: FlippedIntervalStrategy (Default={Default.flipped_interval_strategy})
            If END < POS, fix the interval with the defined strategy
        gq_scale: Optional[float] (Default=None)
            If not None, multiply GQ by this scale
    Returns:
        fixed_record: pysam.VariantRecord
            Corrected variant line
    """
    if VcfKeys.bnd_contig_2 in record.info:
        if record.info[VcfKeys.svtype] in BND_TYPES:
            if VcfKeys.bnd_end_2 not in record.info:
                record.info[VcfKeys.bnd_end_2] = record.stop
            record.stop = record.pos + 1
        else:
            # not a break-end, figure out what's going on here...
            if VcfKeys.source in record.info.keys():
                chr2, end2 = str_to_loc(record.info[VcfKeys.source])
                if record.info[VcfKeys.bnd_contig_2] != chr2:
                    message = f"Variant {record.id} with {VcfKeys.svtype}={record.info[VcfKeys.svtype]} has " \
                        f"{VcfKeys.bnd_contig_2}!={VcfKeys.source} chrom ({record.info[VcfKeys.bnd_contig_2]}!={chr2})"
                    if error_on_mismatched_chr2:
                        raise ValueError(message)
                    else:
                        warnings.warn(message)
                        record.info[VcfKeys.bnd_contig_2] = chr2

                record.info[VcfKeys.bnd_end_2] = end2
            else:
                # no alternate source and not a break-end
                if record.info[VcfKeys.bnd_contig_2] != record.chrom:
                    # use this somehow?
                    # if record.info[VcfKeys.svtype] in "INS" and record.stop == record.pos:
                    #     record.stop = record.pos + 1
                    raise ValueError(
                        f"Variant {record.id} has {VcfKeys.svtype}={record.info[VcfKeys.svtype]} but "
                        f"{VcfKeys.bnd_contig_2}!=chrome ({record.info[VcfKeys.bnd_contig_2]}!={record.chrom})"
                    )
                record.info.pop(VcfKeys.bnd_contig_2)

    if record.pos >= record.stop:
        if record.pos == record.stop:
            # empty interval, valid for INS, otherwise an error
            if record.info[VcfKeys.svtype] not in ["INS", "BND", "CPX", "CTX"]:
                raise ValueError(
                    f"Variant {record.id} with {VcfKeys.svtype}={record.info[VcfKeys.svtype]} has pos=stop={record.pos}"
                )
        else:
            # sometimes this error occurs for INS or similar SV types
            warnings.warn(f"{record.id} had END < POS")
            if flipped_interval_strategy == FlippedIntervalStrategy.end_to_pos:
                record.stop = record.pos
            else:
                # just swap end and pos
                record.pos, record.stop = record.stop, record.pos

    if record.alts == ('<DUP>',):
        # some older VCFs had DUP alleles marked as 2 instead of 1
        num_bad_gt = 0
        for sample in record.samples.values():
            gt = sample[VcfKeys.gt]
            if gt is not None and any(allele is not None and allele > 1 for allele in gt):
                # bad sample GT, DUP allele should be 0 or 1
                num_bad_gt += 1
                sample[VcfKeys.gt] = tuple(
                    a - 2 if (a is not None and a > 1) else a
                    for a in gt
                )
        if num_bad_gt > 0:
            warnings.warn(f"{record.id} had {num_bad_gt} bad samples")
    if gq_scale is not None:
        for sample in record.samples.values():
            gq = sample[VcfKeys.gq]
            if gq is not None:
                sample[VcfKeys.gq] = int(round(gq * gq_scale))

    return record

def _number_more_than_1(vcf_number: Union[str, int]) -> bool:
    if isinstance(vcf_number, str):
        try:
            return int(vcf_number) > 1
        except ValueError:
            return True
    return vcf_number > 1

def _get_genotype_extractor(vcf_prop_name: str, header: pysam.VariantHeader) -> GenotypePropertyExtractor:
    header_field = header.formats.get(vcf_prop_name)
    field_type, number = header_field.type, header_field.number
    if field_type == VcfFieldTypes.string or _number_more_than_1(number):
        encode_dict = CategoryPropertyCollator.get_encode_dict(vcf_prop_name)

        def extractor(genotype_record: pysam.libcbcf.VariantRecordSample) -> Optional[EncodedVcfField]:
            return CategoryPropertyCollator.encode(
                genotype_record.get(vcf_prop_name, None),
                encode_dict
            )
    else:
        def extractor(genotype_record: pysam.libcbcf.VariantRecordSample) -> Optional[EncodedVcfField]:
            return genotype_record.get(vcf_prop_name, None)
    return extractor

def _get_variant_extractor(
        vcf_prop_name: str, header: pysam.VariantHeader, missing_value: Any = Default.missing_value
) -> VariantPropertyExtractor:
    if vcf_prop_name in header.info:
        # get from info
        header_field = header.info.get(vcf_prop_name)
        field_type, number = header_field.type, header_field.number
        if field_type == VcfFieldTypes.string or _number_more_than_1(number):
            encode_dict = CategoryPropertyCollator.get_encode_dict(vcf_prop_name)

            def extractor(variant_record: pysam.VariantRecord) -> Optional[EncodedVcfField]:
                return CategoryPropertyCollator.encode(
                    variant_record.info.get(vcf_prop_name, None),
                    encode_dict
                )
        else:
            def extractor(variant_record: pysam.VariantRecord) -> Optional[EncodedVcfField]:
                return variant_record.info.get(vcf_prop_name, None)
    elif vcf_prop_name == VcfKeys.filter:
        # always a tuple of strings
        encode_dict = CategoryPropertyCollator.get_encode_dict(Keys.filter)

        def extractor(variant_record: pysam.VariantRecord) -> Optional[EncodedVcfField]:
            filters = tuple(variant_record.filter)
            return CategoryPropertyCollator.encode(filters if filters else missing_value, encode_dict)
    else:
        # get property directly from record. These are fields defined in the vcf spec
        if vcf_prop_name in {VcfKeys.pos, VcfKeys.stop, VcfKeys.rlen}:
            field_type = VcfFieldTypes.integer
        elif vcf_prop_name in {VcfKeys.qual}:
            field_type = VcfFieldTypes.float
        elif vcf_prop_name in {VcfKeys.id, VcfKeys.chrom, Keys.contig, VcfKeys.alts, VcfKeys.alleles, VcfKeys.ref}:
            # note: pysam allows querying chrom as contig, so check for both here in case user overrides default
            # properties
            field_type = VcfFieldTypes.string
        else:
            raise ValueError(f"Unknown vcf property '{vcf_prop_name}'")

        if field_type == VcfFieldTypes.string:
            encode_dict = CategoryPropertyCollator.get_encode_dict(vcf_prop_name)

            def extractor(variant_record: pysam.VariantRecord) -> Optional[EncodedVcfField]:
                return CategoryPropertyCollator.encode(
                    getattr(variant_record, vcf_prop_name, None),
                    encode_dict
                )
        else:
            def extractor(variant_record: pysam.VariantRecord) -> Optional[EncodedVcfField]:
                return getattr(variant_record, vcf_prop_name, None)
    return extractor

def _is_location_column(
        column_name: Optional[str],
