def _is_called_where_not_ref(carrier_status: pandas.Series) -> pandas.Series:
    """ return Series containing only non-REF GTs, with bool values True if the GT is called, and False if no-call """
    # noinspection PyTypeChecker
    return (~carrier_status[carrier_status | carrier_status.isna()].isna()).rename(Keys.is_called)

def quantify_overlap_by_svtype(
        interval: interval_overlaps.Record,
        overlappers: pandas.DataFrame,
) -> Dict[str, float]:
    """
    Compute overlap statistics between test interval and supplied overlapping intervals.
    Consider multiple subsets of overlappers (these restrictions are combinitorial):
        -restricted to only called genotypes, and unrestricted by genotype
        -restricted to on specific SVTYPE, and unrestricted
    For each subset, call quantify_overlap() to get reciprocal_overlap, overlap_support, and inverse_distance

    Parameters
    ----------
    interval: interval_overlaps.Record
        Test interval to check for overlaps
    overlappers: pandas.DataFrame
        Table of overlapping intervals with columns {Keys.begin} and {Keys.end}. Overlap is presumed, not checked.
    Returns
    -------
    overlap_statistics: Dict[str, float]
        Dict with multiple statistics (three for each subset of overlappers):
            -reciprocal_overlap: maximum reciprocal overlap between interval and and overlapper
            -overlap_support: proportion of interval that is covered by any overlapper
            -inverse_distance: 1 / minimum distance from interval begin/end to overlapper begin/end
        Keys are of form {subset_name}_{stat_name}
    """
    # measure reciprocal overlap and overlap support
    # keep "called" and "all" versions of all stats (based on whether we allow overlaps with no-call variants)
    # if there are overlappers, break down stats by svtype
    called_overlappers = overlappers.loc[overlappers[Keys.is_called]]

    return {
        **{
            f"{prefix}_{k}": v
            for check_overlappers, prefix in zip((called_overlappers, overlappers),
                                                 (Keys.is_called, Keys.all_overlappers))
            for k, v in quantify_overlap(interval, check_overlappers).items()
        },
        **{
            f"{prefix}_{svtype}_{k}": v
            for check_overlappers, prefix in zip((called_overlappers, overlappers),
                                                 (Keys.is_called, Keys.all_overlappers))
            for svtype in check_overlappers[Keys.svtype].unique()
            for k, v in quantify_overlap(interval,
                                         check_overlappers.loc[check_overlappers[Keys.svtype] == svtype]).items()
        }
    }

def get_trios_overlap_info(
        overlap_stats: Dict[str, pandas.DataFrame],
        ped_files: Union[str, Iterable[str]]
) -> Tuple[Dict[str, pandas.DataFrame], ...]:
    """ Organize overlap info into trios, as specified by the supplied pedigree files """
    if isinstance(ped_files, str):
        ped_files = (ped_files,)

    return tuple(
        {
            Keys.father: overlap_stats[pedigree_line.father_id],
            Keys.mother: overlap_stats[pedigree_line.mother_id],
            Keys.child: overlap_stats[pedigree_line.proband_id]
        }
        for ped_file in ped_files
        for pedigree_line in pedigree_tools.PedigreeFileInfo(ped_file).pedigree_lines
        if not pedigree_line.any_unknown and all(
            sample_id in overlap_stats
            for sample_id in (pedigree_line.father_id, pedigree_line.mother_id, pedigree_line.proband_id)
        )
    )

def get_vapor_p_non_ref_old(vapor_variants: pandas.DataFrame) -> pandas.DataFrame:
    """ Given table of vapor data, return a one-column table of probabilities that each vapor variant is non-REF
     based on GQ """
    p_gt_bad = 10 ** -vapor_variants[Keys.gq]
    return pandas.DataFrame(
        numpy.where(
            vapor_variants[Keys.gt] == "0/0", p_gt_bad, 1.0 - p_gt_bad
        ),
        columns=[Keys.vapor_p_non_ref],
        index=vapor_variants.index
    )

def get_sv_selectors(
        all_sv_types: Set[str],
        bnd_types: Iterable[str] = interval_overlaps.Default.breakend_types,
        size_ranges: Mapping[str, Tuple[float, float]] = Default.sv_selector_size_ranges
) -> Dict[str, SvTypeCutoffSelector]:
    """
    Return Dict with key = SV category and value = SVTypeCutoffSelector (a function that selects only the variants from
    the desired category)
    """
    def _get_selector(_svtype: str, _low: float, _high: float) -> SvTypeCutoffSelector:
        return lambda info: (info[Keys.svtype] == _svtype) & (info[Keys.svlen] >= _low) & (info[Keys.svlen] < _high)

    # don't break down BNDs (and similar types) by size because it doesn't make sense to
    # don't break down INV by size because there are too few
    size_divided_types = all_sv_types.difference(bnd_types).difference({"INV"})
    return {
        **{
            Keys.bnd_types: lambda info: info[Keys.svtype].isin(bnd_types)
        },
        **{
            "INV": lambda info: info[Keys.svtype] == "INV"
        },
        **{
            f"{size_name} {svtype}": _get_selector(svtype, low, high)
            for svtype in size_divided_types for size_name, (low, high) in size_ranges.items()
        }
    }

def get_optimal_overlap_cutoffs(
        overlap_stats: Mapping[str, pandas.DataFrame],
        ped_files: Optional[Union[str, Iterable[str]]] = None,
        vapor_files: Optional[Dict[str, str]] = None,
        f_beta: float = Default.f_beta,
        min_overlap_cutoff_precision: float = Default.min_overlap_cutoff_precision,
        inheritance_af_rareness: float = Default.inheritance_af_rareness,
        bnd_types: Iterable[str] = interval_overlaps.Default.breakend_types,
        size_ranges: Mapping[str, Tuple[float, float]] = Default.sv_selector_size_ranges
) -> CutoffInfo:
    f"""
    Find optimal thresholds for declaring confident "good" or "bad" overlaps with truth data based on
        -Mendelian inheritance in trios    AND/OR
        -support in pacbio reads from VaPoR.
    Args:
        overlap_stats: Dict[str, pandas.DataFrame]
            Map from sample ID to table of overlap statistics (rows indexed by variant ID, columns by statistic)
        ped_files: Optional[Union[str, Iterable[str]]] = None
            Pedigree files with trios in overlap stats
        vapor_files: Optional[Dict[str, str]] = None
            Map from sample ID to vapor file (providing estimation of pacbio support for each short-read variant)
        f_beta: float = {Default.f_beta},
            Relative importance of recall, as compared to precision.
        min_overlap_cutoff_precision: float = {Default.min_overlap_cutoff_precision}
            Minimum allowed proportion of variants with overlap that will pass "good" or "bad" threshold that will be
            supported by inheritance or pacbio support. i.e. 1 - min_overlap_cutoff_precision are confident but wrong.
        inheritance_af_rareness: float = {Default.inheritance_af_rareness}
            Maximum allele frequency where inheritance will be assessed. i.e. if AF > inheritance_af_rareness, don't
            attempt to determine if a variant is mendelian, ignore it for the purposes of finding cutoffs.
        bnd_types: Iterable[str] {interval_overlaps.Default.breakend_types}
            SV types that are considered breakends.
        size_ranges: Mapping[str, Tuple[float, float]] {Default.sv_selector_size_ranges}
            Ranges of svlen to break SV types into
    Returns:
        optimal_overlap_cutoffs: CutoffInfo
            Mapping from SV category to SvTypeCutoffInfo (class holding info necessary to find confidently "good"/"bad"
            overlaps with truth data)
    """
    if ped_files is None:
        ped_files = ()
    elif isinstance(ped_files, str):
        ped_files = (ped_files,)
    if vapor_files is None:
        vapor_files = {}
    if not ped_files and not vapor_files:
        raise ValueError("Need one or more ped files and/or one or more vapor files to compute optimal overlaps")

    trios_overlap_info = tuple(
        {
            Keys.father: overlap_stats[pedigree_line.father_id],
            Keys.mother: overlap_stats[pedigree_line.mother_id],
            Keys.child: overlap_stats[pedigree_line.proband_id]
        }
        for pedigree_line in pedigree_tools.PedigreeFileInfo.load(pedigree_files=ped_files).pedigree_lines
        if not pedigree_line.any_unknown and all(
            sample_id in overlap_stats
            for sample_id in (pedigree_line.father_id, pedigree_line.mother_id, pedigree_line.proband_id)
        )
    )
    print(f"Found {len(trios_overlap_info)} trios")

    # augment overlap stats with probability the variant is non-ref, as estimated by VaPoR:
    vapor_info = {
        sample_id:
            get_vapor_p_non_ref(genomics_io.vapor_to_pandas(vapor_file))
            .join(overlap_stats[sample_id], how="inner")
        for sample_id, vapor_file in vapor_files.items()
        if sample_id in overlap_stats
    }
    print(f"Got {len(vapor_info)} vapor samples")
    if not trios_overlap_info and not vapor_info:
        raise ValueError("No trios from ped files or vapor files were present in the overlap info")

    all_sv_types = set(
        svtype
        for sample_overlap_stats in overlap_stats.values()
        for svtype in sample_overlap_stats[Keys.svtype].unique()
    )
    sv_selectors = get_sv_selectors(all_sv_types=all_sv_types, bnd_types=bnd_types, size_ranges=size_ranges)

    def _get_optimal_cutoff(_cutoffs: List[SvTypeCutoffInfo], _good: bool) -> SvTypeCutoffInfo:
        def _precision(_cutoff: SvTypeCutoffInfo) -> float:
            return _cutoff.precision_good if _good else _cutoff.precision_bad

        def _fscore(_cutoff: SvTypeCutoffInfo) -> float:
            return _cutoff.f_score_good if _good else _cutoff.f_score_bad

        def _cutoff_sort_key(_cutoff: SvTypeCutoffInfo) -> float:
            # choose in priority:
            #  a) if anything meets the precision goal, whatever has the highest f-score
            #  b) otherwise, whatever has the highest precision
            return min_overlap_cutoff_precision + (1.0 - min_overlap_cutoff_precision) * _fscore(_cutoff) \
                if _precision(_cutoff) >= min_overlap_cutoff_precision \
                else _precision(_cutoff)

        _cutoffs.sort(key=_cutoff_sort_key)
        return _cutoffs[-1]

    def _remove_called_status(_stat: str) -> str:
        return '_'.join(_stat.split(f"_{Keys.is_called}_", 1)) if f"_{Keys.is_called}_" in _stat else \
            '_'.join(_stat.split(f"_{Keys.all_overlappers}_", 1)) if f"_{Keys.all_overlappers}_" in _stat \
            else _stat

    # get all the stats that could be used for overlap thresholds
    all_stats = set.union(
        *(set(sample_overlap_stats.columns) for sample_overlap_stats in overlap_stats.values())
    ).difference({Keys.svtype, Keys.svlen, Keys.allele_frequency})
    # we want to use called variants for good overlaps (confident there is an overlapper) and any non-ref for bad
    # overlaps (confident there's no overlapper). So loop through and link them together
    all_stats_linked = {}
    for stat in all_stats:
        base_stat = _remove_called_status(stat)
        if Keys.is_called in stat:
            all_stats_linked[base_stat] = (stat, ) + all_stats_linked.get(base_stat, (None, None))[1:]
        else:
            all_stats_linked[base_stat] = all_stats_linked.get(base_stat, (None, None))[:1] + (stat,)
    overlap_cutoffs = {}
    for selector_name, selector in sv_selectors.items():
        stats_overlap_cutoff_info = [
            _get_stat_optimal_overlap_cutoffs(
                trios_overlap_info, vapor_info, selector, stat_good, stat_bad, f_beta=f_beta,
                min_overlap_cutoff_precision=min_overlap_cutoff_precision,
                inheritance_af_rareness=inheritance_af_rareness
            )
            for (stat_good, stat_bad) in all_stats_linked.values()
        ]
        n_good = next((c_i.num_good for c_i in stats_overlap_cutoff_info if c_i.num_good > 0), 0)
        n_bad = next((c_i.num_bad for c_i in stats_overlap_cutoff_info if c_i.num_bad > 0), 0)
        print(f"{selector_name}: {n_good} good, {n_bad} bad")
        for c_i in stats_overlap_cutoff_info:
            print(f"\t{c_i.stat_good}: good_c={c_i.cutoff_good:.3g}, f={c_i.f_score_good:.3g},"
                  f" prec={c_i.precision_good:.3g}; bad_c={c_i.cutoff_bad:.3g}, f={c_i.f_score_bad:.3g},"
                  f" prec={c_i.precision_bad:.3g}")

        good_cutoff_stats = _get_optimal_cutoff(stats_overlap_cutoff_info, _good=True)
        bad_cutoff_stats = _get_optimal_cutoff(stats_overlap_cutoff_info, _good=False)
        if good_cutoff_stats.f_score_good == 0 and bad_cutoff_stats.f_score_bad == 0:
            # no power, don't bother using this selector
            continue
        overlap_cutoffs[selector_name] = SvTypeCutoffInfo(
            selector=selector,
            stat_good=good_cutoff_stats.stat_good, num_good=good_cutoff_stats.num_good,
            cutoff_good=good_cutoff_stats.cutoff_good, f_score_good=good_cutoff_stats.f_score_good,
            precision_good=good_cutoff_stats.precision_good,
            stat_bad=bad_cutoff_stats.stat_bad, num_bad=bad_cutoff_stats.num_bad,
            cutoff_bad=bad_cutoff_stats.cutoff_bad, f_score_bad=bad_cutoff_stats.f_score_bad,
            precision_bad=bad_cutoff_stats.precision_bad
        )

    return overlap_cutoffs

def load_optimal_overlap_cutoffs(optimal_overlap_cutoffs_file: str) -> CutoffInfo:
    """ Load optimal cutoffs object by unpickling it (with dill module, so it's possible to pickle functions) """
    with open(optimal_overlap_cutoffs_file, "rb") as f_in:
        return dill.load(f_in)

def display_optimal_overlap_cutoffs(optimal_overlap_cutoffs: CutoffInfo):
    """ Display optimal cutoffs in relatively human-readable format """
    for sv_category, sv_cutoff in optimal_overlap_cutoffs.items():
        print(f"{sv_category}: {sv_cutoff}")

def reconcile_confident_variants(
        overlap_variants: Optional[SampleConfidentVariants],
        vapor_variants: Optional[SampleConfidentVariants]
) -> SampleConfidentVariants:
    """ Given confident variants obtained by VaPoR and overlaps, reconcile any differences by favoring VaPoR """
    if overlap_variants is None:
        return vapor_variants
    elif vapor_variants is None:
        return overlap_variants
    else:
        # return union of both methods, but when there are disagreements, prefer VaPoR
        return SampleConfidentVariants(
            good_variant_ids=sorted(
                set(overlap_variants.good_variant_ids)
                .difference(vapor_variants.bad_variant_ids)
                .union(vapor_variants.good_variant_ids)
            ),
            bad_variant_ids=sorted(
                set(overlap_variants.bad_variant_ids)
                .difference(vapor_variants.good_variant_ids)
                .union(vapor_variants.bad_variant_ids)
            )
        )

def output_confident_variants(
        overlap_info: ConfidentVariants,
        output_file: str
):
    """ Output the confident variants, either to a json file or stdout """
    if output_file == '-':
        json.dump(overlap_info, sys.stdout, indent=2, default=lambda x: x.__dict__)
        sys.stdout.flush()
    else:
        _log(f"Saving overlaps to {output_file} ...", end='')
        with open(output_file, 'w') as f_out:
            json.dump(overlap_info, f_out, default=lambda x: x.__dict__)
        _log(" okay")

def _is_file(filename: Optional[str]) -> bool:
    """ return boolean if the file path is a real file on the system """
    return filename is not None and os.path.isfile(filename)

def get_vapor_files(vapor_json: Optional[str]) -> Optional[Dict[str, str]]:
    """ Load map from sample ID to corresponding vapor file, from input JSON """
    if vapor_json is None:
        return None
    if not os.path.isfile(vapor_json):
        raise ValueError(f"vapor json ({vapor_json}) is not a path to a valid file")
    with open(vapor_json, 'r') as f_in:
        vapor_files = json.load(f_in)
    for sample_id, vapor_file in vapor_files.items():
        if not isinstance(sample_id, str) or not isinstance(vapor_file, str) or not os.path.isfile(vapor_file):
            raise ValueError(f"vapor_json ({vapor_json}) must consist of sample_id, VaPoR file pairs. Error with pair "
                             f"{sample_id}, {vapor_file}")
    return vapor_files

def _is_not_missing(series: pandas.Series, missing_value: str) -> numpy.ndarray:
    """
    return numpy array of bools that corresponds to whether each element of series is present (True) or missing (False)
    """
    return numpy.logical_not(genomics_io.is_missing(series, missing_value=missing_value))

def _check_valid_locations(
        variants: pandas.DataFrame,
        non_null_columns: Iterable[str] = (Keys.begin, Keys.end, Keys.contig, Keys.svtype, Keys.svlen)
):
    """ Validate that variants table has all required fields defined with no missing values """
    for column in non_null_columns:
        if column not in variants:
            raise ValueError(f"{column} not in variants")
        if variants[column].hasnans:
            raise ValueError(f"{column} has missing values")

def _get_overlapper_coverage(other_intervals: pandas.DataFrame, component: pandas.DataFrame) -> float:
    """ Estimate the average depth of coverage that other_intervals have over the connected component """
    if len(other_intervals) == 0:
        return 0.0
    component_begin = component[Keys.begin].values[0]
    component_end = component[Keys.end].values[-1]
    other_overlap = numpy.nonzero(
        numpy.logical_and(
            other_intervals[Keys.end].values > component_begin,
            other_intervals[Keys.begin].values < component_end
        )
    )[0]
    if other_overlap.size == 0:
        return 0.0
    # note: other intervals are sorted by (begin, end). no guarantee on where max end is
    other_begin = numpy.maximum(other_intervals[Keys.begin].values.take(other_overlap), component_begin)
    other_end = numpy.minimum(other_intervals[Keys.end].values.take(other_overlap), component_end)
    return (other_end - other_begin).astype(numpy.uint64).sum() / max(float(component_end - component_begin), 1.0)

def _iter_sample_splits(
        sample_ids: numpy.ndarray,
        pedigree_file_info: Optional[pedigree_tools.PedigreeFileInfo] = None,
        truth_samples: Optional[Collection[str]] = None,
        num_splits: int = Default.num_splits
) -> Iterator[Tuple[numpy.ndarray, numpy.ndarray]]:
    """
    Divide up samples into num_splits batches, trying to keep trios and truth samples evenly divided
    Args:
        sample_ids:
        pedigree_file_info:
        truth_samples:
        num_splits:

    Returns:

    """
    sample_order = {
        sample_id: index for index, sample_id in enumerate(sample_ids)
    }
    truth_samples = {} if truth_samples is None else set(truth_samples)
    # get tuple of sample_ids in complete trio structures, don't break up families if they exist (e.g. quads)

    family_sample_ids = [] if pedigree_file_info is None else [
        family_participant_ids
        for __, family_participant_ids in
        pedigree_file_info.subset_participants(sample_ids).iter_family_participant_ids()
    ]

    isolated_sample_ids = set(sample_ids).difference(sample_id for family in family_sample_ids for sample_id in family)
    isolated_truth_samples = truth_samples.intersection(isolated_sample_ids)
    isolated_non_truth_samples = isolated_sample_ids.difference(isolated_truth_samples)
    truth_family_sample_ids = [
        family for family in family_sample_ids if any(sample_id in truth_samples for sample_id in family)
    ]
    non_truth_family_sample_ids = [
        family for family in family_sample_ids if not any(sample_id in truth_samples for sample_id in family)
    ]
    # now evenly divy up into batches, in order of decreasing desirability
    # 1) truth_family_sample_ids (samples in trios with truth information)
    # 2) non_truth_family_sample_ids (samples in trios with no truth information)
    # 3) isolated_truth_samples (samples not in a trio that have truth information)
    # 4) isolated_non_truth_samples (samples not in a trio with no truth information)
    batches = [set() for _ in range(num_splits)]
    if truth_family_sample_ids:
        for batch_ind, batch in enumerate(batches):
            batch.update(_divy_family_samples(truth_family_sample_ids, batch_ind, num_splits))
    if non_truth_family_sample_ids:
        for batch_ind, batch in enumerate(batches):
            batch.update(_divy_family_samples(non_truth_family_sample_ids, batch_ind, num_splits))
    if isolated_truth_samples:
        for batch_ind, batch in enumerate(batches):
            batch.update(_divy_isolated_samples(isolated_truth_samples, batch_ind, num_splits))
    if isolated_non_truth_samples:
        for batch_ind, batch in enumerate(batches):
            batch.update(_divy_isolated_samples(isolated_non_truth_samples, batch_ind, num_splits))

    # Each batch serves as a test set. For each test set, glue other batches into a training set
    for batch_ind, test_batch in enumerate(batches):
        training_batch = {
            sample_id
            for batch in (batches[:batch_ind] + batches[batch_ind + 1:])
            for sample_id in batch
        }

        # yield the samples in the same order as the original VCF, in case that somehow matters
        yield sample_ids.take(sorted(sample_order[sample_id] for sample_id in training_batch)), \
            sample_ids.take(sorted(sample_order[sample_id] for sample_id in test_batch))

def make_cross_validation_vcfs(
        vcf: Text,
        ped_file: Optional[Text] = None,
        truth_samples_file: Optional[Text] = None,
        output_folder: str = Default.output_folder,
        num_splits: int = Default.num_splits,
        index_output_vcf: bool = Default.index_output_vcf,
        num_threads: int = Default.num_threads
) -> Tuple[Tuple[str, str], ...]:
    pedigree_file_info = None if ped_file is None else pedigree_tools.PedigreeFileInfo.load(ped_file)
    if truth_samples_file is None:
        truth_samples = {}
    else:
        with open(truth_samples_file, 'r') as f_in:
            truth_samples = {line.strip() for line in f_in}
    sample_ids = numpy.array(genomics_io.get_vcf_sample_ids(vcf))
    return tuple(
        (
            subsample_vcf(vcf, train_sample_ids, out_vcf=os.path.join(output_folder, f"train_{split_ind}.vcf.gz"),
                          index_output_vcf=index_output_vcf, num_threads=num_threads),
            subsample_vcf(vcf, test_sample_ids, out_vcf=os.path.join(output_folder, f"test_{split_ind}.vcf.gz"),
                          index_output_vcf=index_output_vcf, num_threads=num_threads)
        )
        for split_ind, (train_sample_ids, test_sample_ids) in enumerate(
            _iter_sample_splits(sample_ids, pedigree_file_info=pedigree_file_info, truth_samples=truth_samples,
                                num_splits=num_splits)
        )
    )

def next_fig() -> int:
    """
    Get appropriate handle for next figure
    """
    fignums = pyplot.get_fignums()
    if fignums:
        fignums = sorted(fignums)
        n_figs = len(fignums)
        if fignums[-1] == n_figs:
            next_num = n_figs + 1
        else:
            next_num = -1
            for n, fignum in enumerate(fignums, start=1):
                if fignum > n:
                    next_num = n
                    break
            if next_num <= 0:
                raise RuntimeError("Unable to find next figure number")
    else:
        next_num = 1
    return next_num

def ordered_legend(ax: pyplot.Axes, labels_in_order: Sequence, **legend_kwargs) -> matplotlib.legend.Legend:
    """ get legend, specifying the order of the labels """
    handles, labels = ax.get_legend_handles_labels()
    # sort both labels and handles by labels
    labels, handles = zip(*sorted(zip(labels, handles), key=lambda t: labels_in_order.index(t[0])))
    return ax.legend(handles, labels, **legend_kwargs)

def barh(ax, x_baseline, edges, values, **kwargs):
    y_low = edges[0]
    for value, y_high in zip(values, edges[1:]):
        # rectangle(ax, [x_baseline, x_baseline + value], [edges[0], edges[1]])
        if numpy.isfinite(value):
            ax.add_patch(
                patches.Rectangle(
                    (x_baseline, y_low), value, y_high - y_low, **kwargs
                )
            )
        y_low = y_high

def add_colorbar(mappable, cax=None):
    ax = mappable.axes
    fig = ax.figure
    if cax is None:
        divider = make_axes_locatable(ax)
        cax = divider.append_axes("right", size="5%", pad=0.05)
    return fig.colorbar(mappable, cax=cax)

def same_color_range(*mappables):
    vmin = min(m.get_clim()[0] for m in mappables)
    vmax = max(m.get_clim()[1] for m in mappables)
    for m in mappables:
        m.set_clim(vmin, vmax)

def hist1d(ax, x, bins=Default.num_1d_bins, xlabel="x", ylabel="counts", xscale=None, yscale="log", title=None,
           tick_labelrotation=Default.tick_labelrotation,
           x_is_good=None, x_max_left=numpy.inf, x_min_right=-numpy.inf, min_width=Default.min_1d_hist_width,
           histtype="stepfilled", orientation="vertical",
           title_fontsize=Default.title_fontsize, label_fontsize=Default.label_fontsize, **kwargs):
    if orientation == "horizontal":
        xlabel, ylabel = ylabel, xlabel
        xscale, yscale = yscale, xscale
    if isinstance(bins, int):
        num_bins = bins
        x_min = min(x.min(), x_max_left)
        x_max = max(x.max(), x_min_right)
        if x_max - x_min < min_width:
            x_min -= min_width / 2
            x_max += min_width / 2
        bins = numpy.linspace(x_min, x_max, num=num_bins + 1)
    # bins = "auto"
    if x_is_good is None:
        good_x = x
        bad_x = None
    else:
        good_x = x.compress(x_is_good)
        bad_x = x.compress(numpy.logical_not(x_is_good))

    bin_counts, bins, hist_patches = ax.hist(
        good_x, bins=bins, histtype=histtype, edgecolor='g', facecolor='g', orientation=orientation, **kwargs
    )
    if bad_x is not None:
        ax.hist(bad_x, bins=bins, histtype=histtype, edgecolor='r', facecolor='r', alpha=0.75,
                orientation=orientation, **kwargs)

    ax.tick_params(axis='x', labelrotation=tick_labelrotation)
    ax.autoscale(enable=True, tight=True)
    if xscale is not None:
        ax.set_xscale(xscale)
    if yscale is not None:
        ax.set_yscale(yscale)
    if title is not None:
        ax.set_title(title, fontsize=title_fontsize)
    if xlabel is not None:
        ax.set_xlabel(xlabel, fontsize=label_fontsize)
    if ylabel is not None:
        ax.set_ylabel(ylabel, fontsize=label_fontsize)

    return bin_counts, bins, hist_patches

def _fast_hist2d(
        x: numpy.ndarray,
        y: numpy.ndarray,
        x_edges: numpy.ndarray,
        y_edges: numpy.ndarray
):
    num_x_bins = len(x_edges) - 1
    num_y_bins = len(y_edges) - 1
    max_ravel_bin = num_x_bins * num_y_bins - 1
    bin_type = numpy.min_scalar_type(max_ravel_bin)
    eps = 0 if numpy.issubdtype(x.dtype, numpy.integer) \
        else numpy.finfo(x.dtype).resolution

    def _avg_diff(_edges) -> float:
        return (_edges[-1] - _edges[0]) / (len(_edges) - 1)

    def _is_uniform_spaced(_edges: numpy.ndarray) -> bool:
        return numpy.allclose(_avg_diff(_edges), numpy.diff(_edges))

    def _get_bin_indices(_values: numpy.ndarray, _edges: numpy.ndarray) -> numpy.ndarray:
        """ Get indices corresponding to regularly-spaced bins """
        # pad bins with eps to avoid rounding errors leading to invalid bin assignments (<=0 or >=num_bins)
        _delta = 2 * eps + _avg_diff(_edges)
        _base = _edges[0] - eps
        return numpy.floor(
            (_values - _base) / _delta
        ).astype(bin_type)

    def _get_ravel_indices():
        # want to flip y and rotate 90 at *THIS* stage so we don't have to do that operation to hist_mat
        return _get_bin_indices(x, x_edges) + num_x_bins * _get_bin_indices(y, y_edges)

    if _is_uniform_spaced(x_edges) and _is_uniform_spaced(y_edges):
        # can do faster 2d histogram
        ravel_indices = _get_ravel_indices()
        bin_counts = numpy.bincount(ravel_indices)
        hist_mat = numpy.zeros((num_x_bins, num_y_bins), dtype=bin_type)
        hist_mat.ravel()[:len(bin_counts)] = bin_counts
    else:
        # have to do it slowly
        hist_mat, x_edges, y_edges = numpy.histogram2d(x, y, bins=[x_edges, y_edges], density=False)
        # rotate and flip hist_mat
        hist_mat = numpy.flipud(numpy.rot90(hist_mat))
    return hist_mat, x_edges, y_edges

def _sync_x(self, event):
    """ Event handler for updates to x axis: set x axis to desired limits """
    self.set_xlim(event.get_xlim(), emit=False)

def _sync_y(self, event):
    """ Event handler for updates to y axis: set y axis to desired limits """
    self.set_ylim(event.get_ylim(), emit=False)

def sync_axes(axes: Sequence[pyplot.Axes], sync_x: bool = False, sync_y: bool = False, zoom_to_fit_all: bool = False):
    if not (sync_x or sync_y):
        return

    ax0 = axes[0]
    if zoom_to_fit_all:
        if sync_x:
            xlim = ax0.get_xlim()
            for ax2 in axes[1:]:
                xlim2 = ax2.get_xlim()
                xlim = (min(xlim[0], xlim2[0]), max(xlim[1], xlim2[1]))
            for ax in axes:
                ax.set_xlim(*xlim)
        if sync_y:
            ylim = ax0.get_ylim()
            for ax2 in axes[1:]:
                ylim2 = ax2.get_ylim()
                ylim = (min(ylim[0], ylim2[0]), max(ylim[1], ylim2[1]))
            for ax in axes:
                ax.set_ylim(*ylim)

    for ax in axes:
        if sync_x:
            ax.update_xlim = MethodType(_sync_x, ax)
        if sync_y:
            ax.update_ylim = MethodType(_sync_x, ax)

    for ax2 in axes[1:]:
        if sync_x:
            ax0.callbacks.connect("xlim_changed", ax2.update_xlim)
            ax2.callbacks.connect("xlim_changed", ax0.update_xlim)
        if sync_y:
            ax0.callbacks.connect("ylim_changed", ax2.update_ylim)
            ax2.callbacks.connect("ylim_changed", ax0.update_ylim)

def get_confident_variants_vapor(vapor_files: Optional[Dict[str, str]],
                                 precision: float,
                                 valid_variant_ids: set) -> get_truth_overlap.ConfidentVariants:
    vapor_info = {
        sample_id:
            get_truth_overlap.select_confident_vapor_variants(vapor_file=vapor_file,
                                                              valid_variant_ids=valid_variant_ids,
                                                              precision=precision)
        for sample_id, vapor_file in vapor_files.items()
    }
    return vapor_info

def read_list_file(path: str) -> Iterable[str]:
    with open(path, 'r') as f:
        items = [line for line in f.read().splitlines() if line]
    if len(items) == 0:
        raise ValueError("list empty")
    return items

def get_size_bin(svlen):
    if svlen > SIZE_BINS[0] and svlen < SIZE_BINS[1]:
        return "SMALL"
    elif svlen < SIZE_BINS[2]:
        return "MED"
    else:
        return "LARGE"

def increment_counts(record, counts_by_svtype, counts_by_svtype_size_bin):
    svtype = record.info['SVTYPE']
    svlen = record.info['SVLEN']
    size_bin = get_size_bin(svlen)
    if svtype in counts_by_svtype:
        counts_by_svtype[svtype] = counts_by_svtype[svtype] + 1
    else:
        counts_by_svtype[svtype] = 1
    type_bin_label = svtype + "_" + size_bin
    if type_bin_label in counts_by_svtype_size_bin:
        counts_by_svtype_size_bin[type_bin_label] = counts_by_svtype_size_bin[type_bin_label] + 1
    else:
        counts_by_svtype_size_bin[type_bin_label] = 1

def main(argv: Optional[List[Text]] = None) -> get_truth_overlap.ConfidentVariants:
    arguments = __parse_arguments(sys.argv if argv is None else argv)

    if arguments.irs_contigs_file is not None:
        irs_contigs = frozenset([line.split("\t")[0] for line in read_list_file(arguments.irs_contigs_file)])
    else:
        irs_contigs = None

    vapor_files = get_truth_overlap.get_vapor_files(arguments.vapor_json)
    vapor_variants = {sample: genomics_io.vapor_to_pandas(vapor_files[sample]) for sample in vapor_files}
    for sample in vapor_variants:
        variants_df = vapor_variants[sample]
        p_non_ref_old = get_truth_overlap.get_vapor_p_non_ref_old(variants_df)
        p_non_ref_genotyped = get_truth_overlap.get_vapor_p_non_ref(variants_df)
        p_non_ref_read_threshold = \
            get_truth_overlap.get_vapor_p_non_ref_threshold(variants_df, arguments.vapor_read_support_pos_thresh)
        variants_df['p_non_ref_old'] = p_non_ref_old['p_non_ref']
        variants_df['p_non_ref_genotyped'] = p_non_ref_genotyped['p_non_ref']
        variants_df['p_non_ref_read_threshold'] = p_non_ref_read_threshold['p_non_ref']

    if arguments.irs_sample_batch_lists is not None:
        sample_list_file_to_report_file_mapping = zip(read_list_file(arguments.irs_sample_batch_lists),
                                                      read_list_file(arguments.irs_test_report_list))
    else:
        sample_list_file_to_report_file_mapping = {}

    sample_to_irs_report = {}
    for sample_list_file_report_pair in sample_list_file_to_report_file_mapping:
        sample_list = read_list_file(sample_list_file_report_pair[0])
        report = load_irs_test_report(sample_list_file_report_pair[1])
        for sample in sample_list:
            sample_to_irs_report[sample] = report

    vapor_valid_variants = 0
    irs_valid_variants = 0

    vapor_valid_variants_by_svtype = {}
    irs_valid_variants_by_svtype = {}

    vapor_tested_var_gts = 0
    irs_tested_var_gts = 0
    vapor_gq_supported_var_gts = 0
    vapor_gt_supported_var_gts = 0
    vapor_read_supported_var_gts = 0
    irs_supported_var_gts = 0

    vapor_tested_counts_by_svtype = {}
    vapor_tested_counts_by_svtype_size_bin = {}

    vapor_gq_supported_counts_by_svtype = {}
    vapor_gq_supported_counts_by_svtype_size_bin = {}

    vapor_gt_supported_counts_by_svtype = {}
    vapor_gt_supported_counts_by_svtype_size_bin = {}

    vapor_reads_supported_counts_by_svtype = {}
    vapor_reads_supported_counts_by_svtype_size_bin = {}

    irs_tested_counts_by_svtype = {}
    irs_tested_counts_by_svtype_size_bin = {}

    irs_supported_counts_by_svtype = {}
    irs_supported_counts_by_svtype_size_bin = {}

    with VariantFile(arguments.vcf) as vcf, \
            open(arguments.output_summary, 'w') as out_summary:
        if arguments.output_detail is not None:
            out_detail = gzip.open(arguments.output_detail, 'wt')
            out_detail.write("SVID\tSAMPLE\tSVTYPE\tSVLEN\tCALLED_GT\tCALLED_GQ\tVAPOR_SUPPORT_GT\tVAPOR_SUPPORT_GQ\t"
                             "VAPOR_SUPPORT_READS\tIRS_PVALUE\n")
        else:
            out_detail = None

        for record in vcf:
            svtype = record.info['SVTYPE']
            vapor_valid = False
            irs_valid = False
            if not (svtype == 'DEL' or svtype == 'DUP') or record.info['SVLEN'] <= arguments.vapor_max_cnv_size:
                vapor_valid = True
                vapor_valid_variants = vapor_valid_variants + 1
                if svtype in vapor_valid_variants_by_svtype:
                    vapor_valid_variants_by_svtype[svtype] = vapor_valid_variants_by_svtype[svtype] + 1
                else:
                    vapor_valid_variants_by_svtype[svtype] = 1
            if (svtype == 'DEL' or svtype == 'DUP') and record.info['SVLEN'] >= arguments.irs_min_cnv_size \
                    and (irs_contigs is None or record.contig in irs_contigs):
                irs_valid = True
                irs_valid_variants = irs_valid_variants + 1
                if svtype in irs_valid_variants_by_svtype:
                    irs_valid_variants_by_svtype[svtype] = irs_valid_variants_by_svtype[svtype] + 1
                else:
                    irs_valid_variants_by_svtype[svtype] = 1
            if vapor_valid or irs_valid:
                for sample in get_called_samples(record):
                    vapor_support = False
                    vapor_support_gt = 'NA'
                    vapor_support_gq = 'NA'
                    vapor_support_reads = 'NA'
                    if vapor_valid and sample in vapor_variants:
                        if record.id in vapor_variants[sample].index:
                            vapor_rec = vapor_variants[sample].loc[record.id]
                            vapor_tested_var_gts = vapor_tested_var_gts + 1
                            increment_counts(record, vapor_tested_counts_by_svtype, vapor_tested_counts_by_svtype_size_bin)
                            vapor_support_old = vapor_rec['p_non_ref_old'] > 1 - arguments.vapor_min_precision
                            vapor_support_genotyped = vapor_rec['p_non_ref_genotyped'] > 1 - arguments.vapor_min_precision
                            vapor_support_read_threshold = vapor_rec['p_non_ref_read_threshold'] > 1 - arguments.vapor_min_precision
                            vapor_support = vapor_support_old or vapor_support_genotyped or vapor_support_read_threshold
                            if vapor_support:
                                vapor_support_gt = vapor_rec[genomics_io.Keys.gt]
                                vapor_support_gq = vapor_rec[genomics_io.Keys.gq]
                                vapor_support_reads = vapor_rec[genomics_io.Keys.vapor_read_scores]
                                if vapor_support_old:
                                    vapor_gq_supported_var_gts = vapor_gq_supported_var_gts + 1
                                    increment_counts(record, vapor_gq_supported_counts_by_svtype, vapor_gq_supported_counts_by_svtype_size_bin)
                                if vapor_support_genotyped:
                                    vapor_gt_supported_var_gts = vapor_gt_supported_var_gts + 1
                                    increment_counts(record, vapor_gt_supported_counts_by_svtype, vapor_gt_supported_counts_by_svtype_size_bin)
                                if vapor_support_read_threshold:
                                    vapor_read_supported_var_gts = vapor_read_supported_var_gts + 1
                                    increment_counts(record, vapor_reads_supported_counts_by_svtype, vapor_reads_supported_counts_by_svtype_size_bin)

                    irs_support = False
                    irs_support_pval = 'NA'
                    if irs_valid and sample in sample_to_irs_report:
                        irs_data = sample_to_irs_report[sample]
                        if record.id in irs_data.index:
                            irs_tested_var_gts = irs_tested_var_gts + 1
                            increment_counts(record, irs_tested_counts_by_svtype, irs_tested_counts_by_svtype_size_bin)
                            irs_rec = irs_data.loc[record.id]
                            irs_support = irs_rec['NPROBES'] >= arguments.irs_min_probes and irs_rec[
                                "PVALUE"] <= arguments.irs_good_pvalue_threshold
                            if irs_support:
                                irs_support_pval = irs_rec['PVALUE']
                                irs_supported_var_gts = irs_supported_var_gts + 1
                                increment_counts(record, irs_supported_counts_by_svtype,
                                                 irs_supported_counts_by_svtype_size_bin)

                    if out_detail is not None and (vapor_support or irs_support):
                        out_detail.write("{}\t{}\t{}\t{}\t{}/{}\t{}\t{}\t{}\t{}\t{}\n"
                                         .format(record.id,
                                                 sample,
                                                 record.info['SVTYPE'],
                                                 record.info['SVLEN'],
                                                 record.samples[sample].get('GT', ['N/A', 'N/A'])[0],
                                                 record.samples[sample].get('GT', ['N/A', 'N/A'])[1],
                                                 record.samples[sample].get('GQ', 'N/A'),
                                                 vapor_support_gt,
                                                 vapor_support_gq,
                                                 vapor_support_reads,
                                                 irs_support_pval)
                                         )
        out_summary.write("#Vapor valid variants: {} {}\n#IRS valid variants: {} {}\n"
                          .format(vapor_valid_variants,
                                  vapor_valid_variants_by_svtype,
                                  irs_valid_variants,
                                  irs_valid_variants_by_svtype)
                          )
        out_summary.write("CATEGORY\tCOUNT_VAPOR_TESTED_GTS\tCOUNT_VAPOR_GQ_SUPPORTED_GTS\t"
                          "COUNT_VAPOR_GT_SUPPORTED_GTS\tCOUNT_VAPOR_READ_SUPPORTED_GTS\tCOUNT_IRS_TESTED_GTS\t"
                          "COUNT_IRS_SUPPORTED_GTS\n")
        out_summary.write("{}\t{}\t{}\t{}\t{}\t{}\t{}\n"
                          .format("ALL",
                                  vapor_tested_var_gts,
                                  vapor_gq_supported_var_gts,
                                  vapor_gt_supported_var_gts,
                                  vapor_read_supported_var_gts,
                                  irs_tested_var_gts,
                                  irs_supported_var_gts)
                          )
        for svtype in sorted(set(vapor_tested_counts_by_svtype.keys()).union(set(irs_tested_counts_by_svtype.keys()))):
            if svtype in vapor_tested_counts_by_svtype:
                vapor_tested_count = vapor_tested_counts_by_svtype[svtype]
                if svtype in vapor_gq_supported_counts_by_svtype:
                    vapor_gq_supported_count = vapor_gq_supported_counts_by_svtype[svtype]
                else:
                    vapor_gq_supported_count = 0
                if svtype in vapor_gt_supported_counts_by_svtype:
                    vapor_gt_supported_count = vapor_gt_supported_counts_by_svtype[svtype]
                else:
                    vapor_gt_supported_count = 0
                if svtype in vapor_reads_supported_counts_by_svtype:
                    vapor_reads_supported_count = vapor_reads_supported_counts_by_svtype[svtype]
                else:
                    vapor_reads_supported_count = 0
            else:
                vapor_tested_count = 0
                vapor_gq_supported_count = 0
                vapor_gt_supported_count = 0
                vapor_reads_supported_count = 0
            if svtype in irs_tested_counts_by_svtype:
                irs_tested_count = irs_tested_counts_by_svtype[svtype]
                if svtype in irs_supported_counts_by_svtype:
                    irs_supported_count = irs_supported_counts_by_svtype[svtype]
                else:
                    irs_supported_count = 0
            else:
                irs_tested_count = 0
                irs_supported_count = 0
            out_summary.write("{}\t{}\t{}\t{}\t{}\t{}\t{}\n"
                              .format(svtype,
                                      vapor_tested_count,
                                      vapor_gq_supported_count,
                                      vapor_gt_supported_count,
                                      vapor_reads_supported_count,
                                      irs_tested_count,
                                      irs_supported_count)
                              )
            for size_bin in SIZE_BIN_LABELS:
                svtype_bin = svtype + "_" + size_bin
                if svtype_bin in vapor_tested_counts_by_svtype_size_bin \
                        or svtype_bin in irs_tested_counts_by_svtype_size_bin:
                    if svtype_bin in vapor_tested_counts_by_svtype_size_bin:
                        vapor_tested = vapor_tested_counts_by_svtype_size_bin[svtype_bin]
                        if svtype_bin in vapor_gq_supported_counts_by_svtype_size_bin:
                            vapor_gq_supported = vapor_gq_supported_counts_by_svtype_size_bin[svtype_bin]
                        else:
                            vapor_gq_supported = 0
                        if svtype_bin in vapor_gt_supported_counts_by_svtype_size_bin:
                            vapor_gt_supported = vapor_gt_supported_counts_by_svtype_size_bin[svtype_bin]
                        else:
                            vapor_gt_supported = 0
                        if svtype_bin in vapor_reads_supported_counts_by_svtype_size_bin:
                            vapor_reads_supported = vapor_reads_supported_counts_by_svtype_size_bin[svtype_bin]
                        else:
                            vapor_reads_supported = 0

                    else:
                        vapor_tested = 0
                        vapor_gq_supported = 0
                        vapor_gt_supported = 0
                        vapor_reads_supported = 0

                    if svtype_bin in irs_tested_counts_by_svtype_size_bin:
                        irs_tested = irs_tested_counts_by_svtype_size_bin[svtype_bin]
                        if svtype_bin in irs_supported_counts_by_svtype_size_bin:
                            irs_supported = irs_supported_counts_by_svtype_size_bin[svtype_bin]
                        else:
                            irs_supported = 0
                    else:
                        irs_tested = 0
                        irs_supported = 0

                    out_summary.write("{}\t{}\t{}\t{}\t{}\t{}\t{}\n"
                                      .format(svtype_bin,
                                              vapor_tested,
                                              vapor_gq_supported,
                                              vapor_gt_supported,
                                              vapor_reads_supported,
                                              irs_tested,
                                              irs_supported)
                                      )
        if out_detail is not None:
            out_detail.close()

def assert_indices_equal(i1: pandas.Index, i2: pandas.Index, context: str):
    assert numpy.array_equal(i1.isnull(), i2.isnull()), f"{context}: index null values not equal"
    assert numpy.array_equal(i1[~i1.isnull()], i2[~i2.isnull()]), f"{context}: index non-null values not equal"

def tmpfile(tmpdir, filename=''):
    """
    yield temporary file for testing that will be deleted when the test function
    ends
    """
    if not filename:
        filename = 'tmp_' + ''.join(
            numpy.random.choice(list(string.ascii_letters), size=(6,))
        )
    filename = os.path.join(tmpdir, filename)
    yield filename
    if os.path.isfile(filename):
        os.remove(filename)

def test_static_vars():
    @common.static_vars(my_static_var=42)
    def _func_with_static(new_val: float):
        old_val = _func_with_static.my_static_var
        _func_with_static.my_static_var = new_val
        return old_val

    # check that the initial stored value is good
    assert _func_with_static(3.14159) == 42
    # check that the value changed
    assert _func_with_static(0) == 3.14159

def test_classproperty():
    class Foo:
        def __init__(self, foo):
            self.foo = foo

        # noinspection PyMethodParameters
        @common.classproperty
        def default_foo(cls: type):
            return cls(42)

    assert Foo.default_foo.foo == 42

